# ── Dependency Auto-Installer ─────────────────────────────────────────────────
def _ensure_dependencies() -> None:
    """Auto-install missing packages on first run (works on Termux/pip/venv)."""
    _deps = [
        ('requests',  'requests'),
        ('colorama',  'colorama'),
        ('pyfiglet',  'pyfiglet'),
        ('urllib3',   'urllib3'),
        ('qrcode',    'qrcode[pil]'),
        ('PIL',       'Pillow'),
    ]
    _missing = [_i for _p, _i in _deps if not __import__('importlib').util.find_spec(_p.split('[')[0])]
    if not _missing:
        return
    import subprocess as _sp
    print(f"[*] Auto-installing: {', '.join(_missing)}")
    for _pkg in _missing:
        for _args in (
            [sys.executable, '-m', 'pip', 'install', _pkg, '-q', '--break-system-packages'],
            [sys.executable, '-m', 'pip', 'install', _pkg, '-q'],
        ):
            try:
                _sp.check_call(_args, stdout=_sp.DEVNULL, stderr=_sp.DEVNULL)
                print(f"[✓] Installed: {_pkg}")
                break
            except Exception:
                continue

