# ── Alert Cooldown (Telegram flood prevention) ────────────────────────────────
_alert_cooldown_lock  = threading.Lock()
_alert_last_sent: dict = {}
_ALERT_COOLDOWN_SECS  = 30
def _alert_cooldown_ok(key: str, cooldown: float = None) -> bool:
    """True if enough time has passed since the last alert with this key."""
    cd = cooldown if cooldown is not None else _ALERT_COOLDOWN_SECS
    now = time.time()
    with _alert_cooldown_lock:
        if now - _alert_last_sent.get(key, 0) >= cd:
            _alert_last_sent[key] = now
            return True
    return False

