FAILED_LOGIN_LOG    = os.path.join(SCRIPT_DIR, 'failed_logins.log')
_failed_login_lock  = threading.Lock()
_failed_login_count = 0
def log_failed_login(ip: str, port: int, username: str, password: str,
                     camera_type: str = '') -> None:
    """Append one failed-login attempt to failed_logins.log."""
    global _failed_login_count
    try:
        line = (f"{datetime.now().strftime('%Y-%m-%d %H:%M:%S')} | "
                f"{ip}:{port} | {username}:{password}")
        if camera_type:
            line += f" | {camera_type}"
        with _failed_login_lock:
            with open(FAILED_LOGIN_LOG, 'a', encoding='utf-8') as _f:
                _f.write(line + '\n')
            _failed_login_count += 1
    except Exception:
        pass

# ── Repeat Offender Tracker ───────────────────────────────────────────────────
REPEAT_OFFENDER_FILE = os.path.join(SCRIPT_DIR, 'repeat_offenders.json')
_repeat_lock = threading.Lock()
def load_repeat_offenders() -> dict:
    if os.path.exists(REPEAT_OFFENDER_FILE):
        try:
            with open(REPEAT_OFFENDER_FILE, 'r', encoding='utf-8') as _f:
                return json.load(_f)
        except Exception:
            pass
    return {}
def save_repeat_offenders(data: dict) -> None:
    try:
        with open(REPEAT_OFFENDER_FILE, 'w', encoding='utf-8') as _f:
            json.dump(data, _f, indent=2, ensure_ascii=False)
    except Exception:
        pass
def record_repeat_offender(ip: str, country_code: str = '',
                           camera_type: str = '', credentials: str = '') -> int:
    """Record/update an IP in the repeat-offender registry. Returns seen count."""
    with _repeat_lock:
        data = load_repeat_offenders()
        now  = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
        if ip not in data:
            data[ip] = {'first_seen': now, 'last_seen': now, 'count': 1,
                        'country': country_code, 'camera_type': camera_type,
                        'credentials': credentials}
        else:
            data[ip]['last_seen'] = now
            data[ip]['count']    += 1
            if camera_type:  data[ip]['camera_type']  = camera_type
            if credentials:  data[ip]['credentials']  = credentials
        count = data[ip]['count']
        save_repeat_offenders(data)
    return count

