import random as _rnd

# ── ulimit / File Descriptor Guard ────────────────────────────────────────────
def _check_and_raise_ulimit() -> None:
    """On Linux/Mac: auto-raise open-file-descriptor limit to handle 300 threads."""
    try:
        import resource
        soft, hard = resource.getrlimit(resource.RLIMIT_NOFILE)
        needed = 4096
        if soft < needed:
            try:
                cap = min(needed, hard) if hard not in (-1, 0) else needed
                resource.setrlimit(resource.RLIMIT_NOFILE, (cap, hard))
                print(f"{Fore.GREEN}[✓] FD limit raised: {soft} → {cap}{Style.RESET_ALL}")
            except (ValueError, OSError):
                print(f"{Fore.YELLOW}[⚠] FD limit is {soft} (need {needed}+). "
                      f"Run: ulimit -n 4096{Style.RESET_ALL}")
    except ImportError:
        pass  # Windows has no resource module

# ── Available RAM Check ───────────────────────────────────────────────────────
def _available_ram_mb() -> float:
    """Return available system RAM in MB; 9999 if psutil unavailable."""
    try:
        import psutil as _ps
        return _ps.virtual_memory().available / 1_048_576
    except Exception:
        return 9999.0

def _ram_check_before_scan(country_name: str = '') -> bool:
    """
    Check RAM before expanding large IP ranges.
    Returns True = safe to proceed, False = critically low.
    Prints advisory at < 500 MB; blocks at < 200 MB.
    """
    mb = _available_ram_mb()
    tag = f"for {country_name}" if country_name else ""
    if mb < 200:
        print(f"{Fore.RED}[⚠] Only {mb:.0f} MB RAM free {tag}. "
              f"Close other apps before scanning.{Style.RESET_ALL}")
        return False
    if mb < 500:
        print(f"{Fore.YELLOW}[⚠] {mb:.0f} MB RAM free {tag} — "
              f"streaming mode active (lower memory).{Style.RESET_ALL}")
    return True

# ── IP Range Pre-Validator ────────────────────────────────────────────────────
def _validate_ip_ranges(ranges: list) -> list:
    """
    Filter out blank/malformed CIDR strings before submitting to thread pool.
    Returns only strings that ipaddress.ip_network can parse.
    """
    import ipaddress as _ipa
    valid = []
    for r in ranges:
        r = (r or '').strip()
        if not r or r.startswith('#'):
            continue
        try:
            _ipa.ip_network(r, strict=False)
            valid.append(r)
        except ValueError:
            pass
    return valid

# ── Cached Timestamp (background refresh — avoids per-call syscost) ───────────
_ts_cache: dict = {'ts': '', 'date': ''}
_ts_cache_lock = threading.Lock()

def _ts_updater_loop() -> None:
    while True:
        now = datetime.now()
        with _ts_cache_lock:
            _ts_cache['ts']   = now.strftime('%Y-%m-%d %H:%M:%S')
            _ts_cache['date'] = now.strftime('%Y-%m-%d')
        time.sleep(1)

def get_ts() -> str:
    """Cached timestamp string — refreshed every second by background thread."""
    t = _ts_cache.get('ts', '')
    return t if t else datetime.now().strftime('%Y-%m-%d %H:%M:%S')

def get_date() -> str:
    """Cached date string."""
    d = _ts_cache.get('date', '')
    return d if d else datetime.now().strftime('%Y-%m-%d')

def _start_ts_cache() -> None:
    threading.Thread(target=_ts_updater_loop, daemon=True,
                     name='W8-ts-cache').start()

# ── Memory Pressure Monitor ───────────────────────────────────────────────────
_mem_monitor_running = False

def _mem_monitor_loop() -> None:
    global _mem_monitor_running
    _mem_monitor_running = True
    while _mem_monitor_running:
        try:
            import psutil as _ps
            pct = _ps.virtual_memory().percent
            if pct >= 85 and not _scan_paused.is_set():
                _scan_paused.set()
                print(f"\n{Fore.RED}[⚠] RAM at {pct:.1f}% — scan AUTO-PAUSED "
                      f"to prevent crash{Style.RESET_ALL}")
            elif pct < 70 and _scan_paused.is_set():
                _scan_paused.clear()
                print(f"\n{Fore.GREEN}[✓] RAM at {pct:.1f}% — scan "
                      f"AUTO-RESUMED{Style.RESET_ALL}")
        except Exception:
            pass
        time.sleep(60)

def _start_mem_monitor() -> None:
    threading.Thread(target=_mem_monitor_loop, daemon=True,
                     name='W8-mem-monitor').start()

