def scan_mood(found: int, scanned: int) -> str:
    """Return a coloured mood string based on current success rate."""
    rate = found / max(scanned, 1)
    for threshold, lbl, col in _MOODS:
        if rate >= threshold:
            return f"{col}{lbl}{Style.RESET_ALL}"
    return f"{Fore.WHITE}😴 Bored{Style.RESET_ALL}"

