def population_density_report() -> None:
    """
    Compare camera concentration from ValidCamera files against population density.
    Flags countries with unusually high camera exposure relative to population.
    """
    from collections import Counter
    C, G, Y, W, R = Fore.CYAN, Fore.GREEN, Fore.YELLOW, Style.RESET_ALL, Fore.RED
    files = find_valid_camera_files()
    if not files:
        print(f"{Y}[!] No ValidCamera files found.{W}")
        return
    cam_by_cc: Counter = Counter()
    for fpath in files:
        cc = extract_country_code_from_filename(os.path.basename(fpath))
        try:
            with open(fpath, 'r', encoding='utf-8', errors='replace') as _f:
                count = _f.read().count('Camera Type:')
            if count:
                cam_by_cc[cc] += count
        except Exception:
            pass
    if not cam_by_cc:
        print(f"{Y}[!] No camera data in ValidCamera files.{W}")
        return
    total_cams = sum(cam_by_cc.values())
    rows = []
    for cc, count in cam_by_cc.most_common():
        density   = _POP_DENSITY.get(cc, 0)
        cam_score = (count / max(density, 1)) * 1000
        rows.append((cc, count, density, cam_score, country_flag(cc)))
    rows.sort(key=lambda x: x[3], reverse=True)
    print(f"\n{C}{'═'*68}{W}")
    print(f"{G}  Population Density vs Camera Exposure Report{W}")
    print(f"{C}{'═'*68}{W}")
    print(f"  {'CC':<5} {'':4} {'Cameras':>8} {'Pop/km²':>8}  {'Exposure Score':>14}  Alert")
    print(f"{C}{'─'*68}{W}")
    for cc, count, density, cam_score, flag in rows[:25]:
        alert = (f"{R}⚠ UNUSUAL{W}" if cam_score > 500 else
                 f"{Y}▲ HIGH{W}"    if cam_score > 100 else "")
        print(f"  {cc:<5} {flag:<4} {count:>8} {density:>8}  {cam_score:>14.1f}  {alert}")
    print(f"\n  Total cameras indexed: {G}{total_cams}{W}")

