_CONFLICT_COUNTRIES = {'KP','IR','SY','IQ','RU','AF','LY','SO','YE','MM','SS','SD','CF'}

def flag_border_region(country_code: str) -> list:
    """Return list of countries that share a border with country_code."""
    cc = (country_code or '').upper()
    return sorted((pair - {cc}).pop() for pair in _BORDER_PAIRS if cc in pair)

def border_risk_label(country_code: str) -> str:
    """Return a risk label string if the country borders a conflict/sanctioned state."""
    nb = flag_border_region(country_code)
    if not nb:
        return ''
    if any(n in _CONFLICT_COUNTRIES for n in nb):
        return f"🚧 BORDER RISK [{', '.join(nb[:4])}]"
    return f"🗺 Borders: {', '.join(nb[:4])}"

def border_region_report() -> None:
    """Show border-risk flags for all countries represented in ValidCamera files."""
    from collections import Counter
    C, G, Y, W, R = Fore.CYAN, Fore.GREEN, Fore.YELLOW, Style.RESET_ALL, Fore.RED
    files = find_valid_camera_files()
    if not files:
        print(f"{Y}[!] No ValidCamera files found.{W}")
        return
    cam_by_cc: Counter = Counter()
    for fpath in files:
        cc = extract_country_code_from_filename(os.path.basename(fpath))
        try:
            cnt = open(fpath, 'r', encoding='utf-8', errors='replace').read().count('Camera Type:')
            if cnt:
                cam_by_cc[cc] += cnt
        except Exception:
            pass
    print(f"\n{C}{'═'*65}{W}")
    print(f"{G}  Border Region Risk Report{W}")
    print(f"{C}{'═'*65}{W}")
    for cc, count in cam_by_cc.most_common():
        label = border_risk_label(cc)
        flag  = country_flag(cc)
        col   = R if '🚧' in label else Y if '🗺' in label else G
        print(f"  {col}{cc}{W} {flag} {count:>5} cameras  {label}")

# ── Persistent Access Tracker ─────────────────────────────────────────────────
_PERSISTENT_TRACKER_FILE = os.path.join(SCRIPT_DIR, 'persistent_tracker.json')
_persistent_lock = threading.Lock()

def _load_persistent_tracker() -> dict:
    if not os.path.exists(_PERSISTENT_TRACKER_FILE):
        return {}
    try:
        with open(_PERSISTENT_TRACKER_FILE, 'r', encoding='utf-8') as _f:
            return json.load(_f)
    except Exception:
        return {}

def update_persistent_tracker(ip: str, port: int, username: str, password: str,
                               camera_type: str = '', country_code: str = '') -> None:
    """
    Record a successful login. Tracks how long default credentials remain unchanged
    across multiple scan sessions over days/weeks.
    """
    with _persistent_lock:
        data = _load_persistent_tracker()
        key  = f"{ip}:{port}"
        now_ts = get_ts()
        if key not in data:
            data[key] = {
                'ip': ip, 'port': port, 'first_seen': now_ts,
                'last_seen': now_ts, 'sightings': 1,
                'camera_type': camera_type, 'country_code': country_code,
                'history': [{'ts': now_ts, 'user': username, 'pass': password}],
            }
        else:
            data[key]['last_seen']  = now_ts
            data[key]['sightings'] += 1
            entry = {'ts': now_ts, 'user': username, 'pass': password}
            if entry not in data[key]['history']:
                data[key]['history'].append(entry)
        try:
            with open(_PERSISTENT_TRACKER_FILE, 'w', encoding='utf-8') as _f:
                json.dump(data, _f, indent=2)
        except Exception:
            pass

def view_persistent_tracker() -> None:
    """Display the persistent access tracking report."""
    C, G, Y, W, R = Fore.CYAN, Fore.GREEN, Fore.YELLOW, Style.RESET_ALL, Fore.RED
    data = _load_persistent_tracker()
    if not data:
        print(f"{Y}[!] No persistent tracking data yet.{W}")
        return
    entries = sorted(data.values(), key=lambda x: x.get('sightings', 0), reverse=True)
    print(f"\n{C}{'═'*68}{W}")
    print(f"{G}  Persistent Access Tracker — {len(entries)} devices tracked{W}")
    print(f"{C}{'═'*68}{W}")
    for e in entries[:30]:
        sights = e.get('sightings', 1)
        col    = R if sights >= 5 else Y if sights >= 3 else G
        flag   = country_flag(e.get('country_code', ''))
        print(f"  {col}[x{sights}]{W} {flag} {e['ip']}:{e['port']}  "
              f"First:{e['first_seen'][:10]}  Last:{e['last_seen'][:10]}  "
              f"{C}{e.get('camera_type','')}{W}")
        for h in e.get('history', [])[-3:]:
            print(f"         {Y}►{W} {h['ts']}  {h['user']}:{h['pass']}")

