def append_scan_summary(country_code: str, country_name: str,
                        cameras: int, logins: int,
                        top_cred: str, duration_secs: float,
                        mode: str = 'full'):
    """Append a single-line scan record to scan_summary.log."""
    import datetime as _dt_sum
    _ts  = _dt_sum.datetime.now().strftime('%Y-%m-%d %H:%M')
    _dur = f"{int(duration_secs // 60)}m {int(duration_secs % 60)}s"
    _tc  = top_cred if top_cred else "—"
    _line = (f"{_ts} | {country_code:<4} | {country_name:<28} | "
             f"Cameras: {cameras:<5} | Logins: {logins:<5} | "
             f"Top: {_tc:<26} | Duration: {_dur:<9} | Mode: {mode}")
    try:
        with open(SCAN_SUMMARY_FILE, 'a', encoding='utf-8') as _sf:
            _sf.write(_line + '\n')
    except Exception:
        pass

def _load_daily_filtered(since_date: str) -> dict:
    """Return {cred_key: total_hits} summed over all dates >= since_date from daily file.
    Returns None if the daily file doesn't exist, {} if no matches."""
    if not os.path.exists(CRED_DAILY_FILE):
        return None
    try:
        with open(CRED_DAILY_FILE, 'r', encoding='utf-8') as _df:
            _daily = json.load(_df)
    except Exception:
        return {}
    _out = {}
    for _date, _day_counts in _daily.items():
        if _date >= since_date:
            for _k, _v in _day_counts.items():
                _out[_k] = _out.get(_k, 0) + _v
    return _out

def print_cred_stats(top_n: int = None, since_date: str = None):
    """Print credential success stats ranked by hit count — reads directly from disk.
    top_n: limit output to this many rows (None = show up to 30).
    since_date: YYYY-MM-DD string — show only hits on or after this date."""
    import datetime
    C, G, Y, W, R = Fore.CYAN, Fore.GREEN, Fore.YELLOW, Style.RESET_ALL, Fore.RED
    _limit = top_n if (top_n and top_n > 0) else 30
    print(f"\n{C}{'═'*62}{W}")
    _since_label = f"  Since {since_date} — " if since_date else "  "
    _top_label   = f"Top {_limit}"
    print(f"{G}{_since_label}{_top_label} Credential Success Stats  —  Best Passwords{W}")
    print(f"{C}{'═'*62}{W}")

    if since_date:
        # Use filtered daily data instead of all-time totals
        _raw = _load_daily_filtered(since_date)
        if _raw is None:
            print(f"{Y}  --since requires per-day data (credential_daily_stats.json).{W}")
            print(f"{Y}  Run at least one scan after this update to start collecting daily data.{W}")
            print(f"{C}{'═'*62}{W}\n")
            return
        if not _raw:
            print(f"{Y}  No hits found on or after {since_date}.{W}")
            if os.path.exists(CRED_DAILY_FILE):
                try:
                    _all_dates = sorted(json.load(open(CRED_DAILY_FILE)).keys())
                    if _all_dates:
                        print(f"{Y}  Available date range: {_all_dates[0]}  →  {_all_dates[-1]}{W}")
                except Exception: pass
            print(f"{C}{'═'*62}{W}\n")
            return
    else:
        if not os.path.exists(CRED_STATS_FILE):
            print(f"{Y}  No stats file found: {CRED_STATS_FILE}{W}")
            print(f"{Y}  Run some scans first to accumulate credential hit data.{W}")
            print(f"{C}{'═'*62}{W}\n")
            return
        try:
            with open(CRED_STATS_FILE, 'r', encoding='utf-8') as _f:
                _raw = json.load(_f)
        except Exception as _e:
            print(f"{R}  [!] Failed to read stats file: {_e}{W}")
            print(f"{C}{'═'*62}{W}\n")
            return
        if not _raw:
            print(f"{Y}  Stats file is empty — no credential hits recorded yet.{W}")
            print(f"{C}{'═'*62}{W}\n")
            return

    _sorted = sorted(_raw.items(), key=lambda x: x[1], reverse=True)
    _total_pairs = len(_sorted)
    _total_hits  = sum(v for _, v in _sorted)
    _max_hits    = _sorted[0][1] if _sorted else 1
    _scope = f"since {since_date}" if since_date else "all-time"
    print(f"  {G}Pairs with hits ({_scope}): {Y}{_total_pairs:<6}{G}  Total hits: {Y}{_total_hits}{W}")
    print(f"{C}  {'─'*58}{W}")
    print(f"  {G}{'Rank':<6}{'Username':<22}{'Password':<22}{'Hits':>5}  Bar{W}")
    print(f"{C}  {'─'*58}{W}")
    _show = _sorted[:_limit]
    for _rank, (_key, _hits) in enumerate(_show, 1):
        _parts = _key.split(':', 1)
        _u = _parts[0] if _parts else '?'
        _p = _parts[1] if len(_parts) > 1 else ''
        _bar_len = max(1, int((_hits / _max_hits) * 20))
        _bar = '█' * _bar_len
        _col = G if _rank <= 3 else (Y if _rank <= 10 else W)
        _u_disp = _u[:20] if len(_u) > 20 else _u
        _p_disp = _p[:20] if len(_p) > 20 else _p
        print(f"  {_col}#{_rank:<5}{_u_disp:<22}{_p_disp:<22}{_hits:>5}  {_bar}{W}")
    if _total_pairs > len(_show):
        print(f"\n  {Y}  ... {_total_pairs - len(_show)} more pairs not shown "
              f"(use --top {_total_pairs} to see all){W}")
    if not since_date and os.path.exists(CRED_STATS_FILE):
        _mod = os.path.getmtime(CRED_STATS_FILE)
        _mod_str = datetime.datetime.fromtimestamp(_mod).strftime('%Y-%m-%d %H:%M:%S')
        print(f"\n  {C}File:         {W}{CRED_STATS_FILE}")
        print(f"  {C}Last updated: {W}{_mod_str}")
    print(f"{C}{'═'*62}{W}\n")

def _schedule_cred_stats_save():
    """Schedule a deferred disk write so we batch many rapid successes into one write"""
    global _cred_stats_save_timer
    if _cred_stats_save_timer is None or not _cred_stats_save_timer.is_alive():
        _cred_stats_save_timer = threading.Timer(CRED_STATS_SAVE_INTERVAL, save_cred_success_stats)
        _cred_stats_save_timer.daemon = True
        _cred_stats_save_timer.start()

def record_credential_success(username: str, password: str):
    """Increment success count for a credential pair — deferred disk write to avoid I/O contention.
    Also updates the per-day tracking used by --since date filtering."""
    import datetime as _dt_rcs
    global _cred_stats_dirty, _cred_daily_dirty
    _today    = _dt_rcs.date.today().isoformat()   # "YYYY-MM-DD"
    _cred_key = f"{username}:{password}"
    with cred_stats_lock:
        key = (username, password)
        cred_success_stats[key] = cred_success_stats.get(key, 0) + 1
        _cred_stats_dirty = True
        # Per-day tracking for --since filtering
        if _today not in cred_daily_stats:
            cred_daily_stats[_today] = {}
        cred_daily_stats[_today][_cred_key] = (
            cred_daily_stats[_today].get(_cred_key, 0) + 1
        )
        _cred_daily_dirty = True
    _schedule_cred_stats_save()
    _schedule_cred_daily_save()

_sort_creds_cache: dict = {}   # keys: frozenset of cred tuples → sorted list
_sort_creds_stats_snap: dict = {}  # snapshot of stats used for last sort

def sort_credentials_by_success(credentials):
    """Sort credential list so highest-success-rate credentials are tried first.
    Caches the sorted order and only re-sorts when new successes have been recorded."""
    global _sort_creds_stats_snap
    with cred_stats_lock:
        stats = dict(cred_success_stats)
    # Only re-sort if the stats snapshot changed since last call
    if stats == _sort_creds_stats_snap:
        # Stats unchanged — return cached list if same credential set
        cache_key = tuple(sorted(credentials))
        if cache_key in _sort_creds_cache:
            return _sort_creds_cache[cache_key]
    # Stats changed or no cache — re-sort and update cache
    _sort_creds_stats_snap = stats
    def sort_key(pair):
        return stats.get(pair, 0)
    result = sorted(credentials, key=sort_key, reverse=True)
    cache_key = tuple(sorted(credentials))
    _sort_creds_cache.clear()          # keep cache small — only one entry needed
    _sort_creds_cache[cache_key] = result
    return result

# System Log
SYSTEM_LOG_FILE = os.path.join(os.path.dirname(os.path.abspath(__file__)), "system_log.txt")
system_log_lock = threading.Lock()

def write_system_log(entry: str):
    """Write a timestamped entry to the system log file (file only — Telegram summaries
    are sent separately by the scan completion functions to avoid duplicate messages)."""
    timestamp = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
    line = f"[{timestamp}] {entry}"
    with system_log_lock:
        try:
            with open(SYSTEM_LOG_FILE, 'a', encoding='utf-8') as f:
                f.write(line + "\n")
                f.flush()
        except Exception:
            pass
    print(f"{Fore.CYAN}[LOG] {line}{Style.RESET_ALL}")

