def load_telegram_config():
    """Load Telegram configuration from file or environment variables"""
    global TELEGRAM_CONFIG
    
    # Try loading from file first
    config_file = os.path.join(SCRIPT_DIR, "telegram_config.json")
    if os.path.exists(config_file):
        try:
            with open(config_file, 'r') as f:
                data = json.load(f)
                # Ensure boolean types
                for key in ["enabled", "send_realtime", "send_summary", "send_files"]:
                    if key in data:
                        if isinstance(data[key], str):
                            data[key] = data[key].lower() == "true"
                
                # Support both old format (bot_token/chat_id) and new format (destinations array)
                if "destinations" in data:
                    TELEGRAM_CONFIG.update(data)
                else:
                    # Backward compatibility: convert old format to new format
                    destinations = []
                    if data.get("bot_token") and data.get("chat_id"):
                        destinations.append({
                            "name": "Default Bot",
                            "bot_token": data.get("bot_token"),
                            "chat_id": data.get("chat_id"),
                            "enabled": data.get("enabled", True)
                        })
                    TELEGRAM_CONFIG.update({k: v for k, v in data.items() if k not in ["bot_token", "chat_id"]})
                    TELEGRAM_CONFIG["destinations"] = destinations
        except Exception as e:
            print(f"{Fore.RED}[!] Error loading telegram_config.json: {e}{Style.RESET_ALL}")
            
    # Override with environment variables if present
    env_token = os.environ.get("TELEGRAM_BOT_TOKEN")
    env_chat_id = os.environ.get("TELEGRAM_CHAT_ID")
    if env_token and env_chat_id:
        TELEGRAM_CONFIG["enabled"] = True
        if not TELEGRAM_CONFIG.get("destinations"):
            TELEGRAM_CONFIG["destinations"] = []
        TELEGRAM_CONFIG["destinations"] = [
            {"name": "Default Bot", "bot_token": env_token, "chat_id": env_chat_id, "enabled": True}
        ]

