def save_rtsp_stats(stats):
    try:
        with open(_RTSP_STATS_FILE, 'w', encoding='utf-8') as f:
            json.dump(stats, f, indent=2)
    except Exception:
        pass


def update_rtsp_stats(country_code, country_name, found, scanned):
    """Update per-country RTSP success stats in rtsp_stats.json."""
    stats = load_rtsp_stats()
    today = datetime.now().strftime('%Y-%m-%d')
    if country_code not in stats:
        stats[country_code] = {
            "country": country_name,
            "total_found": 0,
            "total_scanned": 0,
            "last_scan": "",
            "daily": {}
        }
    stats[country_code]["total_found"]   += found
    stats[country_code]["total_scanned"] += scanned
    stats[country_code]["last_scan"]      = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
    stats[country_code]["country"]        = country_name
    day = stats[country_code]["daily"].setdefault(today, {"found": 0, "scanned": 0})
    day["found"]   += found
    day["scanned"] += scanned
    save_rtsp_stats(stats)

def remove_duplicates_from_file(file_path: str):
    """Remove duplicate entries from a result file.
    Deduplicates by IP:Port pair (not IP alone) so the same camera on two
    ports is kept, but the exact same camera seen twice is removed.
    Also strips orphaned blank sections and all-but-one summary headers.
    Writes to a temp file first then atomically renames to avoid corruption."""
    tmp_path = file_path + ".dedup_tmp"
    try:
        if not os.path.exists(file_path):
            return
        with open(file_path, 'r', encoding='utf-8', errors='ignore') as f:
            content = f.read()
        sections = content.split('=' * 60)
        unique_sections = []
        seen_keys = set()   # "ip:port" pairs
        duplicates = 0
        summary_kept = False
        for section in sections:
            stripped = section.strip()
            # Drop entirely empty or whitespace-only sections
            if not stripped:
                continue
            lines = [line.strip() for line in stripped.split('\n') if line.strip()]
            # Handle summary/header sections: keep only the first one
            if 'Valid Camera Count Summary' in stripped or 'Camera Count Summary' in stripped:
                if summary_kept:
                    duplicates += 1
                    continue
                summary_kept = True
                unique_sections.append(section)
                continue
            # Extract IP and Port for dedup key
            ip = None
            port = None
            for line in lines:
                if line.startswith('IP Address:'):
                    ip = line.replace('IP Address:', '').strip()
                elif line.startswith('Port:'):
                    port = line.replace('Port:', '').strip()
                if ip and port:
                    break
            if ip:
                key = f"{ip}:{port}" if port else ip
                if key in seen_keys:
                    duplicates += 1
                    continue
                seen_keys.add(key)
                unique_sections.append(section)
            else:
                # Section has no IP — drop it to prevent junk accumulation
                # unless it looks like a legitimate header (has recognizable fields)
                has_field = any(
                    line.startswith(('Camera Type:', 'Detection Time:', 'Device Model:',
                                     'Username:', 'URL:', 'HTTP Status:'))
                    for line in lines
                )
                if has_field:
                    unique_sections.append(section)
                else:
                    duplicates += 1
        if duplicates > 0:
            with open(tmp_path, 'w', encoding='utf-8') as f:
                f.write(('=' * 60).join(unique_sections))
                f.flush()
                os.fsync(f.fileno())
            os.replace(tmp_path, file_path)
            print(f"\n{Fore.GREEN}[✓] Removed {duplicates} duplicate/junk entries from "
                  f"{os.path.basename(file_path)}{Style.RESET_ALL}")
        else:
            print(f"\n{Fore.CYAN}[i] No duplicates found in "
                  f"{os.path.basename(file_path)}{Style.RESET_ALL}")
    except Exception as e:
        print(f"\n{Fore.YELLOW}[!] Error removing duplicates: {e}{Style.RESET_ALL}")
    finally:
        if os.path.exists(tmp_path):
            try:
                os.remove(tmp_path)
            except Exception:
                pass

def handle_unexpected_stop(signum, frame):
    """Handle Ctrl+C / SIGTERM gracefully.
    First signal: cancel pending work, keep the bar until threads drain, then exit.
    Second signal: force-quit immediately.
    """
    if _stop_requested.is_set():
        try: print(f"\n{Fore.RED}[!] Force quit.{Style.RESET_ALL}")
        except Exception: pass
        os._exit(1)

    _stop_requested.set()
    try:
        print(f"\n{Fore.YELLOW}[!] Stop signal ({signum}) received. "
              f"Finishing running tasks then saving... "
              f"(press Ctrl+C again to force-quit){Style.RESET_ALL}")
    except Exception:
        pass

    try: _flush_camera_batch()
    except Exception: pass
    try: save_cred_success_stats()
    except Exception: pass
    try:
        save_scan_progress(
            country_code=selected_country.get('code', '') if selected_country else '',
            country_name=selected_country.get('name', '') if selected_country else '',
            scanned=scanned_count,
            total=total_ips,
            last_ip_index=_current_range_idx,
            last_ip_in_range=_last_scanned_ip_global,
            output_file=cctv_output_file or ''
        )
    except Exception: pass
    # Save brute-force progress if a login check was running
    try:
        with _brute_active_lock:
            if _active_brute_file and _active_brute_total > 0 and _active_brute_index > 0:
                save_brute_progress(
                    input_file=_active_brute_file,
                    country_code=_active_brute_country_code,
                    last_camera_index=_active_brute_index,
                    total_cameras=_active_brute_total
                )
                print(f"\n{Fore.YELLOW}[✓] Login-check progress saved at camera "
                      f"{_active_brute_index}/{_active_brute_total} — resume next time{Style.RESET_ALL}")
    except Exception: pass
    # DO NOT sys.exit() here — scan loops drain futures, keep bar running, then exit.

def handle_sigterm(signum, frame):
    """Dedicated SIGTERM handler — invoked by Replit/Linux before SIGKILL.
    Synchronously flushes every in-progress save (scan, RTSP, brute, cred
    stats) to give the most precise possible resume point, sends a Telegram
    alert, then hands off to the normal graceful-drain flow."""
    G, Y, W = Fore.GREEN, Fore.YELLOW, Style.RESET_ALL
    try:
        print(f"\n{Y}[SIGTERM] Graceful shutdown received — "
              f"forcing immediate progress save...{W}", flush=True)
    except Exception:
        pass

    _tg_parts = [
        "⚠️ <b>SIGTERM — graceful shutdown</b>",
        "━━━━━━━━━━━━━━━━━━━━━━",
        "All progress flushed immediately.",
    ]

    # ── 1. Country scan progress (option 1 / batch scan) ─────────────────────
    try:
        if total_ips > 0 and selected_country:
            save_scan_progress(
                country_code=selected_country.get('code', ''),
                country_name=selected_country.get('name', ''),
                scanned=scanned_count,
                total=total_ips,
                last_ip_index=_current_range_idx,
                last_ip_in_range=_last_scanned_ip_global,
                output_file=cctv_output_file or '',
                stop_reason='sigterm',
            )
            print(f"{G}  [✓] Scan progress saved "
                  f"({scanned_count}/{total_ips} IPs){W}", flush=True)
            _tg_parts.append(
                f"📡 Scan: {selected_country.get('name','?')} — "
                f"{scanned_count}/{total_ips} IPs"
            )
    except Exception:
        pass

    # ── 1b. IP Range Scan progress (Option 3) ────────────────────────────────
    try:
        with _range_active_lock:
            _rast  = _range_active_start
            _raend = _range_active_end
        if _rast and total_ips > 0:
            _range_prog = {
                "start_ip":  _rast,
                "end_ip":    _raend,
                "scanned":   scanned_count,
                "total":     total_ips,
                "timestamp": datetime.now().strftime('%Y-%m-%d %H:%M:%S'),
            }
            _rp_path = os.path.join(SCRIPT_DIR, "range_scan_progress.json")
            with open(_rp_path, 'w', encoding='utf-8') as _rpf:
                json.dump(_range_prog, _rpf, indent=2)
                _rpf.flush()
                os.fsync(_rpf.fileno())
            print(f"{G}  [✓] IP Range Scan progress saved "
                  f"({scanned_count}/{total_ips} IPs){W}", flush=True)
            _tg_parts.append(
                f"🔍 IP Range: {_rast}–{_raend} — {scanned_count}/{total_ips} IPs"
            )
    except Exception:
        pass

    # ── 2. RTSP batch progress ────────────────────────────────────────────────
    try:
        with _rtsp_active_lock:
            _raf  = list(_rtsp_active_files)
            _rai  = _rtsp_active_index
            _rat  = _rtsp_active_total
            _rafd = _rtsp_active_found
        if _raf and _rat > 0:
            save_rtsp_scan_progress(_raf, _rai, _rat, _rafd)
            print(f"{G}  [✓] RTSP batch progress saved "
                  f"({_rai}/{_rat}){W}", flush=True)
            _tg_parts.append(f"📷 RTSP batch: {_rai}/{_rat} done")
    except Exception:
        pass

    # ── 2b. Quick Re-Test progress (Option 13 Mode 5) ────────────────────────
    try:
        with _retest_active_lock:
            _rtd  = _retest_active_done
            _rtt  = _retest_active_total
            _rtlc = _retest_active_live_count
        if _rtt > 0:
            print(f"{G}  [✓] Re-Test state saved "
                  f"({_rtd}/{_rtt}, {_rtlc} live so far){W}", flush=True)
            _tg_parts.append(f"🔄 Re-Test: {_rtd}/{_rtt} done, {_rtlc} live")
    except Exception:
        pass

    # ── 3. Brute-force progress ───────────────────────────────────────────────
    try:
        with _brute_active_lock:
            _baf = _active_brute_file
            _bai = _active_brute_index
            _bat = _active_brute_total
            _bac = _active_brute_country_code
        if _baf and _bat > 0:
            save_brute_progress(
                input_file=_baf,
                country_code=_bac,
                last_camera_index=_bai,
                total_cameras=_bat,
            )
            print(f"{G}  [✓] Brute-force progress saved "
                  f"({_bai}/{_bat}){W}", flush=True)
            _tg_parts.append(f"🔑 Brute-force: {_bai}/{_bat} done")
    except Exception:
        pass

    # ── 4. Credential stats ───────────────────────────────────────────────────
    try:
        save_cred_success_stats()
        print(f"{G}  [✓] Credential stats saved{W}", flush=True)
    except Exception:
        pass

    # ── 5. Telegram alert (blocking — must complete before SIGKILL) ───────────
    try:
        if TELEGRAM_CONFIG.get("enabled"):
            _tg_parts.append(f"🕒 {datetime.now().strftime('%Y-%m-%d %H:%M:%S')}")
            send_telegram_message_blocking('\n'.join(_tg_parts))
    except Exception:
        pass

    # ── Hand off to normal graceful-drain flow ────────────────────────────────
    handle_unexpected_stop(signum, frame)


