_bulk_print_lock = threading.Lock()


def _run_bulk_tool(cameras: list, task_fn, label: str, max_workers: int = 5) -> list:
    """
    Run task_fn(cam) on every camera in the list using a thread pool.
    Prints thread-safe progress lines.  Returns list of (cam, result) tuples.
    """
    C, G, Y, W, R = Fore.CYAN, Fore.GREEN, Fore.YELLOW, Style.RESET_ALL, Fore.RED
    total   = len(cameras)
    done    = [0]
    results = []
    res_lock = threading.Lock()

    print(f"\n{C}{'═'*60}{W}")
    print(f"{G}  Bulk Mode — {label}{W}")
    print(f"{G}  Cameras : {total}   Threads : {max_workers}{W}")
    print(f"{C}{'═'*60}{W}")

    def _worker(cam):
        try:
            result = task_fn(cam)
        except Exception as exc:
            result = exc
        with _bulk_print_lock:
            done[0] += 1
            pct = done[0] * 100 // total
            status = f"{G}[{done[0]:>4}/{total}  {pct:>3}%]{W}"
            ip_str = f"{cam.get('ip','?')}:{cam.get('port','?')}"
            if isinstance(result, Exception):
                print(f"  {status} {R}✗{W} {ip_str}  — {result}")
            else:
                print(f"  {status} {G}✓{W} {ip_str}")
        with res_lock:
            results.append((cam, result))

    import concurrent.futures as _cf
    with _cf.ThreadPoolExecutor(max_workers=max_workers) as _ex:
        list(_ex.map(_worker, cameras))

    print(f"\n{G}[✓] Bulk run complete — {total} camera(s) processed.{W}")
    return results


def tools_submenu() -> None:
    """Extra Tools sub-menu (Option 12)."""
    C, G, Y, W, R = Fore.CYAN, Fore.GREEN, Fore.YELLOW, Style.RESET_ALL, Fore.RED

