def main():
    """Main function with menu"""
    global start_time, scanned_count, total_ips, valid_results

    # ── Startup init ──────────────────────────────────────────────────────────
    _ensure_dependencies()
    _check_and_raise_ulimit()
    _start_ts_cache()
    _start_mem_monitor()
    load_proxies()
    load_geo_api_keys_from_config()
    load_stealth_config_from_telegram()
    show_random_fact()

    # ── Log-file tee — wraps stdout/stderr before anything else prints ────────
    class _TeeLogger:
        def __init__(self, *streams): self.streams = streams
        def write(self, data):
            for _s in self.streams:
                try: _s.write(data)
                except Exception: pass
        def flush(self):
            for _s in self.streams:
                try: _s.flush()
                except Exception: pass
        def isatty(self): return False
        def fileno(self): raise OSError('no fileno on TeeLogger')
    if '--log-file' in sys.argv:
        try:
            _lf_idx = sys.argv.index('--log-file')
            _lf_path = sys.argv[_lf_idx + 1]
            _lf_handle = open(_lf_path, 'a', encoding='utf-8', buffering=1)
            sys.stdout = _TeeLogger(sys.__stdout__, _lf_handle)
            sys.stderr = _TeeLogger(sys.__stderr__, _lf_handle)
            print(f"[log-file] Logging to: {_lf_path}")
        except (IndexError, IOError) as _lf_e:
            print(f"[!] --log-file error: {_lf_e}", file=sys.__stderr__)

    # ── CLI argument parsing ──────────────────────────────────────────────────
