    # ── --benchmark: test network speed, recommend --threads & --timeout ─────────
    if '--benchmark' in sys.argv:
        import statistics as _stat_bm, socket as _sock_bm, random as _rand_bm
        import concurrent.futures as _cf_bm
        C, G, Y, W, R = Fore.CYAN, Fore.GREEN, Fore.YELLOW, Style.RESET_ALL, Fore.RED
        _BM_BLOCKS = [
            '5.10.', '37.18.', '45.32.', '78.46.', '80.11.', '91.108.',
            '103.21.', '116.58.', '118.69.', '176.9.', '185.16.', '212.58.',
        ]
        _BM_N    = 72
        _BM_PORT = 80
        _BM_TO   = 1.5
        print(f"\n{C}{'═'*62}{W}")
        print(f"{G}  Network Benchmark — Recommending --threads & --timeout{W}")
        print(f"{C}{'═'*62}{W}")
        print(f"  Testing {_BM_N} random IPs on port {_BM_PORT} with {_BM_TO}s timeout...\n")
        _bm_ips = []
        for _bm_b in (_BM_BLOCKS * 6)[:_BM_N]:
            _bm_ips.append(f"{_bm_b}{_rand_bm.randint(1,254)}.{_rand_bm.randint(1,254)}")
        def _bm_probe(ip):
            t0 = time.time()
            try:
                _s = _sock_bm.create_connection((ip, _BM_PORT), timeout=_BM_TO)
                _s.close()
                return ('connected', time.time() - t0)
            except ConnectionRefusedError:
                return ('refused', time.time() - t0)
            except OSError:
                return ('timeout', time.time() - t0)
            except Exception:
                return ('error', time.time() - t0)
        with _cf_bm.ThreadPoolExecutor(max_workers=60) as _bm_ex:
            _bm_res = list(_bm_ex.map(_bm_probe, _bm_ips))
        _bm_lats = []; _bm_ok = _bm_ref = _bm_tmo = _bm_err = 0
        for _bm_st, _bm_lat in _bm_res:
            if _bm_st == 'connected':
                _bm_ok  += 1; _bm_lats.append(_bm_lat * 1000)
            elif _bm_st == 'refused':
                _bm_ref += 1; _bm_lats.append(_bm_lat * 1000)
            elif _bm_st == 'timeout':
                _bm_tmo += 1
            else:
                _bm_err += 1
        _bm_total = len(_bm_res)
        _bm_tmo_rate = _bm_tmo / _bm_total if _bm_total else 0
        if _bm_lats:
            _bm_lats_s = sorted(_bm_lats)
            _bm_med = _stat_bm.median(_bm_lats_s)
            _bm_p90 = _bm_lats_s[int(len(_bm_lats_s) * 0.9)]
        else:
            _bm_med = _bm_p90 = 1500.0
        print(f"  {C}Results:{W}")
        print(f"    Connected (port open) : {G}{_bm_ok}{W}")
        print(f"    Refused  (port closed): {Y}{_bm_ref}{W}")
        print(f"    Timed out             : {R}{_bm_tmo}{W}  ({_bm_tmo_rate*100:.1f}% timeout rate)")
        print(f"    Errors                : {_bm_err}")
        if _bm_lats:
            print(f"    Median RTT            : {G}{_bm_med:.0f} ms{W}")
            print(f"    90th pct RTT          : {Y}{_bm_p90:.0f} ms{W}")
        print(f"\n{C}  {'─'*58}{W}")
        if _bm_p90 < 120:
            _bm_thr = 300; _bm_tmo_rec = 0.10; _bm_qual = "Excellent"
        elif _bm_p90 < 250:
            _bm_thr = 200; _bm_tmo_rec = 0.15; _bm_qual = "Good"
        elif _bm_p90 < 500:
            _bm_thr = 120; _bm_tmo_rec = 0.25; _bm_qual = "Fair"
        elif _bm_p90 < 900:
            _bm_thr = 75;  _bm_tmo_rec = 0.40; _bm_qual = "Slow"
        else:
            _bm_thr = 40;  _bm_tmo_rec = 0.60; _bm_qual = "Poor"
        if _bm_tmo_rate > 0.65:
            _bm_thr = max(20, _bm_thr // 2)
            _bm_tmo_rec = min(1.0, _bm_tmo_rec * 1.5)
            print(f"  {R}⚠  High timeout rate — reducing threads, increasing timeout.{W}")
        _bm_tmo_rec = round(_bm_tmo_rec, 2)   # clean display, e.g. 0.23 not 0.22999...
        print(f"  Network quality  : {G if _bm_qual in ('Excellent','Good') else Y}{_bm_qual}{W}")
        print(f"\n  {G}Recommended flags:{W}")
        print(f"    --threads {_bm_thr}  --timeout {_bm_tmo_rec}")
        print(f"\n  {C}Full command example:{W}")
        print(f"    python3 W8CameraHackV3.py --country TR "
              f"--threads {_bm_thr} --timeout {_bm_tmo_rec}")
        print(f"{C}{'═'*62}{W}\n")
        sys.exit(0)

