            # Colour the label by category
            if 'Proxy' in _label:          _lc = R
            elif 'Hosting' in _label:      _lc = M
            elif 'Public' in _label:       _lc = G
            else:                          _lc = Y   # private / CGN / unknown
            print(f"  {G}\u25cf{W} {C}{_ip}{W}  \u2500  {_lc}{_label}{W}")
            print(f"  {C}{'─'*56}{W}")
