    # ── --tag-results PATH: geo-label every camera block in a CCTV file ──────────
    if '--tag-results' in sys.argv:
        import datetime as _dt_tr
        C, G, Y, W, R, M = (Fore.CYAN, Fore.GREEN, Fore.YELLOW,
                             Style.RESET_ALL, Fore.RED, Fore.MAGENTA)
        _tr_idx = sys.argv.index('--tag-results')
        if (_tr_idx + 1 >= len(sys.argv) or
                sys.argv[_tr_idx + 1].startswith('--')):
            print(f"{R}[!] --tag-results requires a file path.{W}")
            print(f"    e.g.  --tag-results TR_CCTV_Found.txt")
            sys.exit(1)
        _tr_path = sys.argv[_tr_idx + 1]
        if not os.path.exists(_tr_path):
            print(f"{R}[!] File not found: {_tr_path}{W}")
