    # ── --ip-lookup FILE: enrich blocks with live geo/ASN via ip-api.com ─────────
    if '--ip-lookup' in sys.argv:
        import urllib.request as _il_req
        import json          as _il_json
        import time          as _il_time
        _il_idx = sys.argv.index('--ip-lookup')
        if _il_idx + 1 >= len(sys.argv) or sys.argv[_il_idx + 1].startswith('--'):
            print(f"{Fore.RED}[!] --ip-lookup requires a FILE path.{Style.RESET_ALL}")
            sys.exit(1)
        _il_src = sys.argv[_il_idx + 1]
        if not os.path.isfile(_il_src):
            print(f"{Fore.RED}[!] File not found: {_il_src}{Style.RESET_ALL}")
            sys.exit(1)
        _il_out = None
        if '--out' in sys.argv:
            _il_oi = sys.argv.index('--out')
            if _il_oi + 1 < len(sys.argv) and not sys.argv[_il_oi + 1].startswith('--'):
                _il_out = sys.argv[_il_oi + 1]
        if not _il_out:
            _il_base = os.path.splitext(os.path.basename(_il_src))[0]
            _il_out  = os.path.join(os.path.dirname(_il_src) or '.', f'iplookup_{_il_base}.txt')
        _il_overwrite  = '--overwrite'    in sys.argv
        _il_dry        = '--dry-run'      in sys.argv
        _il_delay      = 4.0   # seconds between batch requests (ip-api free: 15 batch req/min)
        if '--delay' in sys.argv:
            try: _il_delay = float(sys.argv[sys.argv.index('--delay') + 1])
            except: pass
        C, G, Y, W, R, M = (Fore.CYAN, Fore.GREEN, Fore.YELLOW,
                             Style.RESET_ALL, Fore.RED, Fore.MAGENTA)
        # ── ip-api.com fields we request ──────────────────────────────────────
        _IL_API_FIELDS  = 'status,country,regionName,city,isp,as,org,query'
        _IL_BATCH_URL   = 'http://ip-api.com/batch'
        _IL_BATCH_SIZE  = 100
        # Map api response keys → block field names
        _IL_FIELD_MAP   = {
            'country'    : 'Country',
            'regionName' : 'Region/State',
            'city'       : 'City',
            'isp'        : 'ISP',
            'org'        : 'Organization',
            'as'         : 'ASN',
        }
        # ── Parse file ────────────────────────────────────────────────────────
        _il_text  = open(_il_src, 'r', encoding='utf-8', errors='replace').read()
        _SEP_il   = '=' * 60
        _il_blks  = [b.strip() for b in _il_text.split(_SEP_il) if b.strip()]
        _il_blank_fmt = False
        if len(_il_blks) <= 1:
            _il_blks     = [b.strip() for b in _il_text.split('\n\n') if b.strip()]
            _il_blank_fmt = True
        # Build ordered dicts preserving original line order
        def _il_parse_block(raw):
            od = {}
            order = []
            for ln in raw.splitlines():
                if ':' in ln:
                    k, _, v = ln.partition(':')
                    k = k.strip()
                    v = v.strip()
                    if k not in od:
                        order.append(k)
                    od[k] = v
            return od, order
        _il_parsed = []   # list of (od, order, raw_block)
        for _ilb in _il_blks:
            _od, _ord = _il_parse_block(_ilb)
            _ip_val   = _od.get('IP Address', _od.get('IP', '')).strip()
            if not _ip_val:
                continue
            if 'IP' in _od and 'IP Address' not in _od:
                _od['IP Address'] = _od.pop('IP')
                _ord = [('IP Address' if x == 'IP' else x) for x in _ord]
            _il_parsed.append((_od, _ord, _ilb))
        _il_total_blks = len(_il_parsed)
        if _il_total_blks == 0:
            print(f"\n  {Y}No camera blocks found in {_il_src}.{W}\n")
            sys.exit(0)
        # ── Determine which IPs need lookup ───────────────────────────────────
        _il_need_lookup = {}  # ip → list of block indices
        for _ili, (_od, _ord, _raw) in enumerate(_il_parsed):
            _ip = _od.get('IP Address', '').strip()
            if not _ip:
                continue
            if not _il_overwrite and _od.get('Country', '').strip():
                continue   # already has country and --overwrite not set
            if _ip not in _il_need_lookup:
                _il_need_lookup[_ip] = []
            _il_need_lookup[_ip].append(_ili)
        _il_unique_ips = list(_il_need_lookup.keys())
        print(f"\n{C}{'='*64}{W}")
        print(f"{G}  IP Lookup Enrichment  --  {os.path.basename(_il_src)}{W}")
        print(f"{C}{'='*64}{W}\n")
        print(f"  {Y}Camera blocks      : {_il_total_blks:,}{W}")
        print(f"  {G}IPs to look up     : {len(_il_unique_ips):,}{W}")
        if not _il_overwrite:
            _il_already = sum(1 for od, *_ in _il_parsed
                              if od.get('Country','').strip())
            print(f"  {Y}Already have Country : {_il_already:,}  (skipped, use --overwrite to re-fetch){W}")
        if _il_dry:
            print(f"  {M}Dry run — no requests or writes will be made.{W}")
        print()
        if not _il_unique_ips:
            print(f"  {Y}Nothing to look up. All blocks already have Country.{W}\n"
                  f"  {Y}Use --overwrite to re-fetch all IPs.{W}\n")
            sys.exit(0)
        # ── Batch fetch from ip-api.com ───────────────────────────────────────
        _il_geo_cache = {}   # ip → geo dict
        _il_batches   = [_il_unique_ips[i:i + _IL_BATCH_SIZE]
                         for i in range(0, len(_il_unique_ips), _IL_BATCH_SIZE)]
        _il_errors    = 0
        for _ilbi, _il_batch in enumerate(_il_batches):
            _il_pct = int((_ilbi) / len(_il_batches) * 100)
            _il_bar = chr(0x2588) * max(1, int(_ilbi / len(_il_batches) * 20))
            print(f"  {C}[{_ilbi+1}/{len(_il_batches)}]{W}  {_il_pct:>3}%  {G}{_il_bar:<20}{W}  "
                  f"fetching {len(_il_batch)} IPs ...", end='\r', flush=True)
            if _il_dry:
                for _dip in _il_batch:
                    _il_geo_cache[_dip] = {}
                continue
            _il_body = _il_json.dumps([
                {'query': _dip, 'fields': _IL_API_FIELDS}
                for _dip in _il_batch
            ]).encode('utf-8')
            try:
                _il_req_obj = _il_req.Request(
                    _IL_BATCH_URL,
                    data    = _il_body,
                    headers = {'Content-Type': 'application/json'},
                    method  = 'POST',
                )
                with _il_req.urlopen(_il_req_obj, timeout=10) as _il_resp:
                    _il_results = _il_json.loads(_il_resp.read().decode('utf-8'))
                for _ilr in _il_results:
                    if _ilr.get('status') == 'success':
                        _il_geo_cache[_ilr['query']] = _ilr
                    else:
                        _il_errors += 1
            except Exception as _ile:
                _il_errors += len(_il_batch)
            if _ilbi < len(_il_batches) - 1:
                _il_time.sleep(_il_delay)
        print(f"  {G}[{len(_il_batches)}/{len(_il_batches)}]{W}  100%  "
              f"{G}{'█'*20}{W}  done.              ")
        _il_hits = sum(1 for v in _il_geo_cache.values() if v)
        print(f"\n  {G}Successful lookups : {_il_hits:,} / {len(_il_unique_ips):,}{W}")
        if _il_errors:
            print(f"  {R}Failed / private   : {_il_errors:,}{W}")
        # ── Merge geo data into parsed blocks ─────────────────────────────────
        _il_enriched_count = 0
        _il_new_blocks     = []
        for _od, _ord, _raw in _il_parsed:
            _ip = _od.get('IP Address', '').strip()
            _geo = _il_geo_cache.get(_ip, {})
            if _geo:
                _changed = False
                for _api_key, _block_key in _IL_FIELD_MAP.items():
                    _val = _geo.get(_api_key, '').strip()
                    if not _val:
                        continue
                    if _il_overwrite or not _od.get(_block_key, '').strip():
                        if _od.get(_block_key) != _val:
                            _changed = True
                        _od[_block_key] = _val
                        if _block_key not in _ord:
                            _ord.append(_block_key)
                if _changed:
                    _il_enriched_count += 1
            # Reconstruct block as `Key: Value` lines
            _lines = [f"{k}: {_od[k]}" for k in _ord if k in _od]
            _il_new_blocks.append('\n'.join(_lines))
        if _il_dry:
            print(f"  {M}Dry run: {_il_enriched_count:,} block(s) would be enriched. No file written.{W}")
            print(f"\n{C}{'='*64}{W}\n")
            sys.exit(0)
        # ── Write output ───────────────────────────────────────────────────────
        if _il_blank_fmt:
            _il_output = '\n\n'.join(_il_new_blocks)
        else:
            _il_sep_str = '\n' + _SEP_il + '\n'
            _il_output  = _il_sep_str.join(
                '\n' + b + '\n' for b in _il_new_blocks)
        try:
            with open(_il_out, 'w', encoding='utf-8') as _il_wf:
                _il_wf.write(_il_output)
        except Exception as _il_we:
            print(f"\n{R}[!] Write failed: {_il_we}{W}")
            sys.exit(1)
        _il_out_kb = os.path.getsize(_il_out) // 1024
        print(f"  {G}Blocks enriched    : {_il_enriched_count:,}{W}")
        print(f"  {G}Output             : {os.path.basename(_il_out)}  ({_il_out_kb:,} KB){W}")
        print(f"\n{C}{'='*64}{W}\n")
        sys.exit(0)

    # ── --dedup-file FILE: deduplicate a result file by IP:Port ──────────────────
    if '--dedup-file' in sys.argv:
        _df_idx = sys.argv.index('--dedup-file')
        if _df_idx + 1 >= len(sys.argv) or sys.argv[_df_idx + 1].startswith('--'):
            print(f"{Fore.RED}[!] --dedup-file requires a FILE path.{Style.RESET_ALL}")
            sys.exit(1)
        _df_src = sys.argv[_df_idx + 1]
        if not os.path.isfile(_df_src):
            print(f"{Fore.RED}[!] File not found: {_df_src}{Style.RESET_ALL}")
            sys.exit(1)
        _df_out      = None
        _df_in_place = '--in-place' in sys.argv
        _df_dry      = '--dry-run'  in sys.argv
        _df_keep_first = '--keep-first' in sys.argv
        if not _df_in_place:
            if '--out' in sys.argv:
                _df_oi = sys.argv.index('--out')
                if _df_oi + 1 < len(sys.argv) and not sys.argv[_df_oi + 1].startswith('--'):
                    _df_out = sys.argv[_df_oi + 1]
            if not _df_out:
                _df_base = os.path.splitext(os.path.basename(_df_src))[0]
                _df_out  = os.path.join(os.path.dirname(_df_src) or '.', f'dedup_{_df_base}.txt')
        else:
            _df_out = _df_src
        C, G, Y, W, R, M = (Fore.CYAN, Fore.GREEN, Fore.YELLOW,
                             Style.RESET_ALL, Fore.RED, Fore.MAGENTA)
        # ── Parse file into raw blocks ─────────────────────────────────────────
        _df_text      = open(_df_src, 'r', encoding='utf-8', errors='replace').read()
        _SEP_df       = '=' * 60
        _df_raw_blocks = [b.strip() for b in _df_text.split(_SEP_df) if b.strip()]
        _df_blank_fmt  = False
        if len(_df_raw_blocks) <= 1:
            _df_raw_blocks = [b.strip() for b in _df_text.split('\n\n') if b.strip()]
            _df_blank_fmt  = True
        _df_total = len(_df_raw_blocks)
        if _df_total == 0:
            print(f"\n  {Y}No camera blocks found in {_df_src}.{W}\n")
            sys.exit(0)
        # ── Score helper (more fields + creds = higher score) ─────────────────
        def _df_score(raw):
            score = 0
            has_user = has_pass = False
            for ln in raw.splitlines():
                if ':' in ln:
                    k, _, v = ln.partition(':')
                    if v.strip():
                        score += 1
                    if k.strip().lower() in ('username', 'user'):
                        has_user = bool(v.strip())
                    if k.strip().lower() in ('password', 'pass'):
                        has_pass = bool(v.strip())
            if has_user and has_pass:
                score += 10
            return score
        def _df_ip_port_key(raw):
            ip = port = ''
            for ln in raw.splitlines():
                if ':' in ln:
                    k, _, v = ln.partition(':')
                    k = k.strip().lower()
                    v = v.strip()
                    if k in ('ip address', 'ip') and not ip:
                        ip = v
                    if k == 'port' and not port:
                        port = v
            return f"{ip}:{port}" if ip else None
        # ── Deduplicate ────────────────────────────────────────────────────────
        _df_seen   = {}   # key → (best_raw, best_score)
        _df_order  = []   # insertion-order unique keys
        for _dfb in _df_raw_blocks:
            _df_key = _df_ip_port_key(_dfb)
            if _df_key is None:
                continue
            if _df_key not in _df_seen:
                _df_seen[_df_key]  = (_dfb, _df_score(_dfb))
                _df_order.append(_df_key)
            else:
                if not _df_keep_first:
                    _df_new_score = _df_score(_dfb)
                    if _df_new_score > _df_seen[_df_key][1]:
                        _df_seen[_df_key] = (_dfb, _df_new_score)
        _df_unique_blocks = [_df_seen[k][0] for k in _df_order]
        _df_dupes = _df_total - len(_df_unique_blocks)
        _df_src_kb = os.path.getsize(_df_src) // 1024
        print(f"\n{C}{'='*64}{W}")
        print(f"{G}  Deduplicate File  --  {os.path.basename(_df_src)}{W}")
        print(f"{C}{'='*64}{W}\n")
        print(f"  {Y}Total blocks       : {_df_total:,}{W}")
        print(f"  {G}Unique IP:Port keys : {len(_df_unique_blocks):,}{W}")
        _df_mode = 'keep-first' if _df_keep_first else 'best-entry'
        print(f"  {R}Duplicates removed : {_df_dupes:,}  (mode: {_df_mode}){W}")
        print(f"  {Y}Source size        : {_df_src_kb:,} KB{W}")
        if _df_dry:
            print(f"\n  {M}Dry run — no file written.{W}\n{C}{'='*64}{W}\n")
            sys.exit(0)
        if _df_dupes == 0:
            print(f"\n  {G}File is already clean — no duplicates found.{W}")
            if not _df_in_place:
                print(f"  {Y}No output file written (nothing to do).{W}")
            print(f"\n{C}{'='*64}{W}\n")
            sys.exit(0)
        # ── Reconstruct and write ─────────────────────────────────────────────
        if _df_blank_fmt:
            _df_output = '\n\n'.join(_df_unique_blocks)
        else:
            _df_sep_str = '\n' + _SEP_df + '\n'
            _df_output  = _df_sep_str.join('\n' + b + '\n' for b in _df_unique_blocks)
        try:
            with open(_df_out, 'w', encoding='utf-8') as _df_wf:
                _df_wf.write(_df_output)
        except Exception as _df_we:
            print(f"\n{R}[!] Write failed: {_df_we}{W}")
            sys.exit(1)
        _df_out_kb   = os.path.getsize(_df_out) // 1024
        _df_saved_kb = _df_src_kb - _df_out_kb
        _df_saved_pct = int(_df_saved_kb / _df_src_kb * 100) if _df_src_kb else 0
        print(f"  {G}Output             : {os.path.basename(_df_out)}  ({_df_out_kb:,} KB){W}")
        print(f"  {G}Space saved        : {_df_saved_kb:,} KB  ({_df_saved_pct}%){W}")
        if _df_in_place:
            print(f"  {M}File updated in-place.{W}")
        print(f"\n{C}{'='*64}{W}\n")
        sys.exit(0)

    # ── --dedup-bulk [DIR]: deduplicate every CCTV result file in a directory ────
    if '--dedup-bulk' in sys.argv:
        _db_idx  = sys.argv.index('--dedup-bulk')
        _db_scan_dir = SCRIPT_DIR
        if (_db_idx + 1 < len(sys.argv) and
                not sys.argv[_db_idx + 1].startswith('--')):
            _db_scan_dir = sys.argv[_db_idx + 1]
        if not os.path.isdir(_db_scan_dir):
            print(f"{Fore.RED}[!] Directory not found: {_db_scan_dir}{Style.RESET_ALL}")
            sys.exit(1)
        _db_out_dir    = None
        _db_in_place   = '--in-place'   in sys.argv
        _db_dry        = '--dry-run'    in sys.argv
        _db_keep_first = '--keep-first' in sys.argv
        if not _db_in_place and '--out-dir' in sys.argv:
            _dbi = sys.argv.index('--out-dir')
            if _dbi + 1 < len(sys.argv) and not sys.argv[_dbi + 1].startswith('--'):
                _db_out_dir = sys.argv[_dbi + 1]
                os.makedirs(_db_out_dir, exist_ok=True)
        C, G, Y, W, R, M = (Fore.CYAN, Fore.GREEN, Fore.YELLOW,
                             Style.RESET_ALL, Fore.RED, Fore.MAGENTA)
        # ── Collect target files ───────────────────────────────────────────────
        _db_files = sorted(
            f for f in os.listdir(_db_scan_dir)
            if ('ValidCamera' in f or 'CCTV_Found' in f or 'cctv_found' in f)
            and f.endswith('.txt')
            and not f.startswith('dedup_')
        )
        if not _db_files:
            print(f"\n  {Y}No CCTV result files found in {_db_scan_dir}.{W}\n")
            sys.exit(0)
        _SEP_db = '=' * 60
        def _db_ip_port_key(raw):
            ip = port = ''
            for ln in raw.splitlines():
                if ':' in ln:
                    k, _, v = ln.partition(':')
                    k2 = k.strip().lower()
                    v2 = v.strip()
                    if k2 in ('ip address', 'ip') and not ip:
                        ip = v2
                    if k2 == 'port' and not port:
                        port = v2
            return f"{ip}:{port}" if ip else None
        def _db_score(raw):
            sc = 0; hu = hp = False
            for ln in raw.splitlines():
                if ':' in ln:
                    k, _, v = ln.partition(':')
                    k2 = k.strip().lower()
                    if v.strip(): sc += 1
                    if k2 in ('username', 'user') and v.strip(): hu = True
                    if k2 in ('password', 'pass') and v.strip(): hp = True
            if hu and hp: sc += 10
            return sc
        print(f"\n{C}{'='*66}{W}")
        print(f"{G}  Dedup Bulk  --  {_db_scan_dir}{W}")
        print(f"{C}{'='*66}{W}\n")
        _db_mode = 'keep-first' if _db_keep_first else 'best-entry'
        print(f"  {Y}Files found  : {len(_db_files)}{W}   mode: {_db_mode}"
              + (f"   dry-run" if _db_dry else "") + "\n")
        _db_grand_files = _db_grand_blocks = _db_grand_unique = _db_grand_dupes = 0
        _db_grand_saved_kb = 0
        for _dbf in _db_files:
            _db_src_path = os.path.join(_db_scan_dir, _dbf)
            _db_text = open(_db_src_path, 'r',
                            encoding='utf-8', errors='replace').read()
            _db_raw  = [b.strip() for b in _db_text.split(_SEP_db) if b.strip()]
            _db_blank = False
            if len(_db_raw) <= 1:
                _db_raw  = [b.strip() for b in _db_text.split('\n\n') if b.strip()]
                _db_blank = True
            if not _db_raw:
                continue
            _db_seen  = {}
            _db_order = []
            for _dblk in _db_raw:
                _dbk = _db_ip_port_key(_dblk)
                if not _dbk:
                    continue
                if _dbk not in _db_seen:
                    _db_seen[_dbk]  = (_dblk, _db_score(_dblk))
                    _db_order.append(_dbk)
                elif not _db_keep_first:
                    _dbs2 = _db_score(_dblk)
                    if _dbs2 > _db_seen[_dbk][1]:
                        _db_seen[_dbk] = (_dblk, _dbs2)
            _db_uniq_blks = [_db_seen[k][0] for k in _db_order]
            _db_n_total   = len(_db_raw)
            _db_n_unique  = len(_db_uniq_blks)
            _db_n_dupes   = _db_n_total - _db_n_unique
            _db_src_kb    = os.path.getsize(_db_src_path) // 1024
            _db_status    = f"{G}clean{W}" if _db_n_dupes == 0 else f"{R}{_db_n_dupes} dupes{W}"
            print(f"  {C}[+]{W} {_dbf[:52]:<52}  "
                  f"{Y}{_db_n_total:>6,}{W} blks  {_db_status}")
            _db_grand_blocks  += _db_n_total
            _db_grand_unique  += _db_n_unique
            _db_grand_dupes   += _db_n_dupes
            _db_grand_files   += 1
            if _db_dry or _db_n_dupes == 0:
                continue
            # ── Write output ──────────────────────────────────────────────────
            if _db_blank:
                _db_out_text = '\n\n'.join(_db_uniq_blks)
            else:
                _db_sep_s    = '\n' + _SEP_db + '\n'
                _db_out_text = _db_sep_s.join('\n' + b + '\n' for b in _db_uniq_blks)
            if _db_in_place:
                _db_dst = _db_src_path
            elif _db_out_dir:
                _db_dst = os.path.join(_db_out_dir,
                                       f'dedup_{os.path.basename(_db_src_path)}')
            else:
                _db_dst = os.path.join(
                    os.path.dirname(_db_src_path),
                    f'dedup_{os.path.basename(_db_src_path)}')
            try:
                with open(_db_dst, 'w', encoding='utf-8') as _db_wf:
                    _db_wf.write(_db_out_text)
                _db_dst_kb  = os.path.getsize(_db_dst) // 1024
                _db_grand_saved_kb += max(0, _db_src_kb - _db_dst_kb)
            except Exception as _db_we:
                print(f"    {R}[!] Write failed: {_db_we}{W}")
        # ── Grand summary ──────────────────────────────────────────────────────
        print(f"\n{C}{'='*66}{W}")
        print(f"  {Y}Files processed   : {_db_grand_files:,}{W}")
        print(f"  {Y}Total blocks      : {_db_grand_blocks:,}{W}")
        print(f"  {G}Unique kept       : {_db_grand_unique:,}{W}")
        print(f"  {R}Duplicates removed: {_db_grand_dupes:,}{W}")
        if not _db_dry:
            print(f"  {G}Space saved       : {_db_grand_saved_kb:,} KB{W}")
        if _db_dry:
            print(f"\n  {M}Dry run — no files written.{W}")
        elif _db_in_place:
            print(f"\n  {M}All files updated in-place.{W}")
        elif _db_out_dir:
            print(f"\n  {G}Output directory  : {_db_out_dir}{W}")
        print(f"\n{C}{'='*66}{W}\n")
        sys.exit(0)

    # ── --find-cameras IP/CIDR: fast port sweep for open camera ports ────────────
    if '--find-cameras' in sys.argv:
        import ipaddress       as _fca_ip_mod
        import socket          as _fca_sock
        from concurrent.futures import ThreadPoolExecutor as _FcaTpe
        _fca_idx = sys.argv.index('--find-cameras')
        if _fca_idx + 1 >= len(sys.argv) or sys.argv[_fca_idx + 1].startswith('--'):
            print(f"{Fore.RED}[!] --find-cameras requires an IP, CIDR, or comma-list "
                  f"(e.g. 192.168.1.0/24  or  1.2.3.4,1.2.3.5){Style.RESET_ALL}")
            sys.exit(1)
        _fca_target   = sys.argv[_fca_idx + 1]
        _fca_timeout  = 1.0
        _fca_threads  = 200
        _fca_ports    = [80, 554, 8080, 8554, 37777, 34567, 5000, 8000]
        if '--timeout' in sys.argv:
            try: _fca_timeout = float(sys.argv[sys.argv.index('--timeout') + 1])
            except: pass
        if '--threads' in sys.argv:
            try: _fca_threads = int(sys.argv[sys.argv.index('--threads') + 1])
            except: pass
        if '--ports' in sys.argv:
            try:
                _fca_ports = [int(p) for p in
                              sys.argv[sys.argv.index('--ports') + 1].split(',')]
            except: pass
        C, G, Y, W, R, M = (Fore.CYAN, Fore.GREEN, Fore.YELLOW,
                             Style.RESET_ALL, Fore.RED, Fore.MAGENTA)
        # ── Expand targets ────────────────────────────────────────────────────
        _fca_ips = []
        for _fca_part in _fca_target.split(','):
            _fca_part = _fca_part.strip()
            try:
                _fca_net = _fca_ip_mod.ip_network(_fca_part, strict=False)
                _fca_ips.extend(str(h) for h in _fca_net.hosts())
            except ValueError:
                _fca_ips.append(_fca_part)
        _fca_ips = list(dict.fromkeys(_fca_ips))   # dedupe, preserve order
        _fca_tasks = [(ip, port) for ip in _fca_ips for port in _fca_ports]
        print(f"\n{C}{'='*64}{W}")
        print(f"{G}  Find Cameras  --  {_fca_target}{W}")
        print(f"{C}{'='*64}{W}\n")
        print(f"  {Y}Hosts          : {len(_fca_ips):,}{W}")
        print(f"  {Y}Ports          : {', '.join(str(p) for p in _fca_ports)}{W}")
        print(f"  {Y}Probes         : {len(_fca_tasks):,}  ({_fca_threads} threads, "
              f"{_fca_timeout}s timeout){W}\n")
        # ── Port probe ────────────────────────────────────────────────────────
        def _fca_probe(args):
            _ip, _port = args
            try:
                s = _fca_sock.socket(_fca_sock.AF_INET, _fca_sock.SOCK_STREAM)
                s.settimeout(_fca_timeout)
                r = s.connect_ex((_ip, _port))
                s.close()
                return (_ip, _port, r == 0)
            except Exception:
                return (_ip, _port, False)
        _fca_open   = {}   # ip → [port, ...]
        _fca_done   = 0
        _fca_total  = len(_fca_tasks)
        with _FcaTpe(max_workers=_fca_threads) as _fca_ex:
            for _fca_ip, _fca_port, _fca_ok in _fca_ex.map(_fca_probe, _fca_tasks):
                _fca_done += 1
                if _fca_ok:
                    _fca_open.setdefault(_fca_ip, []).append(_fca_port)
                if _fca_done % max(1, _fca_total // 40) == 0 or _fca_done == _fca_total:
                    _fca_pct = int(_fca_done / _fca_total * 100)
                    _fca_bar = chr(0x2588) * max(1, _fca_pct // 5)
                    print(f"  {C}{_fca_pct:>3}%{W}  {G}{_fca_bar:<20}{W}  "
                          f"{_fca_done:,}/{_fca_total:,}", end='\r', flush=True)
        print(f"  {G}100%  {'█'*20}{W}  {_fca_total:,}/{_fca_total:,}          ")
        # ── Results ───────────────────────────────────────────────────────────
        if not _fca_open:
            print(f"\n  {Y}No open camera ports found.{W}\n")
        else:
            print(f"\n  {G}{'IP Address':<18}  {'Open Ports'}{W}")
            print(f"  {C}{'─'*46}{W}")
            for _fca_r_ip in sorted(_fca_open,
                                    key=lambda x: [int(n) for n in x.split('.')
                                                   if n.isdigit()]):
                _fca_r_ports = _fca_open[_fca_r_ip]
                _fca_tags = []
                for _p in _fca_r_ports:
                    _tag = {80:'HTTP', 554:'RTSP', 8080:'HTTP-alt',
                            8554:'RTSP-alt', 37777:'Dahua', 34567:'DVR',
                            5000:'HIKVISION-SDK', 8000:'HIKVISION-SDK'}.get(_p, str(_p))
                    _fca_tags.append(f"{_p}({_tag})")
                print(f"  {G}{_fca_r_ip:<18}{W}  {Y}{', '.join(_fca_tags)}{W}")
            print(f"\n  {C}{'─'*46}{W}")
            print(f"  {G}Hosts with open ports : {len(_fca_open):,}{W}")
            print()
            # ── Suggested next commands ───────────────────────────────────────
            _fca_hints = []
            for _hnt_ip, _hnt_ports in list(_fca_open.items())[:5]:
                _hnt_port = _hnt_ports[0]
                _fca_hints.append(
                    f"  python W8CameraHackV3.py --onvif-probe {_hnt_ip}:{_hnt_port}"
                    f" --user admin --pass admin")
            if _fca_hints:
                print(f"  {M}Suggested next steps:{W}")
                for _h in _fca_hints:
                    print(f"  {Y}{_h}{W}")
                print()
        print(f"{C}{'='*64}{W}\n")
