            ('admin',      'admin123'),
            ('admin',      'Admin123'),
            ('admin',      'password'),
            ('admin',      '1234'),
            ('admin',      '888888'),
            ('admin',      '666666'),
            ('admin',      '111111'),
            ('admin',      '123456789'),
            ('admin',      'admin1234'),
            ('admin',      'pass'),
            ('root',       ''),
            ('root',       'root'),
            ('root',       'admin'),
            ('root',       '12345'),
            ('root',       'pass'),
            ('guest',      ''),
            ('guest',      'guest'),
            ('user',       'user'),
