                print(f"  {G}{'─'*40}{W}")
                print(f"  {G}Username : {_hu}{W}")
                print(f"  {G}Password : {_hp_disp}{W}")
                for _proto, _path, _code in _hres:
                    print(f"    {C}{_proto:<14}{W}  {Y}{_path}{W}  [{_code}]")
