    # ── --batch-check-creds FILE: run default-cred check across every IP:Port ────
    if '--batch-check-creds' in sys.argv:
        import socket  as _bcc_sock
        import base64  as _bcc_b64
        from concurrent.futures import ThreadPoolExecutor as _BccTpe, as_completed as _bcc_as_done
        from requests.auth import HTTPBasicAuth as _BccBasic
        _bcc_idx = sys.argv.index('--batch-check-creds')
        if _bcc_idx + 1 >= len(sys.argv) or sys.argv[_bcc_idx + 1].startswith('--'):
            print(f"{Fore.RED}[!] --batch-check-creds requires a FILE path.{Style.RESET_ALL}")
            sys.exit(1)
        _bcc_src = sys.argv[_bcc_idx + 1]
