            f'<div class="l">IPs Scanned</div></div>'
            f'<div class="s"><div class="n" style="color:#58a6ff">'
            f'{len(_srh_cameras)}</div>'
            f'<div class="l">Cameras Found</div></div>'
            f'<div class="s"><div class="n" style="color:#e3b341">'
            f'{len(_srh_ports)}</div>'
            f'<div class="l">Ports Probed</div></div>'
