    # ── --rtsp-probe IP:PORT: test common RTSP stream paths ───────────────────
    if '--rtsp-probe' in sys.argv:
        import datetime as _dt_rp
        C, G, Y, W, R, M = (Fore.CYAN, Fore.GREEN, Fore.YELLOW,
                             Style.RESET_ALL, Fore.RED, Fore.MAGENTA)
        _rp_idx = sys.argv.index('--rtsp-probe')
        if _rp_idx + 1 >= len(sys.argv) or sys.argv[_rp_idx + 1].startswith('--'):
            print(f"{R}[!] --rtsp-probe requires IP:PORT  e.g. --rtsp-probe 1.2.3.4:554{W}")
            sys.exit(1)
        _rp_target = sys.argv[_rp_idx + 1]
        _rp_ip, _rp_port = (_rp_target.rsplit(':', 1) if ':' in _rp_target
                            else (_rp_target, '554'))
        try:
            _rp_port = int(_rp_port)
        except ValueError:
            print(f"{R}[!] Invalid port in '{_rp_target}'{W}"); sys.exit(1)
        _rp_user = _rp_pass = ''
        if '--user' in sys.argv:
            _ui = sys.argv.index('--user')
            if _ui + 1 < len(sys.argv) and not sys.argv[_ui+1].startswith('--'):
                _rp_user = sys.argv[_ui + 1]
        if '--pass' in sys.argv:
            _pi = sys.argv.index('--pass')
            if _pi + 1 < len(sys.argv) and not sys.argv[_pi+1].startswith('--'):
                _rp_pass = sys.argv[_pi + 1]
        _rp_paths = [
            # Hikvision
            '/Streaming/Channels/1', '/Streaming/Channels/101',
            '/Streaming/Channels/102', '/h264/ch1/main/av_stream', '/h264/ch01main',
            # Dahua
            '/cam/realmonitor?channel=1&subtype=0',
            '/cam/realmonitor?channel=1&subtype=1',
            '/h264Preview_01_main', '/h264Preview_01_sub',
            # Axis
            '/axis-media/media.amp', '/mpeg4/media.amp',
            # Generic
            '/stream1', '/stream2', '/live', '/live/ch0', '/live/0/main',
            '/video1', '/video.h264', '/1', '/0', '/main', '/sub', '/ch01',
            '/ch0/main/av_stream', '/onvif/profile1', '/onvif/profile2',
        ]

        def _rtsp_describe(ip, port, path, user='', pw='', timeout=3.0):
            cred = f"{user}:{pw}@" if user else ''
            url  = f"rtsp://{cred}{ip}:{port}{path}"
            req  = (f"DESCRIBE {url} RTSP/1.0\r\n"
                    f"CSeq: 1\r\nUser-Agent: W8Scanner/3.0\r\n"
                    f"Accept: application/sdp\r\n\r\n")
            try:
                s = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
                s.settimeout(timeout)
                s.connect((ip, port))
                s.sendall(req.encode())
                resp = s.recv(512).decode('utf-8', errors='replace')
                s.close()
                if resp.startswith('RTSP/'):
                    return True, resp.split('\r\n')[0], url
            except Exception:
                pass
            return False, '', url

        print(f"\n{C}{'═'*66}{W}")
        print(f"{G}  RTSP Probe  —  {_rp_ip}:{_rp_port}{W}")
        _rp_auth_tag = f"{_rp_user}:{_rp_pass}" if _rp_user else "anonymous"
        print(f"  {Y}Auth : {_rp_auth_tag}   Paths to test: {len(_rp_paths)}{W}")
        print(f"{C}{'═'*66}{W}")
        _rp_live          = []
        _rp_auth_required = []
        _rp_results       = {}
        _rp_print_lock    = threading.Lock()

        def _rp_probe_one(path):
            return path, *_rtsp_describe(_rp_ip, _rp_port, path, _rp_user, _rp_pass)

        with ThreadPoolExecutor(max_workers=len(_rp_paths)) as _rp_ex:
            for _path, _ok, _status, _url in _rp_ex.map(_rp_probe_one, _rp_paths):
                _rp_results[_path] = (_ok, _status, _url)

        # Print in original path order
        for _path in _rp_paths:
            _ok, _status, _url = _rp_results[_path]
            if _ok:
                _num = _status.split()[1] if len(_status.split()) > 1 else '?'
                if _num == '200':
                    _rp_live.append((_path, _url))
                    print(f"  {G}[200 LIVE ]{W}  {_url}")
                elif _num in ('401', '403'):
                    _rp_auth_required.append((_path, _url, _status))
                    print(f"  {Y}[{_num} AUTH  ]{W}  {_url}")
                elif _num == '404':
                    pass
                else:
                    print(f"  {C}[{_num}       ]{W}  {_url}")
        print(f"\n{C}{'─'*66}{W}")
        print(f"  {G}Live streams   : {len(_rp_live)}{W}")
        print(f"  {Y}Auth required  : {len(_rp_auth_required)}{W}")
        if _rp_live:
            print(f"\n  {G}── Direct RTSP URLs (paste into VLC or ffplay) ──{W}")
            for _path, _url in _rp_live:
                print(f"    {G}{_url}{W}")
        if _rp_auth_required and not _rp_user:
            print(f"\n  {Y}Tip: retry with --user admin --pass <password> "
                  f"to access auth-protected streams{W}")
        print(f"\n{C}{'═'*66}{W}\n")
        sys.exit(0)

    # ── --onvif-probe IP:PORT: ONVIF SOAP GetDeviceInformation ────────────────
    if '--onvif-probe' in sys.argv:
        import datetime as _dt_op
        import re       as _re_op
        import html     as _html_op
        C, G, Y, W, R, M = (Fore.CYAN, Fore.GREEN, Fore.YELLOW,
                             Style.RESET_ALL, Fore.RED, Fore.MAGENTA)
        _op_idx = sys.argv.index('--onvif-probe')
        if _op_idx + 1 >= len(sys.argv) or sys.argv[_op_idx + 1].startswith('--'):
            print(f"{R}[!] --onvif-probe requires IP:PORT  e.g. --onvif-probe 1.2.3.4:80{W}")
            sys.exit(1)
        _op_target = sys.argv[_op_idx + 1]
        _op_ip, _op_port = (_op_target.rsplit(':', 1) if ':' in _op_target
                            else (_op_target, '80'))
        try:
            _op_port = int(_op_port)
        except ValueError:
            print(f"{R}[!] Invalid port in '{_op_target}'{W}"); sys.exit(1)
        _op_user = _op_pass = ''
        if '--user' in sys.argv:
            _ui = sys.argv.index('--user')
            if _ui + 1 < len(sys.argv) and not sys.argv[_ui+1].startswith('--'):
                _op_user = sys.argv[_ui + 1]
        if '--pass' in sys.argv:
            _pi = sys.argv.index('--pass')
            if _pi + 1 < len(sys.argv) and not sys.argv[_pi+1].startswith('--'):
                _op_pass = sys.argv[_pi + 1]
        _SOAP_DEV_INFO = (
            '<?xml version="1.0" encoding="utf-8"?>'
            '<s:Envelope xmlns:s="http://www.w3.org/2003/05/soap-envelope">'
            '<s:Body><tds:GetDeviceInformation '
            'xmlns:tds="http://www.onvif.org/ver10/device/wsdl"/>'
            '</s:Body></s:Envelope>')
        _SOAP_CAPS = (
            '<?xml version="1.0" encoding="utf-8"?>'
            '<s:Envelope xmlns:s="http://www.w3.org/2003/05/soap-envelope">'
            '<s:Body><tds:GetCapabilities '
            'xmlns:tds="http://www.onvif.org/ver10/device/wsdl">'
            '<tds:Category>All</tds:Category>'
            '</tds:GetCapabilities></s:Body></s:Envelope>')
        _SOAP_PROFILES = (
            '<?xml version="1.0" encoding="utf-8"?>'
            '<s:Envelope xmlns:s="http://www.w3.org/2003/05/soap-envelope">'
            '<s:Body><trt:GetProfiles '
            'xmlns:trt="http://www.onvif.org/ver10/media/wsdl"/>'
            '</s:Body></s:Envelope>')

        def _onvif_post(endpoint, body):
            url = f"http://{_op_ip}:{_op_port}{endpoint}"
            hdrs = {'Content-Type': 'application/soap+xml;charset=UTF-8', 'SOAPAction': ''}
            try:
                if _op_user:
                    r = requests.post(url, data=body, headers=hdrs,
                                      auth=HTTPDigestAuth(_op_user, _op_pass),
                                      timeout=5, verify=False)
                else:
                    r = requests.post(url, data=body, headers=hdrs,
                                      timeout=5, verify=False)
                return r.status_code, r.text
            except Exception:
                return 0, ''

        print(f"\n{C}{'═'*66}{W}")
        print(f"{G}  ONVIF Probe  —  {_op_ip}:{_op_port}{W}")
        _op_auth_tag = f"{_op_user}:{_op_pass}" if _op_user else "no auth"
        print(f"  {Y}Auth : {_op_auth_tag}{W}")
        print(f"{C}{'═'*66}{W}")
        _op_found_ep = None
        _op_dev_info = {}
        for _ep in ['/onvif/device_service', '/onvif/Device',
                    '/onvif/device', '/onvif', '/onvif/services', '/device_service']:
            print(f"  Testing {_ep} ...", end='', flush=True)
            _sc, _body = _onvif_post(_ep, _SOAP_DEV_INFO)
            if _sc == 200 and 'Manufacturer' in _body:
                print(f" {G}[✓ 200 ONVIF]{W}")
                _op_found_ep = _ep
                for _f in ['Manufacturer', 'Model', 'FirmwareVersion',
                            'SerialNumber', 'HardwareId']:
                    _m = _re_op.search(rf'<[^>]*{_f}[^>]*>([^<]+)<', _body)
                    if _m:
                        _op_dev_info[_f] = _m.group(1).strip()
                break
            elif _sc == 401:
                print(f" {Y}[401 Auth Required]{W}")
                _op_found_ep = _ep
                break
            elif _sc in (400, 500) and _body:
                print(f" {Y}[ONVIF endpoint found — fault response]{W}")
                _op_found_ep = _ep
                _sc2, _body2 = _onvif_post(_ep, _SOAP_CAPS)
                if _sc2 == 200:
                    _op_dev_info['ONVIF'] = 'GetCapabilities responded OK'
                break
            elif _sc == 0:
                print(f" {R}[no response]{W}")
            else:
                print(f" {C}[HTTP {_sc}]{W}")
        if not _op_found_ep:
            print(f"\n  {R}[✗] No ONVIF service found on {_op_ip}:{_op_port}{W}")
            print(f"  Try a different port (80, 8080, 8000) or the device may not support ONVIF.")
        else:
            if _op_dev_info:
                print(f"\n  {G}── Device Information ──{W}")
                for _fk, _fl in [('Manufacturer', 'Manufacturer'),
                                  ('Model',            'Model'),
                                  ('FirmwareVersion',  'Firmware'),
                                  ('SerialNumber',     'Serial No.'),
                                  ('HardwareId',       'Hardware ID'),
                                  ('ONVIF',            'ONVIF')]:
                    if _fk in _op_dev_info:
                        print(f"    {Y}{_fl:<16}{W} {_op_dev_info[_fk]}")
            else:
                print(f"\n  {Y}ONVIF endpoint found but no device info returned "
                      f"(auth may be required){W}")
            # Try GetProfiles then GetStreamUri for valid RTSP URLs
            if _op_user:
                print(f"\n  {C}Fetching media profiles...{W}", end='', flush=True)
                _sc3, _body3 = _onvif_post(_op_found_ep, _SOAP_PROFILES)
                if _sc3 == 200 and 'token' in _body3:
                    _tokens = _re_op.findall(r'token="([^"]+)"', _body3)
                    print(f" {G}[{len(_tokens)} profile(s)]{W}")
                    # Derive media endpoint from device endpoint
                    _op_media_ep = (_op_found_ep
                                    .replace('device_service', 'media')
                                    .replace('device', 'media'))
                    for _toki, _tok in enumerate(_tokens[:8]):
                        # ── GetStreamUri: ask the camera for the real RTSP URL ──
                        _SOAP_SU = (
                            '<?xml version="1.0" encoding="utf-8"?>'
                            '<s:Envelope xmlns:s="http://www.w3.org/2003/05/soap-envelope">'
                            '<s:Body><trt:GetStreamUri '
                            'xmlns:trt="http://www.onvif.org/ver10/media/wsdl">'
                            '<trt:StreamSetup>'
                            '<tt:Stream xmlns:tt="http://www.onvif.org/ver10/schema">'
                            'RTP-Unicast</tt:Stream>'
                            '<tt:Transport xmlns:tt="http://www.onvif.org/ver10/schema">'
                            '<tt:Protocol>RTSP</tt:Protocol>'
                            '</tt:Transport></trt:StreamSetup>'
                            f'<trt:ProfileToken>{_tok}</trt:ProfileToken>'
                            '</trt:GetStreamUri></s:Body></s:Envelope>')
                        _sc_su, _b_su = _onvif_post(_op_media_ep, _SOAP_SU)
                        _rtsp = ''
                        if _sc_su == 200:
                            _m_su = _re_op.search(
                                r'<[^>]*Uri[^>]*>(rtsp://[^<]+)<', _b_su)
                            if _m_su:
                                # Decode XML entities (&amp; → &, etc.) so
                                # the URL is valid for VLC / ffplay
                                _rtsp = _html_op.unescape(
                                    _m_su.group(1).strip())
                        # Inject credentials if the camera returned a bare URL
                        if _rtsp and '@' not in _rtsp and _op_user:
                            _rtsp = _rtsp.replace(
                                'rtsp://', f'rtsp://{_op_user}:{_op_pass}@')
                        # Fallback: use well-known indexed paths (no made-up params)
                        if not _rtsp:
                            _fb_paths = [
                                '/Streaming/Channels/101',
                                '/cam/realmonitor?channel=1&subtype=0',
                                '/onvif/profile1',
                            ]
                            _fb = _fb_paths[_toki] if _toki < len(_fb_paths) \
                                  else f'/Streaming/Channels/{(_toki + 1) * 100 + 1}'
                            _cred = (f'{_op_user}:{_op_pass}@' if _op_user else '')
                            _rtsp = f'rtsp://{_cred}{_op_ip}:554{_fb}'
                        print(f"    {G}{_rtsp}{W}")
                else:
                    print(f" {Y}[{_sc3} — no profiles]{W}")
        print(f"\n{C}{'═'*66}{W}\n")
        sys.exit(0)

    # ── --live-view IP:PORT: pull MJPEG frames continuously to disk ───────────
    if '--live-view' in sys.argv:
        import datetime as _dt_lv
        C, G, Y, W, R, M = (Fore.CYAN, Fore.GREEN, Fore.YELLOW,
                             Style.RESET_ALL, Fore.RED, Fore.MAGENTA)
        _lv_idx = sys.argv.index('--live-view')
        if _lv_idx + 1 >= len(sys.argv) or sys.argv[_lv_idx + 1].startswith('--'):
            print(f"{R}[!] --live-view requires IP:PORT  e.g. --live-view 1.2.3.4:80{W}")
            sys.exit(1)
        _lv_target = sys.argv[_lv_idx + 1]
        _lv_ip, _lv_port = (_lv_target.rsplit(':', 1) if ':' in _lv_target
                            else (_lv_target, '80'))
        try:
            _lv_port = int(_lv_port)
        except ValueError:
            print(f"{R}[!] Invalid port in '{_lv_target}'{W}"); sys.exit(1)
        _lv_user = _lv_pass = ''
        if '--user' in sys.argv:
            _ui = sys.argv.index('--user')
            if _ui + 1 < len(sys.argv) and not sys.argv[_ui+1].startswith('--'):
                _lv_user = sys.argv[_ui + 1]
        if '--pass' in sys.argv:
            _pi = sys.argv.index('--pass')
            if _pi + 1 < len(sys.argv) and not sys.argv[_pi+1].startswith('--'):
                _lv_pass = sys.argv[_pi + 1]
        _lv_fps = 1
        if '--fps' in sys.argv:
            try:
                _fi = sys.argv.index('--fps')
                _lv_fps = max(1, min(int(sys.argv[_fi + 1]), 30))
            except (IndexError, ValueError):
                pass
        _lv_max_frames = 0
        if '--frames' in sys.argv:
            try:
                _fri = sys.argv.index('--frames')
                _lv_max_frames = max(1, int(sys.argv[_fri + 1]))
            except (IndexError, ValueError):
                pass
        _lv_out_dir = os.path.join(SCRIPT_DIR, 'live_frames')
        if '--live-out' in sys.argv:
            _li = sys.argv.index('--live-out')
            if _li + 1 < len(sys.argv) and not sys.argv[_li+1].startswith('--'):
                _lv_out_dir = sys.argv[_li + 1]
        os.makedirs(_lv_out_dir, exist_ok=True)
        _lv_mjpeg_paths = [
            '/ISAPI/Streaming/channels/1/httpPreview',
            '/ISAPI/Streaming/channels/101/httpPreview',
            '/cgi-bin/mjpg/video.cgi?channel=0&subtype=1',
            '/cgi-bin/mjpeg', '/cgi-bin/mjpg.cgi',
            '/video.mjpg', '/mjpeg', '/mjpeg.cgi', '/mjpeg/video.cgi',
            '/live.mjpeg', '/stream/video.mjpeg', '/video.cgi', '/image.cgi',
        ]
        print(f"\n{C}{'═'*62}{W}")
        print(f"{G}  Live View  —  {_lv_ip}:{_lv_port}{W}")
        _lv_auth_tag = f"{_lv_user}:{_lv_pass}" if _lv_user else "anonymous"
        _lv_lim = (f"max {_lv_max_frames} frames" if _lv_max_frames
                   else "unlimited (Ctrl+C to stop)")
        print(f"  {Y}Auth    : {_lv_auth_tag}{W}")
        print(f"  {Y}FPS     : {_lv_fps}  |  Frames: {_lv_lim}{W}")
        print(f"  {Y}Save to : {_lv_out_dir}{W}")
        print(f"{C}{'═'*62}{W}")
        print(f"  Searching for MJPEG stream endpoint...")
        _lv_sess = requests.Session()
        _lv_sess.verify = False
        _lv_auths = []
        if _lv_user:
            _lv_auths = [HTTPDigestAuth(_lv_user, _lv_pass), (_lv_user, _lv_pass)]
        _lv_auths.append(None)
        _lv_stream_url  = None
        _lv_stream_auth = None
        for _lv_path in _lv_mjpeg_paths:
            _url = f"http://{_lv_ip}:{_lv_port}{_lv_path}"
            for _auth in _lv_auths:
                try:
                    _r = _lv_sess.get(_url, auth=_auth, timeout=4,
                                      stream=True, allow_redirects=True)
                    _ct = _r.headers.get('Content-Type', '')
                    if (_r.status_code == 200 and
                            ('multipart' in _ct or 'mjpeg' in _ct or 'jpeg' in _ct)):
                        _lv_stream_url  = _url
                        _lv_stream_auth = _auth
                        print(f"  {G}[✓] Stream found: {_url}{W}")
                        _r.close()
                        break
                    _r.close()
                except Exception:
                    continue
            if _lv_stream_url:
                break
        if not _lv_stream_url:
            print(f"\n  {R}[✗] No MJPEG stream found on {_lv_ip}:{_lv_port}{W}")
            print(f"  Camera may use RTSP only, or require credentials.")
            print(f"\n{C}{'═'*62}{W}\n")
            sys.exit(1)
        print(f"  {G}Streaming...  Ctrl+C to stop{W}\n")
        _lv_saved    = 0
        _lv_interval = 1.0 / _lv_fps
        try:
            _lv_resp = _lv_sess.get(_lv_stream_url, auth=_lv_stream_auth,
                                    stream=True, timeout=30)
            _lv_buf = b''
            _lv_last_save = time.time()
            for _chunk in _lv_resp.iter_content(chunk_size=4096):
                if not _chunk:
                    continue
                _lv_buf += _chunk
                while True:
                    _start = _lv_buf.find(b'\xff\xd8')
                    _end   = _lv_buf.find(b'\xff\xd9', _start + 2) if _start != -1 else -1
                    if _start == -1 or _end == -1:
                        break
                    _jpg    = _lv_buf[_start:_end + 2]
                    _lv_buf = _lv_buf[_end + 2:]
                    _now    = time.time()
                    if _now - _lv_last_save >= _lv_interval:
                        _lv_saved += 1
                        _lv_ts    = _dt_lv.datetime.now().strftime('%H%M%S_%f')[:10]
                        _fname    = f"frame_{_lv_saved:05d}_{_lv_ts}.jpg"
                        _fpath    = os.path.join(_lv_out_dir, _fname)
                        with open(_fpath, 'wb') as _jf:
                            _jf.write(_jpg)
                        _lv_last_save = _now
                        _sz = (f"{len(_jpg)//1024}KB" if len(_jpg) >= 1024
                               else f"{len(_jpg)}B")
                        sys.stdout.write(
                            f"\r  {G}[Frame {_lv_saved:>4}]{W}  {_fname}  {_sz}   ")
                        sys.stdout.flush()
                        if _lv_max_frames and _lv_saved >= _lv_max_frames:
                            raise KeyboardInterrupt
        except KeyboardInterrupt:
            pass
        except Exception as _lve:
            print(f"\n  {R}[!] Stream error: {_lve}{W}")
        print(f"\n\n  {G}[✓] Saved {_lv_saved} frame(s) to: {_lv_out_dir}{W}")
        print(f"\n{C}{'═'*62}{W}\n")
        sys.exit(0)

    # ── --report IP:PORT: full investigation report in one command ─────────────
