                    _csof.write(f"Date     : {_cs_ts}\n")
                    _csof.write(f"Cameras  : {len(_cs_cameras)}\n")
                    _csof.write(f"Creds    : {len(_cs_creds)}\n")
                    _csof.write(f"Cracked  : {len(_cs_cracked)}\n\n")
                    for _cr in _cs_cracked:
                        _csof.write('=' * 60 + '\n')
                        _csof.write(f"Camera Type: {_cr['type'] or 'Unknown'}\n")
                        _csof.write(f"IP Address : {_cr['ip']}\n")
                        _csof.write(f"Port       : {_cr['port']}\n")
                        _csof.write(f"URL        : http://{_cr['ip']}:{_cr['port']}\n")
                        _csof.write(f"Username   : {_cr['user']}\n")
                        _csof.write(f"Password   : {_cr['pass']}\n")
                        _csof.write('=' * 60 + '\n\n')
