    _parser.add_argument('--user',            metavar='U', default='',
                         help='[cam-snap] username (default: blank)')
    _parser.add_argument('--pass',            metavar='P', default='', dest='cam_pass',
                         help='[cam-snap] password (default: blank)')
    _parser.add_argument('--bulk-snapshot',   metavar='FILE', default=None,
                         help='Concurrent JPEG snapshots from every camera in a CCTV or IP:port file')
    _parser.add_argument('--snap-threads',    metavar='N', type=int, default=20,
                         help='[bulk-snapshot] worker threads (default: 20)')
    _parser.add_argument('--snap-out',        metavar='DIR', default='',
                         help='[bulk-snapshot] output directory (default: <script_dir>/snapshots/)')
    _parser.add_argument('--scan-range',      metavar='CIDR', default=None,
                         help='Probe every IP in a CIDR subnet for camera ports')
    _parser.add_argument('--rtsp-probe',      metavar='IP:PORT', default=None,
                         help='Test common RTSP stream paths on the target')
    _parser.add_argument('--onvif-probe',     metavar='IP:PORT', default=None,
                         help='ONVIF SOAP probe for device information')
    _parser.add_argument('--live-view',       metavar='IP:PORT', default=None,
                         help='Pull MJPEG frames continuously to disk')
    _parser.add_argument('--fps',             metavar='N', type=int, default=1,
                         help='[live-view] frames per second to save (default: 1)')
    _parser.add_argument('--frames',          metavar='N', type=int, default=0,
                         help='[live-view] max frames to save, 0=unlimited')
    _parser.add_argument('--live-out',        metavar='DIR', default='',
                         help='[live-view] output folder')
    _parser.add_argument('--report',          metavar='IP:PORT', default=None,
                         help='Full investigation report: port scan + ONVIF + RTSP + snapshot + creds')
    _parser.add_argument('--report-html',     metavar='IP:PORT', default=None,
                         help='Same 5-stage report as dark-themed self-contained HTML file')
    _parser.add_argument('--scan-range-html', metavar='CIDR',    default=None,
                         help='Subnet scan → dark HTML report with sortable camera table')
    _parser.add_argument('--credential-spray',metavar='FILE',    default=None,
                         help='Spray credentials.txt against every camera in a CCTV file')
