            print(f"\n{Fore.GREEN}{'═'*56}{Style.RESET_ALL}")
            print(f"{Fore.GREEN}[✓] Merge & Deduplication Complete!{Style.RESET_ALL}")
            print(f"{Fore.YELLOW}    Total duplicate entries removed: {_total_removed}{Style.RESET_ALL}")
            print(f"{Fore.GREEN}{'═'*56}{Style.RESET_ALL}")
            
            # Send to Telegram if enabled
