                    print(f"{Y}  b.{W} Back to Main Menu")
                    print(f"{C}{'═'*62}{W}\n")
                    try:
                        sub = input(f"{G}Select (1/2/3/4/b): {W}").strip().lower()
                    except (EOFError, KeyboardInterrupt):
                        print(f"\n{Y}[*] Returning to Main Menu...{W}")
                        break

                    if sub in ('b', 'back', ''):
                        print(f"{Y}[*] Returning to Main Menu...{W}")
