if __name__ == "__main__":
    try:
        main()
    except (KeyboardInterrupt, EOFError):
        try:
            _flush_camera_batch()
        except Exception:
            pass
        try:
            save_cred_success_stats()
        except Exception:
            pass
        try:
            save_cred_daily_stats()
        except Exception:
            pass
        print(f"\n\n{Fore.YELLOW}[!] Interrupted by user{Style.RESET_ALL}")
        sys.exit(0)
    except SystemExit:
        raise
    except Exception as e:
        # Don't clear progress on crash - we want to be able to resume!
        try:
            _flush_camera_batch()
        except Exception:
            pass
        try:
            if TELEGRAM_CONFIG.get("enabled"):
                send_telegram_message_blocking(f"⚠️ <b>Scanner Crashed</b>\nError: {str(e)[:200]}")
                if cctv_output_file and os.path.exists(cctv_output_file):
                    send_telegram_file_blocking(cctv_output_file, "Emergency backup")
        except Exception:
            pass
        print(f"\n{Fore.RED}[!] Error: {e}{Style.RESET_ALL}")
        # Keep the progress file so user can resume
        sys.exit(1)
